  function renderLiveReadouts() {
    dom.setupOverlay.classList.toggle("hidden", state.started);
    dom.clockReadout.textContent = formatClock(state.clock);
    dom.pauseReadout.textContent = state.runEnded ? "Scientist dead" : state.paused ? "Paused" : "Running";
    dom.speedReadout.textContent = `Speed ${currentTimeSpeed().label}`;
    dom.timeSpeedSelect.value = currentTimeSpeed().id;
    dom.pauseBtn.textContent = state.paused ? "Resume" : "Pause";
    dom.seedReadout.textContent = `Seed: ${state.seed}`;
    const released = releasedSlimeCount();
    const containerText = `Containers ${occupiedPermanentContainerCount()}/${permanentContainers().length}`;
    dom.storageReadout.textContent = released ? `${containerText}; Released ${released}` : containerText;
    const overflow = overflowCorpseCount();
    const localCorpses = localCorpseCount();
    const localText = localCorpses ? `; Local ${localCorpses}` : "";
    dom.wasteReadout.textContent = overflow
      ? `Drums ${drummedCorpseCount()}/${WASTE_DRUM_CAPACITY}${localText} +${overflow}`
      : `Drums ${drummedCorpseCount()}/${WASTE_DRUM_CAPACITY}${localText}`;
    const suspicionBand = suspicionBandForValue(state.suspicion);
    dom.suspicionReadout.textContent = `Suspicion: ${suspicionBand.label}`;
    dom.suspicionReadout.dataset.suspicionBand = suspicionBand.id;
    dom.suspicionReadout.title = `Suspicion is ${suspicionBand.label.toLowerCase()}. Exact Suspicion is hidden.`;
    renderVitalReadouts();
    refreshActionControls();
    renderQueueShell();
    for (const element of document.querySelectorAll("[data-task-remaining]")) {
      const task = state.tasks.find((candidate) => candidate.id === element.dataset.taskRemaining);
      if (task) {
        element.textContent = `${formatDuration(task.dueAt - state.clock)} remaining`;
      }
    }
    for (const element of document.querySelectorAll("[data-slime-life]")) {
      const slime = findSlime(element.dataset.slimeLife);
      if (slime) {
        element.textContent = `life ${formatDuration(Math.max(0, slime.deathAt - state.clock))}`;
      }
    }
    for (const element of document.querySelectorAll("[data-slime-maturity]")) {
      const slime = findSlime(element.dataset.slimeMaturity);
      if (slime) {
        element.textContent = slime.mature ? "mature" : `matures in ${formatDuration(slime.matureAt - state.clock)}`;
      }
    }
    for (const element of document.querySelectorAll("[data-corpse-decay]")) {
      const corpse = findCorpse(element.dataset.corpseDecay);
      if (corpse) {
        element.textContent = corpseDecayText(corpse);
      }
    }
    for (const element of document.querySelectorAll("[data-job-remaining]")) {
      const slime = findSlime(element.dataset.jobRemaining);
      if (slime && (slime.job === "corpse" || slime.job === "disposal")) {
        element.textContent = jobRemainingText(slime);
      }
    }
    for (const element of document.querySelectorAll("[data-job-fill]")) {
      const slime = findSlime(element.dataset.jobFill);
      if (slime) {
        element.style.width = `${jobProgressPercent(slime)}%`;
      }
    }
  }

  function renderHelix() {
    const rows = 12;
    const cols = GENOME_LENGTH * 3 + 6;
    const grid = Array.from({ length: rows }, () => Array.from({ length: cols }, () => ({ text: " ", type: "text" })));

    for (let i = 0; i < GENOME_LENGTH; i += 1) {
      const x = i * 3 + 3;
      const yA = Math.round(1 + ((Math.sin(i * 0.78) + 1) / 2) * 8);
      const yB = rows - 1 - yA;
      const minY = Math.min(yA, yB);
      const maxY = Math.max(yA, yB);
      const base = state.currentGenome[i];
      const complement = COMPLEMENT[base];
      const pair = `${base}-${complement}`;
      for (let y = minY + 1; y < maxY; y += 1) {
        grid[y][x] = { text: y % 2 === 0 ? ":" : ".", type: "text" };
      }
      grid[yA][x] = { text: base, type: "base", index: i, complement: false, pair };
      grid[yB][x] = { text: complement, type: "base", index: i, complement: true, pair };
      if (i > 0) {
        const prevX = (i - 1) * 3 + 3;
        const prevYA = Math.round(1 + ((Math.sin((i - 1) * 0.78) + 1) / 2) * 8);
        const prevYB = rows - 1 - prevYA;
        const midX = Math.floor((prevX + x) / 2);
        const midYA = Math.floor((prevYA + yA) / 2);
        const midYB = Math.floor((prevYB + yB) / 2);
        grid[midYA][midX] = { text: yA > prevYA ? "\\" : "/", type: "text" };
        grid[midYB][midX] = { text: yB > prevYB ? "\\" : "/", type: "text" };
      }
    }

    dom.helixGrid.style.gridTemplateColumns = `repeat(${cols}, 1ch)`;
    dom.helixGrid.textContent = "";
    for (let y = 0; y < rows; y += 1) {
      for (let x = 0; x < cols; x += 1) {
        const cell = document.createElement("span");
        cell.className = "helix-cell";
        const data = grid[y][x];
        if (data.type === "base") {
          const button = document.createElement("button");
          button.type = "button";
          button.className = `base-glyph ${baseClass(data.text)}${data.complement ? " base-complement" : ""}`;
          button.textContent = data.text;
          button.title = `Base pair ${data.index + 1}: ${data.pair}`;
          button.setAttribute("aria-label", `Base pair ${data.index + 1}: ${data.pair}`);
          button.addEventListener("click", () => {
            cycleBasePair(data.index, data.complement);
          });
          cell.append(button);
        } else {
          cell.textContent = data.text;
        }
        dom.helixGrid.append(cell);
      }
    }
  }

  function renderPredictions() {
    const evaluated = evaluateGenome(state.currentGenome);
    dom.predictionList.textContent = "";
    for (const region of DISPLAY_REGION_DEFS) {
      const detail = evaluated.details[region.key];
      const key = knowledgeKey(region.key, detail.codes);
      const known = state.journalMode === "auto" ? state.discoveries[region.key]?.[key] : null;
      const row = document.createElement("div");
      row.className = "prediction-row";
      row.append(
        traitLabelEl(region, known ? knownOutcomeMarker(region.key, known, evaluated.traits[region.key]) : null),
        known
          ? traitValueEl(region.key, evaluated.traits[region.key], formatKnownPrediction(region.key, known, evaluated.traits[region.key], state.currentGenome))
          : textEl("span", "Undiscovered")
      );
      dom.predictionList.append(row);
    }
  }

  function renderMutationBench() {
    const lockedCount = REGION_DEFS.filter((region) => isRegionLocked(region.key)).length;
    const selected = getSelectedSlime();
    setActionButtonState(dom.loadSelectedGenomeBtn, !selected, "Select a living sample first.");
    setActionButtonState(dom.randomUnlockedBtn, lockedCount === REGION_DEFS.length, "All genome regions are locked.");
    dom.lockSummary.textContent = `${lockedCount}/${REGION_DEFS.length} regions locked`;
    dom.regionLockGrid.textContent = "";

    for (const region of REGION_DEFS) {
      const locked = isRegionLocked(region.key);
      const row = document.createElement("div");
      row.className = `region-lock-row${locked ? " locked" : ""}`;

      const toggleLabel = document.createElement("label");
      toggleLabel.className = "region-lock-toggle";
      toggleLabel.title = `${locked ? "Unlock" : "Lock"} ${region.label}`;
      const toggle = document.createElement("input");
      toggle.type = "checkbox";
      toggle.checked = locked;
      toggle.addEventListener("change", () => {
        setRegionLock(region.key, toggle.checked);
        persist();
        render();
      });
      toggleLabel.append(toggle);

      const name = document.createElement("div");
      name.className = "region-lock-name";
      name.append(textEl("span", region.label), baseSequenceEl(getRegionCode(state.currentGenome, region.key), "region-code"));

      const mutate = document.createElement("button");
      mutate.type = "button";
      mutate.className = "region-mutate";
      mutate.textContent = "Mutate";
      setActionButtonState(mutate, locked, `${region.label} is locked.`);
      mutate.addEventListener("click", () => {
        mutateRegion(region.key);
      });

      row.append(toggleLabel, name, mutate);
      dom.regionLockGrid.append(row);
    }
  }

  function renderFoundryActionState() {
    const duration = synthesisDurationSeconds();
    const resourceCosts = synthesisResourceCosts();
    const resourceRoomId = synthesisResourceRoomId();
    renderSynthesisTubeStatus();
    setButtonStaminaLabel(dom.synthesizeBtn, "Synthesize Slime", BASE_ACTION_STAMINA, ["fabrication", "creatureHandling"], { duration: formatDuration(duration), suffix: `${formatResourceBundle(resourceCosts)} in ${roomName(resourceRoomId)}` });
    const reason = synthesisActionBlockReason();
    setActionButtonState(dom.synthesizeBtn, Boolean(reason), reason);
    if (!reason) {
      const logisticsHint = resourceLogisticsHint(resourceCosts, resourceRoomId, "Synthesize slime");
      dom.synthesizeBtn.title = logisticsHint || "";
    }
  }

  function renderSynthesisTubeStatus() {
    dom.synthesisTubeStatus.textContent = synthesisTubeStatusText();
  }

  function synthesisResourceCosts() {
    return { biomass: SYNTHESIS_BIOMASS_COST };
  }

  function synthesisResourceRoomId() {
    return synthesisTube()?.roomId || MAIN_ROOM_ID;
  }

  function synthesisStaminaCost() {
    return adjustedStaminaCost(BASE_ACTION_STAMINA, ["fabrication", "creatureHandling"]);
  }

  function synthesisDurationSeconds() {
    return adjustedDuration(8, "fabrication");
  }

  function synthesisActionBlockReason() {
    return synthesisTubeBlockReason()
      || resourceBlockReason(synthesisResourceCosts())
      || staminaBlockReason(synthesisStaminaCost());
  }

  function startSynthesisFromCurrentGenome() {
    const synthesisReason = synthesisTubeBlockReason();
    if (synthesisReason) {
      addEvent(synthesisReason);
      persist();
      render();
      return false;
    }
    return startStaminaTask({
      type: "synthesize",
      label: "Synthesize slime",
      baseDuration: 8,
      skillId: "fabrication",
      baseXp: 25,
      baseCost: BASE_ACTION_STAMINA,
      resourceCosts: synthesisResourceCosts(),
      resourceRoomId: synthesisResourceRoomId(),
      data: { genome: state.currentGenome }
    });
  }

  function synthesisRelatedTasks() {
    return (state.tasks || []).filter((task) =>
      task.type === "synthesize"
      || (task.type === "resourceHaul" && task.data?.continuation?.kind === "staminaTask" && task.data.continuation.task?.type === "synthesize")
    );
  }

  function synthesisTubeStatusText() {
    const tube = synthesisTube();
    if (!tube) {
      return "No synthesis tube exists.";
    }
    const occupants = synthesisTubeOccupants();
    if (occupants.length) {
      return `Synthesis tube occupied by ${occupants.map((slime) => slime.name).join(", ")}.`;
    }
    const corpses = containerCorpses(tube.id);
    if (corpses.length) {
      return `Synthesis tube blocked by ${corpses.map((corpse) => `${corpse.name} remains`).join(", ")}.`;
    }
    const relatedTask = synthesisRelatedTasks()[0] || null;
    if (relatedTask?.type === "resourceHaul") {
      return "Synthesis awaiting material hauling.";
    }
    if (relatedTask?.type === "synthesize") {
      return "Synthesis in progress.";
    }
    return "Synthesis tube empty.";
  }

  function synthesisTubeTaskSummary() {
    const tasks = synthesisRelatedTasks();
    if (!tasks.length) {
      return "No synthesis task queued.";
    }
    return tasks
      .map((task) => `${task.label}; ${formatDuration(Math.max(0, task.dueAt - state.clock))} remaining`)
      .join("; ");
  }

  function openFoundryWorkspace() {
    setActiveWorkspaceTab("foundry", { scroll: true, animate: false });
    return true;
  }

  function knownOutcomeEditorBlockReason() {
    return state.journalMode === "auto" ? "" : "Known outcomes require Automatic journal mode.";
  }

  function openKnownOutcomeEditorFromContext() {
    const reason = knownOutcomeEditorBlockReason();
    if (reason) {
      addEvent(reason);
      persist();
      render();
      return false;
    }
    setActiveWorkspaceTab("foundry", { scroll: true, animate: false });
    dom.knownEditor.classList.remove("hidden");
    renderKnownEditor();
    return true;
  }

  function synthesisContextDescription() {
    const resourceCosts = synthesisResourceCosts();
    const resourceRoomId = synthesisResourceRoomId();
    return resourceLogisticsHint(resourceCosts, resourceRoomId, "Synthesize slime")
      || `Queue synthesis using ${formatResourceBundle(resourceCosts)}, ${formatNumber(synthesisStaminaCost())} STA, and ${formatDuration(synthesisDurationSeconds())}.`;
  }

  function synthesisTubeBlockReason() {
    const tube = synthesisTube();
    const occupants = synthesisTubeOccupants();
    const corpses = tube ? containerCorpses(tube.id) : [];
    if (occupants.length) {
      return `Synthesis tube occupied by ${occupants.map((slime) => slime.name).join(", ")}.`;
    }
    if (corpses.length) {
      return `Synthesis tube blocked by ${corpses.map((corpse) => `${corpse.name} remains`).join(", ")}.`;
    }
    if (pendingSynthesisCount() > 0) {
      return "Synthesis already in progress.";
    }
    return "";
  }

  function refreshActionControls() {
    renderFoundryActionState();
    refreshReleaseButtonState();
    refreshTestButtonStates();
    refreshBreedButtonState();
    refreshCorpseActionStates();
  }

  function refreshReleaseButtonState() {
    const selected = getSelectedSlime();
    const cost = adjustedStaminaCost(HANDLING_STAMINA, ["creatureHandling"]);
    const releaseLabel = selected?.status === "released" ? "Contain Creature" : "Release into Room";
    setButtonStaminaLabel(dom.releaseBtn, releaseLabel, HANDLING_STAMINA, ["creatureHandling"]);
    const reason = !selected || selected.status === "dead"
      ? "No living slime selected."
      : isUnknownCreatureRecord(selected)
        ? "This creature's current condition is uncertain; confirm its location first."
      : selected.status === "released" && !firstOpenPermanentContainer()
        ? "No open permanent container is available."
      : staminaBlockReason(cost);
    setActionButtonState(dom.releaseBtn, Boolean(reason), reason);
    if (!reason && selected && selected.status !== "released") {
      dom.releaseBtn.title = releaseSuitabilityTooltipText(selected);
    }
  }

  function refreshTestButtonStates() {
    const slime = getSelectedSlime();
    for (const button of dom.testButtons.querySelectorAll("[data-test-id]")) {
      const test = TESTS.find((candidate) => candidate.id === button.dataset.testId);
      if (!test) {
        continue;
      }
      const cost = adjustedStaminaCost(BASE_ACTION_STAMINA, [test.skillId, "creatureHandling"]);
      const duration = adjustedDuration(test.duration, test.skillId);
      setButtonStaminaLabel(button, test.label, BASE_ACTION_STAMINA, [test.skillId, "creatureHandling"], { duration: formatDuration(duration) });
      const reason = testBlockReason(test, slime, cost);
      setActionButtonState(button, Boolean(reason), reason);
    }
  }

  function testBlockReason(test, slime, cost) {
    if (!slime || slime.status === "dead") {
      return "No living slime selected.";
    }
    if (hasPendingTest(slime.id, test.id)) {
      return "Test already pending.";
    }
    return staminaBlockReason(cost);
  }

  function refreshBreedButtonState() {
    const breedable = state.slimes.filter(isBreedable);
    const cost = adjustedStaminaCost(BASE_ACTION_STAMINA, ["husbandry", "creatureHandling"]);
    const duration = adjustedDuration(18, "husbandry");
    setButtonStaminaLabel(dom.breedBtn, "Force Recombination", BASE_ACTION_STAMINA, ["husbandry", "creatureHandling"], { duration: formatDuration(duration) });
    const reason = breedable.length < 2
      ? "Forced recombination requires two mature slimes."
      : !canAddContainedSlime()
        ? "Forced recombination requires at least one open permanent container."
        : staminaBlockReason(cost);
    setActionButtonState(dom.breedBtn, Boolean(reason), reason);
  }

  function refreshCorpseActionStates() {
    for (const button of dom.corpseList?.querySelectorAll("[data-corpse-id]") || []) {
      const corpse = findCorpse(button.dataset.corpseId);
      if (corpse) {
        refreshNecropsyButton(button, corpse);
      }
    }
  }

  function renderCreatureRecordTabs() {
    const activeTab = currentCreatureRecordTab();
    const counts = {
      living: livingCreatureRecords().length,
      unknown: unknownCreatureRecords().length,
      deceased: (state.corpses || []).length,
      jobs: (state.slimes || []).filter((slime) => slime.status !== "dead").length
    };
    if (dom.livingRecordBadge) dom.livingRecordBadge.textContent = String(counts.living);
    if (dom.unknownRecordBadge) dom.unknownRecordBadge.textContent = String(counts.unknown);
    if (dom.deceasedRecordBadge) dom.deceasedRecordBadge.textContent = String(counts.deceased);
    if (dom.jobRecordBadge) dom.jobRecordBadge.textContent = String(counts.jobs);

    for (const button of document.querySelectorAll("[data-creature-record-tab]")) {
      const tab = normalizeCreatureRecordTab(button.dataset.creatureRecordTab);
      const active = tab === activeTab;
      setElementHotkeyHint(button, CREATURE_RECORD_TAB_HOTKEYS[tab]);
      button.classList.toggle("active-record-tab", active);
      button.setAttribute("aria-selected", String(active));
      button.tabIndex = active ? 0 : -1;
    }
    for (const panel of document.querySelectorAll("[data-creature-record-panel]")) {
      const tab = normalizeCreatureRecordTab(panel.dataset.creatureRecordPanel);
      panel.hidden = tab !== activeTab;
    }
  }

  function renderSlimes() {
    dom.slimeList.textContent = "";
    renderCreatureRecordTabs();
    const selected = getSelectedSlime();
    dom.selectedSlimeSummary.textContent = "";
    if (selected) {
      if (isUnknownCreatureRecord(selected)) {
        const record = creatureRecordForSlime(selected);
        dom.selectedSlimeSummary.append(
          textEl("strong", selected.name),
          document.createTextNode(` - status uncertain - ${creatureRecordAgeText(record)} - last known in ${roomName(record?.lastKnownRoomId || MAIN_ROOM_ID)}`)
        );
      } else {
        const selectedRoomLabel = slimeRoomLabel(selected);
        dom.selectedSlimeSummary.append(
          slimeNameLink(selected),
          document.createTextNode(` - ${slimeLocationLabel(selected)}${selectedRoomLabel ? ` - ${selectedRoomLabel}` : ""} - ${slimeActivityLabel(selected)}`)
        );
      }
      const selectedContainer = selected.containerId ? containerById(selected.containerId) : null;
      if (selectedContainer && selected.status !== "dead" && !isUnknownCreatureRecord(selected)) {
        const testing = containmentTestRecordForSlime(selected);
        dom.selectedSlimeSummary.append(document.createTextNode(` - Escape pressure: ${testing.pressureLabel}`));
        const risk = activeContainmentRisk(selected, selectedContainer);
        const prediction = activeContainmentRiskPrediction(risk, selected, selectedContainer);
        dom.selectedSlimeSummary.append(document.createTextNode(` - Active containment risk: ${predictionRangeText(prediction.range)}`));
        dom.selectedSlimeSummary.append(activeContainmentRiskPredictionEl(risk, selected, selectedContainer));
      }
    } else {
      dom.selectedSlimeSummary.textContent = "No slime selected";
    }
    refreshReleaseButtonState();

    const livingSlimes = livingCreatureRecords();
    if (livingSlimes.length === 0) {
      dom.slimeList.append(emptyText("No confirmed living records. Loose creatures with stale observations appear under Unknown."));
      return;
    }

    for (const slime of livingSlimes) {
      const card = document.createElement("article");
      card.className = `slime-card${slime.id === state.selectedSlimeId ? " selected" : ""}${slime.status === "dead" ? " dead" : ""}`;
      card.dataset.slimeCard = slime.id;
      card.addEventListener("click", (event) => {
        if (event.target.closest("button, input, select, textarea")) {
          return;
        }
        setSelection({ kind: "slime", id: slime.id, source: "panel" });
        persist();
        render();
      });
      const title = document.createElement("h3");
      title.append(slimeNameLink(slime, "entity-link-title"), textEl("span", slimeStateLabel(slime)));
      const meta = document.createElement("div");
      meta.className = "slime-meta";
      const evaluated = evaluateGenome(slime.genome);
      const maturity = chip(slime.mature ? "mature" : `matures in ${formatDuration(slime.matureAt - state.clock)}`);
      maturity.dataset.slimeMaturity = slime.id;
      const life = chip(`life ${formatDuration(Math.max(0, slime.deathAt - state.clock))}`);
      life.dataset.slimeLife = slime.id;
      meta.append(maturity);
      meta.append(life);
      meta.append(chip(slimeLocationLabel(slime)));
      const roomChip = slimeRoomLabel(slime);
      if (roomChip) {
        meta.append(chip(roomChip));
      }
      meta.append(chip(slimeActivityLabel(slime)));
      const movementChip = slimeMovementChip(slime);
      if (movementChip) {
        meta.append(movementChip);
      }
      meta.append(slimeAiChip(slime));
      const responseChip = slimeResponseChip(slime);
      if (responseChip) {
        meta.append(responseChip);
      }
      const combatDecisionChip = slimeCombatDecisionChip(slime);
      if (combatDecisionChip) {
        meta.append(combatDecisionChip);
      }
      const combatChip = slimeCombatChip(slime);
      if (combatChip) {
        meta.append(combatChip);
      }
      const driveChip = slimeDriveChip(slime);
      if (driveChip) {
        meta.append(driveChip);
      }
      const perceptionChip = slimePerceptionChip(slime);
      if (perceptionChip) {
        meta.append(perceptionChip);
      }
      const socialChip = slimeSocialChip(slime);
      if (socialChip) {
        meta.append(socialChip);
      }
      const habitatChip = slimeHabitatChip(slime);
      if (habitatChip) {
        meta.append(habitatChip);
      }
      const containmentTestChip = slimeContainmentTestChip(slime);
      if (containmentTestChip) {
        meta.append(containmentTestChip);
      }
      const elementalHazardChip = slimeElementalHazardChip(slime, evaluated);
      if (elementalHazardChip) {
        meta.append(elementalHazardChip);
      }
      for (const activityChip of slimeDoorIntentChips(slime)) {
        meta.append(activityChip);
      }
      for (const activityChip of slimeCleanupActivityPerformanceChips(slime)) {
        meta.append(activityChip);
      }
      if (slime.revealed?.sustenance && isEnvironmentalSustenance(slime)) {
        meta.append(chip(environmentalSustenanceStatus(slime) || environmentalSustenanceLabel(slime)));
      }
      card.append(title, renderIdentityStrip(slime, evaluated), meta);
      if (slime.id === state.selectedSlimeId) {
        card.append(renderSlimeStats(slime));
        card.append(renderSlimeActivity(slime));
        card.append(renderSlimeAnalyzePanel(slime));
        card.append(renderSlimeResponse(slime));
        card.append(renderSlimeSocialContext(slime));
        const containmentTesting = renderSlimeContainmentTesting(slime);
        if (containmentTesting) {
          card.append(containmentTesting);
        }
        card.append(renderSlimeCombatControls(slime));
        const elementalHazards = renderSlimeElementalHazards(slime, evaluated);
        if (elementalHazards) {
          card.append(elementalHazards);
        }
        card.append(renderSlimeHabitat(slime));
        card.append(renderSlimeDrives(slime));
        card.append(renderSlimePerception(slime));
        card.append(renderFeedingControls(slime));
        card.append(renderLivingHarvestControls(slime));
        card.append(renderTraitGrid(slime, evaluated));
      }
      card.append(renderSlimeGenomeFooter(slime));
      dom.slimeList.append(card);
    }
  }

  function renderUnknownCreatureRecords() {
    if (!dom.unknownCreatureList) {
      return;
    }
    dom.unknownCreatureList.textContent = "";
    const unknown = unknownCreatureRecords();
    if (!unknown.length) {
      dom.unknownCreatureList.append(emptyText("No uncertain creature records."));
      return;
    }

    for (const slime of unknown) {
      const record = creatureRecordForSlime(slime);
      const card = document.createElement("article");
      card.className = "unknown-creature-card";
      card.dataset.unknownCreatureCard = slime.id;

      const title = document.createElement("h3");
      title.append(textEl("strong", slime.name), textEl("span", "status uncertain"));

      const meta = document.createElement("div");
      meta.className = "slime-meta";
      meta.append(
        chip(creatureRecordAgeText(record)),
        chip(`last known: ${roomName(record?.lastKnownRoomId || MAIN_ROOM_ID)}`),
        chip(record?.lastKnownStatus === "released" ? "loose when last seen" : "contained when last seen")
      );
      if (record?.lastKnownActivity) {
        meta.append(chip(record.lastKnownActivity.replace(/^Activity:\s*/i, "")));
      }
      if (Number.isFinite(Number(slime.deathAt))) {
        meta.append(chip(`expected death ${formatClock(slime.deathAt)}`));
      }

      const actions = document.createElement("div");
      actions.className = "record-actions";
      const focus = document.createElement("button");
      focus.type = "button";
      focus.textContent = "Focus Last Known";
      focus.title = "Return to the map at the last room where this creature was directly observed.";
      focus.addEventListener("click", () => {
        setActiveWorkspaceTab("map");
        focusRoom(record?.lastKnownRoomId || MAIN_ROOM_ID, { source: "panel" });
        persist();
        render();
      });
      actions.append(focus);

      card.append(title, meta, actions);
      dom.unknownCreatureList.append(card);
    }
  }


  function renderCorpses() {
    dom.corpseList.textContent = "";
    const overflow = overflowCorpseCount();
    const localCorpses = localCorpseCount();
    const baseSummary = `${drummedCorpseCount()}/${WASTE_DRUM_CAPACITY} waste drums used`;
    const localSummary = localCorpses ? `; ${localCorpses} local corpse${localCorpses === 1 ? "" : "s"}` : "";
    dom.wasteSummary.textContent = overflow
      ? `${baseSummary}${localSummary}; ${overflow} overflow specimen${overflow === 1 ? "" : "s"}`
      : `${baseSummary}${localSummary}`;

    if (!state.corpses?.length) {
      dom.corpseList.append(emptyText("No deceased specimens."));
      return;
    }

    for (const corpse of state.corpses) {
      normalizeCorpseLocation(corpse);
      const evaluated = evaluateGenome(corpse.genome);
      const card = document.createElement("article");
      card.className = `corpse-card corpse-${corpseFreshness(corpse)}${corpse.storage === "overflow" ? " overflow" : ""}`;
      card.dataset.corpseCard = corpse.id;
      card.classList.toggle("selected-map-target", selectedTargetMatchesCard("corpse", corpse.id));
      card.addEventListener("click", (event) => {
        if (event.target.closest("button, input, select, textarea")) {
          return;
        }
        setSelection({ kind: "corpse", id: corpse.id, source: "panel" });
        persist();
        render();
      });

      const title = document.createElement("h3");
      const name = document.createElement("span");
      name.append(corpseNameLink(corpse, "entity-link-title"), document.createTextNode(" remains"));
      title.append(name, textEl("span", corpseStateLabel(corpse)));

      const meta = document.createElement("div");
      meta.className = "slime-meta";
      const storageChip = chip(corpseLocationLabel(corpse));
      if (corpse.storage === "overflow") {
        storageChip.classList.add("danger-chip");
      }
      const decay = chip(corpseDecayText(corpse));
      decay.dataset.corpseDecay = corpse.id;
      meta.append(storageChip, decay, chip(`died ${formatClock(corpse.diedAt)}`), chip(corpse.genome));

      const actions = document.createElement("div");
      actions.className = "corpse-actions";
      const necropsy = document.createElement("button");
      necropsy.type = "button";
      necropsy.dataset.corpseId = corpse.id;
      refreshNecropsyButton(necropsy, corpse);
      necropsy.addEventListener("click", () => {
        startNecropsy(corpse);
      });
      const dump = document.createElement("button");
      dump.type = "button";
      dump.className = "danger-action";
      dump.textContent = "Dump Outside";
      const dumpReason = dumpCorpseBlockReason(corpse);
      setActionButtonState(dump, Boolean(dumpReason), dumpReason);
      dump.addEventListener("click", () => {
        dumpCorpseOutside(corpse.id);
      });
      const forensic = document.createElement("button");
      forensic.type = "button";
      forensic.dataset.forensicAnalyzeCorpseId = corpse.id;
      forensic.textContent = `Forensic Analyze (${FORENSIC_ANALYZE_MANA_COST} MANA)`;
      const forensicReason = forensicAnalyzeCorpseBlockReason(corpse);
      setActionButtonState(forensic, Boolean(forensicReason), forensicReason);
      forensic.title = forensicReason || `Spend ${FORENSIC_ANALYZE_MANA_COST} Mana to read broad cause, tissue, and evidence state.`;
      forensic.addEventListener("click", () => startForensicAnalyzeCorpse(corpse.id));
      actions.append(necropsy, forensic, ...corpseHarvestButtons(corpse), dump);

      card.append(title, renderIdentityStrip(corpse, evaluated), meta, actions);
      if (corpse.necropsyReport) {
        const report = document.createElement("p");
        report.className = "corpse-report";
        report.textContent = corpse.necropsyReport;
        card.append(report);
      }
      if (corpse.forensicReport) {
        corpse.forensicReport = normalizeForensicReport(corpse.forensicReport);
        const report = document.createElement("p");
        report.className = "corpse-report";
        report.dataset.forensicReport = corpse.id;
        report.textContent = `Forensic Analyze: ${corpse.forensicReport.summary}`;
        card.append(report);
      }
      dom.corpseList.append(card);
    }
  }

  function creatureRecordEntityBySpecimenId(specimenId) {
    const id = String(specimenId || "");
    const slime = findSlime(id);
    if (slime) {
      return { kind: "slime", id: slime.id, name: slime.name, state: slimeStateLabel(slime), entity: slime };
    }
    const corpse = (state.corpses || []).find((entry) => entry.specimenId === id || entry.id === id);
    if (corpse) {
      return { kind: "corpse", id: corpse.id, specimenId: corpse.specimenId, name: corpse.name, state: corpseStateLabel(corpse), entity: corpse };
    }
    return null;
  }

  function creatureRecordEntityLink(entity) {
    if (!entity) {
      return textEl("span", "unknown record");
    }
    if (entity.kind === "slime") {
      return slimeNameLink(entity.entity, "entity-link-chip");
    }
    return corpseNameLink(entity.entity, "entity-link-chip");
  }

  function lineageEntryForCreature(source, kind) {
    const entity = kind === "corpse"
      ? { kind, id: source.id, specimenId: source.specimenId, name: source.name, state: corpseStateLabel(source), entity: source }
      : { kind, id: source.id, specimenId: source.id, name: source.name, state: slimeStateLabel(source), entity: source };
    return {
      entity,
      parentIds: idList(source.parentIds),
      broodId: cleanLineageId(source.broodId)
    };
  }

  function renderLineageRecords() {
    if (!dom.lineageList) {
      return;
    }
    dom.lineageList.textContent = "";
    const entries = [
      ...(state.slimes || []).map((slime) => lineageEntryForCreature(slime, "slime")),
      ...(state.corpses || []).map((corpse) => lineageEntryForCreature(corpse, "corpse"))
    ].filter((entry) => entry.parentIds.length || entry.broodId);

    if (!entries.length) {
      dom.lineageList.append(emptyText("No lineage records yet. Natural splitting and forced recombination will populate this file."));
      return;
    }

    for (const entry of entries) {
      const row = document.createElement("article");
      row.className = "lineage-card";
      row.dataset.lineageRecord = entry.entity.specimenId || entry.entity.id;

      const title = document.createElement("h3");
      title.append(creatureRecordEntityLink(entry.entity), textEl("span", entry.entity.state));

      const meta = document.createElement("div");
      meta.className = "slime-meta";
      if (entry.broodId) {
        meta.append(chip(`brood ${entry.broodId}`));
      }
      if (entry.parentIds.length) {
        const parentLine = document.createElement("div");
        parentLine.className = "lineage-links";
        parentLine.append(textEl("span", "Parents: "));
        entry.parentIds.forEach((parentId, index) => {
          const parent = creatureRecordEntityBySpecimenId(parentId);
          if (index > 0) {
            parentLine.append(document.createTextNode(", "));
          }
          parentLine.append(creatureRecordEntityLink(parent));
        });
        meta.append(parentLine);
      } else {
        meta.append(chip("parents unknown"));
      }

      row.append(title, meta);
      dom.lineageList.append(row);
    }
  }


  function renderContainers() {
    state.containers = normalizeContainers(state.containers);
    dom.containerList.textContent = "";
    const permanent = permanentContainers();
    const occupied = occupiedPermanentContainerCount();
    const released = releasedSlimeCount();
    dom.containerSummary.textContent = `${occupied}/${permanent.length} permanent containers occupied${released ? `; ${released} released` : ""}`;

    const tube = synthesisTube();
    if (tube) {
      dom.containerList.append(containerCardEl(tube));
    }

    for (const container of permanent) {
      dom.containerList.append(containerCardEl(container));
    }

    const releasedSlimes = (state.slimes || []).filter((slime) => slime.status === "released");
    if (releasedSlimes.length) {
      const card = document.createElement("div");
      card.className = "container-card released";
      const title = document.createElement("div");
      title.className = "container-title";
      title.append(textEl("strong", "Released Slimes"), textEl("span", `${releasedSlimes.length} loose`));
      const list = document.createElement("div");
      list.className = "released-slime-list";
      for (const slime of releasedSlimes) {
        const row = document.createElement("div");
        row.className = "container-occupant-row";
        row.append(slimeNameLink(slime), textEl("span", roomName(slime.roomId || MAIN_ROOM_ID)));
        list.append(row);
      }
      card.append(title, list);
      dom.containerList.append(card);
    }
  }

  // Helper function to generate a compact environment summary
  function containerEnvironmentSummary(container) {
    if (!container.environment) return "";
    
    const attributes = [];
    for (const def of ROOM_ATTRIBUTE_DEFS) {
      const key = def.key;
      const value = container.environment[key]?.current || 0;
      const status = value < 25 ? "low" : value > 75 ? "high" : "normal";
      attributes.push(`${def.label}: ${value}% (${status})`);
    }
    return attributes.join("; ");
  }

  // Helper function to generate environment warnings
  function containerEnvironmentWarnings(container) {
    if (!container.environment) return [];

    const warnings = [];
    const breachState = containerBreachState(container);
    if (breachState === "breached") {
      warnings.push("Container breached");
    } else if (breachState === "compromised") {
      warnings.push("Container compromised");
    }
    const condition = containerCondition(container);
    if (condition < 25) {
      warnings.push("Container condition critical");
    } else if (condition < 50) {
      warnings.push("Container condition damaged");
    } else if (condition < 75) {
      warnings.push("Container condition worn");
    }
    for (const def of ROOM_ATTRIBUTE_DEFS) {
      const key = def.key;
      const value = container.environment[key]?.current || 0;
      
      if (value < 25) {
        warnings.push(`${def.label} low`);
      } else if (value > 75) {
        warnings.push(`${def.label} high`);
      }
    }
    return warnings;
  }


  function containerGeometry(container) {
    if (!container) return null;
    if (container.id === SYNTHESIS_TUBE_ID || container.typeId === "synthesisTube" || container.type === "synthesis") {
      return SYNTHESIS_TUBE_GEOMETRY;
    }
    return CONTAINER_BASE_TYPE_BY_ID[container.typeId]?.geometry || null;
  }

  function formatDimensionCm(value) {
    if (!Number.isFinite(value)) return "?";
    return String(Math.round(value * 10) / 10);
  }

  function formatGeometryDimensions(geometry) {
    if (!geometry?.internalCm) return "unknown size";
    const dims = geometry.internalCm;
    if (Number.isFinite(dims.diameter) && Number.isFinite(dims.height)) {
      return `${formatDimensionCm(dims.diameter)} cm diameter × ${formatDimensionCm(dims.height)} cm tall`;
    }
    if (Number.isFinite(dims.length) && Number.isFinite(dims.width) && Number.isFinite(dims.height)) {
      return `${formatDimensionCm(dims.length)} × ${formatDimensionCm(dims.width)} × ${formatDimensionCm(dims.height)} cm`;
    }
    return "unknown size";
  }

  function formatOpeningDimensions(geometry) {
    if (!geometry?.openingCm) return "";
    const opening = geometry.openingCm;
    if (Number.isFinite(opening.diameter)) {
      return `${formatDimensionCm(opening.diameter)} cm opening`;
    }
    if (Number.isFinite(opening.width) && Number.isFinite(opening.height)) {
      return `${formatDimensionCm(opening.width)} × ${formatDimensionCm(opening.height)} cm opening`;
    }
    return "";
  }

  function containerGeometrySummary(container) {
    const geometry = containerGeometry(container);
    if (!geometry) return "interior size unknown";
    const opening = formatOpeningDimensions(geometry);
    const top = geometry.openTop ? "open top" : "closed";
    return `${formatGeometryDimensions(geometry)} · ${geometry.shape} · ${top}${opening ? ` · ${opening}` : ""}`;
  }


  function containerInteriorMeasure(container) {
    const geometry = containerGeometry(container);
    const dims = geometry?.internalCm;
    if (!dims) return null;
    if (Number.isFinite(dims.diameter) && Number.isFinite(dims.height)) {
      return {
        length: dims.diameter,
        width: dims.diameter,
        height: dims.height,
        maxSpan: Math.max(dims.diameter, dims.height),
        minSpan: Math.min(dims.diameter, dims.height)
      };
    }
    if (Number.isFinite(dims.length) && Number.isFinite(dims.width) && Number.isFinite(dims.height)) {
      return {
        length: dims.length,
        width: dims.width,
        height: dims.height,
        maxSpan: Math.max(dims.length, dims.width, dims.height),
        minSpan: Math.min(dims.length, dims.width, dims.height)
      };
    }
    return null;
  }

  function containerOpeningMeasure(container) {
    const geometry = containerGeometry(container);
    const opening = geometry?.openingCm;
    if (!opening) return null;
    if (Number.isFinite(opening.diameter)) {
      return {
        width: opening.diameter,
        height: opening.diameter,
        minSpan: opening.diameter,
        maxSpan: opening.diameter
      };
    }
    if (Number.isFinite(opening.width) && Number.isFinite(opening.height)) {
      return {
        width: opening.width,
        height: opening.height,
        minSpan: Math.min(opening.width, opening.height),
        maxSpan: Math.max(opening.width, opening.height)
      };
    }
    return null;
  }

  function slimeCompressibility(profile, consistencyKnown = true) {
    const consistency = profile?.consistency || "soft gelatin";
    if (!consistencyKnown) return 0.65;
    if (["watery", "runny gel", "syrupy", "loose jelly", "mucous", "foamy", "grainy slurry"].includes(consistency)) return 0.25;
    if (["soft gelatin", "elastic gel", "bouncy rubber", "sticky taffy", "aerated mousse"].includes(consistency)) return 0.55;
    if (["dense rubber", "clay-like"].includes(consistency)) return 0.85;
    if (["crystalline gel", "brittle jelly"].includes(consistency)) return 1.05;
    return 0.75;
  }

  function slimeDimensionEstimate(profile, volumeCm3) {
    const safeVolume = Math.max(1, Number(volumeCm3) || 1);
    const root = Math.cbrt(safeVolume);
    const shape = profile?.shape || "blob";
    if (shape === "cubic") {
      return { length: root, width: root, height: root, openingNeed: root };
    }
    if (shape === "spherical") {
      const diameter = Math.cbrt((6 * safeVolume) / Math.PI);
      return { length: diameter, width: diameter, height: diameter, openingNeed: diameter };
    }
    if (shape === "humanoid-ish") {
      const height = Math.cbrt(safeVolume * 9);
      return { length: height * 0.45, width: height * 0.38, height, openingNeed: height * 0.38 };
    }
    if (shape === "dog-shaped") {
      const length = Math.cbrt(safeVolume * 5.5);
      return { length, width: length * 0.38, height: length * 0.45, openingNeed: length * 0.38 };
    }
    if (shape === "puddle" || shape === "flat sheet") {
      const depth = clamp(root * (shape === "puddle" ? 0.08 : 0.12), 1, 22);
      const spread = 2 * Math.sqrt(safeVolume / (Math.PI * depth));
      return { length: spread, width: spread, height: depth, openingNeed: Math.min(spread, 20) };
    }
    if (shape === "worm-like") {
      const length = Math.cbrt(safeVolume * 30);
      const thickness = Math.sqrt(safeVolume / (Math.PI * length)) * 2;
      return { length, width: thickness, height: thickness, openingNeed: thickness };
    }
    if (shape === "columnar") {
      const height = Math.cbrt(safeVolume * 4);
      const diameter = Math.sqrt((4 * safeVolume) / (Math.PI * height));
      return { length: diameter, width: diameter, height, openingNeed: diameter };
    }
    if (shape === "conical") {
      const height = Math.cbrt((12 * safeVolume) / Math.PI);
      const diameter = Math.sqrt((12 * safeVolume) / (Math.PI * height));
      return { length: diameter, width: diameter, height, openingNeed: diameter };
    }
    if (shape === "disc") {
      const thickness = clamp(root * 0.22, 2, 40);
      const diameter = 2 * Math.sqrt(safeVolume / (Math.PI * thickness));
      return { length: diameter, width: diameter, height: thickness, openingNeed: Math.min(diameter, Math.max(thickness, diameter * 0.35)) };
    }
    if (shape === "branching" || shape === "star-like") {
      const span = Math.cbrt(safeVolume * 8);
      const core = root * 0.34;
      return { length: span, width: span, height: core, openingNeed: core * 1.5 };
    }
    if (shape === "mushroom-shaped") {
      const height = Math.cbrt(safeVolume * 3.2);
      return { length: height * 0.72, width: height * 0.72, height, openingNeed: height * 0.72 };
    }
    if (shape === "shell-like") {
      const length = Math.cbrt(safeVolume * 3.6);
      return { length, width: length * 0.62, height: length * 0.32, openingNeed: length * 0.62 };
    }
    const height = Math.cbrt(safeVolume * 0.75);
    const width = Math.sqrt(safeVolume / height);
    return { length: width, width, height, openingNeed: width };
  }

  function containerDimensionalSuitabilityConcerns(slime, container, profile, options = {}) {
    const interior = containerInteriorMeasure(container);
    if (!interior || !profile) return [];
    const massFraction = clamp(slimeStat(slime, "currentMass").current, 1, 100) / 100;
    const currentDims = slimeDimensionEstimate(profile, profile.volumeCm3 * massFraction);
    const fullDims = slimeDimensionEstimate(profile, profile.volumeCm3);
    const compressibility = slimeCompressibility(profile, options.consistencyKnown);
    const concerns = [];
    const floorLong = Math.max(interior.length, interior.width);
    const floorShort = Math.min(interior.length, interior.width);
    const currentLong = Math.max(currentDims.length, currentDims.width);
    const currentShort = Math.min(currentDims.length, currentDims.width);
    const fullLong = Math.max(fullDims.length, fullDims.width);
    const fullShort = Math.min(fullDims.length, fullDims.width);

    if (currentDims.height > interior.height * (1.25 + (1 - compressibility) * 0.35)) {
      concerns.push({ severity: compressibility >= 0.9 ? "severe" : "major", text: `Current body height presses against the ${containerTypeLabel(container.typeId)} interior.` });
    } else if (fullDims.height > interior.height * (1.35 + (1 - compressibility) * 0.35)) {
      concerns.push({ severity: compressibility >= 0.9 ? "major" : "moderate", text: `Full-size body may become too tall for the ${containerTypeLabel(container.typeId)} interior.` });
    }

    if (currentLong > floorLong * (1.2 + (1 - compressibility) * 0.5) || currentShort > floorShort * (1.2 + (1 - compressibility) * 0.5)) {
      concerns.push({ severity: compressibility >= 0.9 ? "severe" : "major", text: `Current body dimensions strain the ${containerTypeLabel(container.typeId)} floor space.` });
    } else if (fullLong > floorLong * (1.35 + (1 - compressibility) * 0.5) || fullShort > floorShort * (1.35 + (1 - compressibility) * 0.5)) {
      concerns.push({ severity: compressibility >= 0.9 ? "major" : "moderate", text: `Full-size body may outgrow the ${containerTypeLabel(container.typeId)} interior dimensions.` });
    }

    const geometry = containerGeometry(container);
    const opening = containerOpeningMeasure(container);
    if (opening && !geometry?.openTop) {
      const openingNeed = currentDims.openingNeed * compressibility;
      const fullOpeningNeed = fullDims.openingNeed * compressibility;
      if (openingNeed > opening.minSpan * 1.1) {
        concerns.push({ severity: compressibility >= 0.9 ? "major" : "moderate", text: `Current body may be difficult to move through the ${containerTypeLabel(container.typeId)} opening.` });
      } else if (fullOpeningNeed > opening.minSpan * 1.2) {
        concerns.push({ severity: compressibility >= 0.9 ? "moderate" : "minor", text: `Full-size body may not pass cleanly through the ${containerTypeLabel(container.typeId)} opening.` });
      }
    }

    if (geometry?.openTop && ["climbing", "hopping", "scuttling", "clinging"].includes(profile.movement)) {
      concerns.push({ severity: "minor", text: `Open-top geometry may matter if this slime's movement lets it climb or hop.` });
    }

    return concerns.slice(0, 3);
  }



  function normalizeContainerCondition(value) {
    const number = Number(value);
    return clamp(Number.isFinite(number) ? number : CONTAINER_CONDITION_DEFAULT, 0, 100);
  }

  function containerCondition(container) {
    if (!container) return CONTAINER_CONDITION_DEFAULT;
    container.condition = normalizeContainerCondition(container.condition);
    return container.condition;
  }

  function adjustContainerCondition(container, delta) {
    if (!container) return false;
    const before = containerCondition(container);
    container.condition = normalizeContainerCondition(before + (Number(delta) || 0));
    return Math.abs(container.condition - before) >= 0.01;
  }

  function applyContainerMaterialDamage(container, amount, damageTypeId, source = "damage") {
    if (!container) return null;
    const damageId = normalizeDamageTypeId(damageTypeId) || "physical";
    const resistance = containerDamageResistanceScore(container, damageId);
    const effective = Math.max(0.1, roundOutputValue(Math.max(0, Number(amount) || 0) * clamp((115 - resistance) / 75, 0.15, 1.5)));
    const before = containerCondition(container);
    adjustContainerCondition(container, -effective);
    if (containerCondition(container) <= 0) {
      container.breachState = "breached";
      container.isOpen = true;
    } else if (containerCondition(container) < STRUCTURE_BREACH_THRESHOLD && containerBreachState(container) === "intact") {
      container.breachState = "compromised";
    }
    addEvent(`${container.name} took ${formatNumber(effective)} ${damageTypeDef(damageId)?.label.toLowerCase()} damage from ${source}; ${containerConditionLabel(container)}.`);
    return { effective, before, after: containerCondition(container), resistance };
  }

  function debugDamageContainer(containerId, damageTypeId, amount = 40) {
    const container = containerById(containerId);
    if (!container) return false;
    applyContainerMaterialDamage(container, amount, damageTypeId, `debug ${damageTypeDef(damageTypeId)?.label.toLowerCase() || damageTypeId} damage`);
    refreshIncidentAlerts();
    persist();
    render();
    return true;
  }

  function containerConditionLabel(container) {
    const condition = containerCondition(container);
    if (condition < 25) return `${formatNumber(condition)}% critical`;
    if (condition < 50) return `${formatNumber(condition)}% damaged`;
    if (condition < 75) return `${formatNumber(condition)}% worn`;
    return `${formatNumber(condition)}% intact`;
  }

  function normalizeContainmentIncidentProgress(candidate) {
    const source = candidate && typeof candidate === "object" ? candidate : {};
    const normalized = {};
    for (const [key, value] of Object.entries(source)) {
      if (!key || !value || typeof value !== "object") {
        continue;
      }
      normalized[key] = {
        progress: Math.max(0, Number(value.progress) || 0),
        lastIncidentAt: Number.isFinite(Number(value.lastIncidentAt)) ? Number(value.lastIncidentAt) : null
      };
    }
    return normalized;
  }

  function containmentIncidentKey(slime, container) {
    return `${container?.id || "room"}:${slime?.id || "unknown"}`;
  }

  function containmentIncidentRecord(slime, container) {
    state.containmentIncidentProgress = normalizeContainmentIncidentProgress(state.containmentIncidentProgress);
    const key = containmentIncidentKey(slime, container);
    state.containmentIncidentProgress[key] ||= { progress: 0, lastIncidentAt: null };
    return state.containmentIncidentProgress[key];
  }

  function cleanupContainmentIncidentProgress() {
    if (!state?.containmentIncidentProgress) return;
    const activeKeys = new Set();
    for (const slime of state.slimes || []) {
      if (!slime || slime.status !== "contained" || !slime.containerId) {
        continue;
      }
      const container = containerById(slime.containerId);
      if (container) {
        activeKeys.add(containmentIncidentKey(slime, container));
      }
    }
    for (const key of Object.keys(state.containmentIncidentProgress)) {
      if (!activeKeys.has(key)) {
        delete state.containmentIncidentProgress[key];
      }
    }
  }

  function updateSlimeHabitatEffects(minutes) {
    const elapsed = Math.max(0, Number(minutes) || 0);
    if (!elapsed || !state?.started) {
      return 0;
    }
    let changes = 0;
    const days = secondsToDays(elapsed);
    for (const slime of state.slimes || []) {
      if (!slime || slime.status === "dead") {
        continue;
      }
      if (slime.status === "contained" && containerById(slime.containerId)?.type === "synthesis") {
        continue;
      }
      const fit = slimeHabitatFit(slime);
      const previousRecord = JSON.stringify(slime.habitat || {});
      slime.habitat = cleanSlimeHabitatRecord(fit);
      if (JSON.stringify(slime.habitat) !== previousRecord) {
        changes += 1;
      }
      const stressDelta = fit.stressPerDay * days;
      if (Math.abs(stressDelta) < 0.01) {
        continue;
      }
      const beforeStress = slimeStat(slime, "stress").current;
      adjustSlimeStat(slime, "stress", stressDelta);
      if (Math.abs(slimeStat(slime, "stress").current - beforeStress) >= 0.01) {
        changes += 1;
      }
    }
    return changes;
  }

  function updateContainerCompatibilityEffects(minutes) {
    const elapsed = Math.max(0, Number(minutes) || 0);
    if (!elapsed || !state?.started) {
      return 0;
    }
    let changes = 0;
    for (const slime of state.slimes || []) {
      if (!slime || slime.status !== "contained" || slime.status === "dead" || !slime.containerId) {
        continue;
      }
      const container = containerById(slime.containerId);
      if (!container || container.type === "synthesis") {
        continue;
      }
      const compatibility = containerCompatibilityAssessment(slime, container, { knownOnly: false });
      if (compatibility.score < 35) {
        continue;
      }
      const days = secondsToDays(elapsed);
      const severity = compatibility.score >= 90 ? 1
        : compatibility.score >= 60 ? 0.55
          : 0.25;
      const stressDelta = (1.5 + severity * 3) * days;
      if (stressDelta >= 0.01) {
        const beforeStress = slimeStat(slime, "stress").current;
        adjustSlimeStat(slime, "stress", stressDelta);
        if (Math.abs(slimeStat(slime, "stress").current - beforeStress) >= 0.01) {
          changes += 1;
        }
      }
      if (compatibility.materialScore >= 16) {
        const contaminationDelta = (0.6 + severity * 2.4) * days;
        if (contaminationDelta >= 0.01) {
          changes += adjustContainerEnvironment(container, "contamination", contaminationDelta) ? 1 : 0;
        }
        const conditionDelta = -(0.2 + severity * 0.8) * days;
        if (Math.abs(conditionDelta) >= 0.01) {
          changes += adjustContainerCondition(container, conditionDelta) ? 1 : 0;
        }
      }
      if (compatibility.supportScore >= 16) {
        const contaminationDelta = (0.4 + severity * 1.2) * days;
        if (contaminationDelta >= 0.01) {
          changes += adjustContainerEnvironment(container, "contamination", contaminationDelta) ? 1 : 0;
        }
      }
      if (compatibility.score >= 60) {
        const record = containmentIncidentRecord(slime, container);
        const beforeProgress = record.progress;
        record.progress += secondsToMinutes(elapsed) * (compatibility.score >= 90 ? 0.28 : 0.12);
        if (Math.abs(record.progress - beforeProgress) >= 0.01) {
          changes += 1;
        }
      }
    }
    return changes;
  }

  function updateContainmentIncidents(minutes) {
    const elapsed = Math.max(0, Number(minutes) || 0);
    if (!elapsed || !state?.started) {
      return 0;
    }

    let changes = 0;
    cleanupContainmentIncidentProgress();

    for (const slime of state.slimes || []) {
      if (!slime || slime.status !== "contained" || slime.status === "dead" || !slime.containerId) {
        continue;
      }

      const container = containerById(slime.containerId);
      if (!container || container.type === "synthesis") {
        continue;
      }

      const risk = activeContainmentRisk(slime, container);
      const record = containmentIncidentRecord(slime, container);

      if (risk.score < 75) {
        const before = record.progress;
        record.progress = Math.max(0, record.progress - CONTAINMENT_INCIDENT_PROGRESS_DECAY_PER_HOUR * secondsToHours(elapsed));
        if (Math.abs(record.progress - before) >= 0.01) {
          changes += 1;
        }
        continue;
      }

      const riskMultiplier = risk.score >= 110 ? 1.6 : 1 + (risk.score - 75) / 80;
      record.progress += secondsToMinutes(elapsed) * riskMultiplier;

      const cooldownReady = record.lastIncidentAt == null || state.clock - record.lastIncidentAt >= CONTAINMENT_INCIDENT_COOLDOWN;
      if (record.progress >= CONTAINMENT_INCIDENT_THRESHOLD && cooldownReady) {
        const incident = chooseMinorContainmentIncident(slime, container, risk);
        triggerMinorContainmentIncident(slime, container, risk, incident);
        record.progress = 0;
        record.lastIncidentAt = state.clock;
        changes += 1;
      }
    }

    return changes;
  }

  function chooseMinorContainmentIncident(slime, container, risk) {
    const evaluated = evaluateGenome(slime.genome);
    const profile = physicalProfile(slime.genome, evaluated);
    const seal = containerEffectiveSeal(container);
    const type = containerTypeDef(container.typeId);
    const byproduct = baseOutcomeLabel(evaluated.traits.byproduct);
    const runny = ["watery", "runny gel", "syrupy", "loose jelly", "mucous", "foamy", "grainy slurry"].includes(profile?.consistency);
    const foulingByproduct = ["adhesive gel", "black resin", "grease pearls", "coagulating wax", "acid droplets", "corrosive slime", "dissolved sludge", "smoke vapor", "numbing paste", "contaminated residue", "irritant film", "bitter sludge", "warm tar", "dark mucus", "inky gel", "plant mucus"].includes(byproduct);

    if ((runny && (seal < 55 || type.gap >= 60)) || risk.potentialReasons.some((reason) => /gap|seal|seep/i.test(reason))) {
      return "leak";
    }

    if (foulingByproduct || risk.potentialReasons.some((reason) => /foul|mess|exposure|contamination/i.test(reason))) {
      return "fouling";
    }

    if (risk.potentialReasons.some((reason) => /damage|durability|weight|critical|damaged/i.test(reason))) {
      return "strain";
    }

    return "disturbance";
  }

  function triggerMinorContainmentIncident(slime, container, risk, incident) {
    const incidentLabel = {
      disturbance: "disturbance",
      fouling: "fouling",
      leak: "leak/seep strain",
      strain: "structural strain"
    }[incident] || "disturbance";

    let message = `Minor containment incident: ${slime.name} caused ${incidentLabel} in ${container.name}.`;
    let suspicion = 0;

    if (incident === "fouling") {
      adjustContainerEnvironment(container, "contamination", 8);
      adjustContainerCondition(container, -1);
      adjustSlimeStat(slime, "stress", 2);
      message += " Interior contamination rose.";
    } else if (incident === "leak") {
      adjustContainerEnvironment(container, "contamination", 5);
      adjustRoomAttribute(container.roomId || slime.roomId || MAIN_ROOM_ID, "contamination", 2);
      adjustContainerCondition(container, -2);
      adjustSlimeStat(slime, "stress", 3);
      suspicion = 1;
      message += " A small trace reached the room.";
    } else if (incident === "strain") {
      adjustContainerCondition(container, -4);
      adjustSlimeStat(slime, "stress", 2);
      message += " The container condition worsened.";
    } else {
      adjustContainerCondition(container, -1);
      adjustSlimeStat(slime, "stress", 3);
      message += " The disturbance raised Stress.";
    }

    if (risk.label === "Failing") {
      suspicion += 1;
    }

    if (suspicion) {
      addSuspicion(suspicion);
      message += ` Suspicion +${suspicion}.`;
    }

    addEvent(message);
    return true;
  }

  function containmentTestMethodDef(methodId) {
    return CONTAINMENT_TEST_METHOD_BY_ID[cleanContainmentTestMethod(methodId)] || CONTAINMENT_TEST_METHOD_BY_ID.none;
  }

  function containmentTestRecordForSlime(slime) {
    if (!slime) {
      return defaultContainmentTestRecord();
    }
    slime.containmentTest = normalizeContainmentTestRecord(slime.containmentTest);
    return slime.containmentTest;
  }

  function containmentTestPressureClassName(record) {
    const band = cleanContainmentTestBand(record?.pressureBand);
    if (band === "critical") return "container-band-unsuitable";
    if (band === "high") return "container-band-poor";
    if (band === "moderate" || band === "low") return "container-band-questionable";
    return "container-band-good";
  }

  function containmentTestDamageTypes(slime, methodId) {
    const method = containmentTestMethodDef(methodId);
    const baseTypes = method.id === "ability"
      ? slimeCombatDamageTypes(slime)
      : method.damageTypes.map(damageTypeDef).filter(Boolean);
    const seen = new Set();
    return baseTypes
      .filter(Boolean)
      .filter((type) => {
        if (seen.has(type.id)) return false;
        seen.add(type.id);
        return true;
      });
  }

  function containmentTestingVisibleReason(slime, traitKey, knownText, hiddenText = "unidentified biology is affecting containment behavior") {
    return traitKey && !slimeTraitKnown(slime, traitKey) ? hiddenText : knownText;
  }

  function containmentTestingBehaviorPressure(behavior) {
    return {
      "vibration hunting": 22,
      guarding: 17,
      swarming: 16,
      burrowing: 18,
      "still ambush": 12,
      circling: 8,
      "edge following": 10,
      "tool orbiting": 10,
      "sound following": 8,
      hiding: 5
    }[behavior] || 0;
  }

  function containmentTestingStabilityPressure(stability, risk) {
    if (risk >= 8 || /predatory/.test(stability)) return 28;
    if (risk >= 7 || /volatile|erratic/.test(stability)) return 22;
    if (risk >= 6 || /fractious|territorial/.test(stability)) return 16;
    if (/hungry|nervous|fragile/.test(stability)) return 10;
    if (/placid|docile|steady|obedient|dormant/.test(stability)) return -8;
    return 0;
  }

  function containmentTestingPressureInfo(slime, container, evaluated, profile) {
    const reasons = [];
    let score = 0;
    const add = (points, reason) => {
      score += Number(points) || 0;
      if (reason) reasons.push(reason);
    };

    const stress = slimeStatPercent(slime, "stress");
    const nutrition = slimeStatPercent(slime, "nutrition");
    const integrity = slimeStatPercent(slime, "bodyIntegrity");
    const mass = slimeStatPercent(slime, "currentMass");
    const division = slimeStatPercent(slime, "divisionPressure");
    const condition = containerCondition(container);
    const compatibility = containerCompatibilityAssessment(slime, container, { knownOnly: false });
    const habitat = slimeHabitatFit(slime, { knownOnly: false });
    const type = containerTypeDef(container.typeId);
    const revealed = slime.revealed || {};
    const recentPain = recentPainForSlime(slime);

    if (stress >= 85) add(32, "high Stress is driving active testing");
    else if (stress >= 65) add(22, "Stress is high enough to make the slime restless");
    else if (stress >= 40) add(10, "rising Stress may lead to probing");

    if (nutrition <= 8) add(34, "critical hunger is pushing the slime to search for escape routes");
    else if (nutrition <= 20) add(24, "hunger is pushing the slime to test containment");
    else if (nutrition <= 35) add(12, "low nutrition is increasing escape pressure");

    if (integrity <= 18) add(18, "failing Body Integrity is making behavior desperate");
    else if (integrity <= 35) add(10, "damaged Body Integrity is making behavior less stable");

    if (recentPain) {
      add(clamp(8 + recentPain.amount, 8, 26), "recent pain is provoking containment testing");
    }

    if (habitat.band.id === "hostile") add(26, "hostile habitat is provoking containment testing");
    else if (habitat.band.id === "poor") add(14, "poor habitat fit is making containment uncomfortable");

    if (compatibility.score >= 90) add(28, containmentTestingVisibleReason(slime, "", "container compatibility is dangerously poor"));
    else if (compatibility.score >= 60) add(18, "container compatibility is poor");
    else if (compatibility.score >= 35) add(8, "container compatibility is questionable");

    if (condition < 15) add(24, "damaged containment gives the slime something to exploit");
    else if (condition < 35) add(15, "worn containment gives the slime weak points");
    else if (condition < 60) add(6, "container wear is becoming noticeable");

    if (containerAccessOpen(container)) add(22, "open handling access creates an obvious route");
    if (isContainerInTransit(container.id)) add(12, "being hauled is disturbing the slime");
    if (type.gap >= 60 || containerEffectiveSeal(container) < 35) add(12, "gaps or weak sealing invite probing");
    if (mass >= 95 && division >= 65) add(10, "full body mass and division pressure are crowding containment");

    const behavior = baseOutcomeLabel(evaluated.traits.behavior);
    const behaviorPoints = containmentTestingBehaviorPressure(behavior);
    if (behaviorPoints) {
      add(behaviorPoints, containmentTestingVisibleReason(slime, "behavior", `${behavior} behavior may test boundaries`, "unidentified behavior is testing boundaries"));
    }

    const stability = baseOutcomeLabel(evaluated.traits.stability);
    const stabilityRisk = Number(evaluated.traits.stability.meta?.risk) || 0;
    const stabilityPoints = containmentTestingStabilityPressure(stability, stabilityRisk);
    if (stabilityPoints > 0) {
      add(stabilityPoints, containmentTestingVisibleReason(slime, "stability", `${stability} stability raises escape pressure`, "unidentified temperament is raising escape pressure"));
    } else if (stabilityPoints < 0) {
      score += stabilityPoints;
      if (revealed.stability) reasons.push(`${stability} stability dampens testing`);
    }

    return {
      score: clamp(score, 0, 120),
      reasons: [...new Set(reasons)].filter(Boolean).slice(0, 6),
      compatibility,
      habitat,
      profile
    };
  }

  function scoreContainmentTestMethods(slime, container, evaluated, profile, pressureInfo) {
    const type = containerTypeDef(container.typeId);
    const methodScores = {
      wait: 8,
      press: 12,
      attack: 0,
      seep: 0,
      corrode: 0,
      shock: 0,
      climb: 0,
      foul: 0,
      ability: 0
    };
    const reasons = {};
    const add = (methodId, points, reason) => {
      methodScores[methodId] = (methodScores[methodId] || 0) + Math.max(0, Number(points) || 0);
      if (reason) {
        reasons[methodId] ||= [];
        reasons[methodId].push(reason);
      }
    };

    const consistency = profile?.consistency || "";
    const appendages = profile?.appendages || "none";
    const behavior = baseOutcomeLabel(evaluated.traits.behavior);
    const stability = baseOutcomeLabel(evaluated.traits.stability);
    const byproduct = baseOutcomeLabel(evaluated.traits.byproduct);
    const damageIds = new Set(slimeCombatDamageTypes(slime).map((typeDef) => typeDef.id));
    const weakestResistance = (damageId) => containerDamageResistanceScore(container, damageId);

    if (["watery", "runny gel", "syrupy", "loose jelly", "mucous", "foamy", "grainy slurry"].includes(consistency)) {
      add("seep", 32, containmentTestingVisibleReason(slime, "consistency", `${consistency} body can search along seals`, "fluid body behavior is visible at the seal"));
    }
    if (["mucous", "tar-like", "waxen", "syrupy"].includes(consistency)) {
      add("foul", 18, containmentTestingVisibleReason(slime, "consistency", `${consistency} body can foul the interior`, "sticky body behavior is fouling the interior"));
      add("climb", 8, containmentTestingVisibleReason(slime, "consistency", `${consistency} body can cling to surfaces`, "clingy body behavior is testing surfaces"));
    }
    if (["rubbery", "clay-like", "crystalline gel"].includes(consistency)) {
      add("press", 12, containmentTestingVisibleReason(slime, "consistency", `${consistency} body can apply pressure`, "solid body pressure is visible"));
    }

    if (appendages && appendages !== "none") {
      add("climb", 26, containmentTestingVisibleReason(slime, "appendages", `${appendages} can grip or probe seams`, "appendages are probing seams"));
      if (["spines", "hook claws", "limb-like arms", "grasping pseudopods"].includes(appendages)) {
        add("attack", 16, containmentTestingVisibleReason(slime, "appendages", `${appendages} can strike or pry at weak points`, "appendages are striking weak points"));
      }
    }

    if (damageIds.has("corrosive")) add("corrode", 34 + Math.max(0, 45 - weakestResistance("corrosive")) * 0.2, "corrosive force is suited to weak material");
    if (damageIds.has("electrical")) add("shock", 32 + Math.max(0, 45 - weakestResistance("electrical")) * 0.2, "electrical force is testing fittings");
    if (damageIds.has("moisture")) add("seep", 18 + Math.max(0, 45 - weakestResistance("moisture")) * 0.15, "moisture force supports seepage");
    const abilityDamageIds = [...damageIds].filter((id) => !["physical", "corrosive", "electrical", "moisture"].includes(id));
    if (abilityDamageIds.length) {
      const weakestAbilityResistance = Math.min(...abilityDamageIds.map((id) => weakestResistance(id)));
      add("ability", 55 + Math.max(0, 50 - weakestAbilityResistance) * 0.25, "unstable elemental force is pushing against containment");
    }
    if (damageIds.has("force")) add("press", 18, "force-aspected pressure stresses the container");
    if (damageIds.has("physical")) add("press", 8, "physical body pressure stresses the container");

    if (/acid|solvent|corrosive|dissolved/.test(byproduct)) {
      add("corrode", 18, containmentTestingVisibleReason(slime, "byproduct", `${byproduct} can attack weak materials`, "produced residue is attacking weak material"));
      add("foul", 10, containmentTestingVisibleReason(slime, "byproduct", `${byproduct} can foul the interior`, "produced residue is fouling the interior"));
    }
    if (/smoke|contaminated|irritant|bitter|numbing|mucus|resin|tar|wax|grease/.test(byproduct)) {
      add("foul", 18, containmentTestingVisibleReason(slime, "byproduct", `${byproduct} can foul containment`, "produced residue is fouling containment"));
    }

    if (/vibration hunting|guarding|still ambush|swarming/.test(behavior)) add("attack", 24, containmentTestingVisibleReason(slime, "behavior", `${behavior} behavior favors direct attacks`, "observed behavior favors direct attacks"));
    if (/burrowing/.test(behavior)) add("press", 20, containmentTestingVisibleReason(slime, "behavior", "burrowing behavior favors pressure", "observed behavior favors pressure"));
    if (/edge following|tool orbiting|circling|sound following/.test(behavior)) add("wait", 16, containmentTestingVisibleReason(slime, "behavior", `${behavior} behavior may watch for routines`, "observed behavior is tracking routines"));
    if (/predatory|territorial|volatile|erratic|fractious|hungry/.test(stability)) add("attack", 18, containmentTestingVisibleReason(slime, "stability", `${stability} stability favors direct testing`, "temperament favors direct testing"));
    if (/nervous|fragile|dormant|apathetic/.test(stability)) add("wait", 12, containmentTestingVisibleReason(slime, "stability", `${stability} stability favors waiting`, "temperament favors waiting"));

    if (type.gap >= 60 || containerEffectiveSeal(container) < 45) {
      add("seep", 18, "gaps and weak sealing give seepage a route");
      add("climb", 10, "gaps give appendages places to probe");
      add("wait", 6, "weak access rewards waiting");
    }
    if (type.durability < 45 || containerCondition(container) < 35) {
      add("attack", 16, "weak condition rewards direct attacks");
      add("press", 12, "weak condition rewards pressure");
    }
    if (!type.drainage) {
      add("foul", 8, "lack of drainage makes fouling easier");
    }
    if (pressureInfo.pressure >= 85) {
      add("attack", 10, "critical pressure makes direct action more likely");
      add("ability", 8, "critical pressure makes unstable force more likely");
    }

    const best = Object.entries(methodScores)
      .filter(([methodId]) => methodId !== "none")
      .sort((a, b) => b[1] - a[1])[0] || ["press", 0];
    const methodId = best[1] > 0 ? best[0] : "press";
    return {
      methodId,
      methodScore: best[1],
      reasons: [...new Set(reasons[methodId] || [])].filter(Boolean).slice(0, 3)
    };
  }

  function evaluateContainmentTesting(slime, container) {
    const previous = containmentTestRecordForSlime(slime);
    if (!slime || !container || slime.status !== "contained" || slime.status === "dead" || container.type === "synthesis") {
      return normalizeContainmentTestRecord({ active: false, progress: 0 });
    }
    const evaluated = evaluateGenome(slime.genome);
    const profile = physicalProfile(slime.genome, evaluated);
    const pressureInfo = containmentTestingPressureInfo(slime, container, evaluated, profile);
    const band = containmentTestBandForPressure(pressureInfo.score);
    if (band.id === "quiet" || band.id === "low") {
      return normalizeContainmentTestRecord({
        ...previous,
        active: false,
        method: "none",
        methodLabel: CONTAINMENT_TEST_METHOD_BY_ID.none.label,
        activity: CONTAINMENT_TEST_METHOD_BY_ID.none.activity,
        pressure: pressureInfo.score,
        pressureBand: band.id,
        pressureLabel: band.label,
        reasons: pressureInfo.reasons,
        effects: [],
        lastEvaluatedAt: state.clock,
        lastResult: band.id === "low" ? "Minor warning signs only." : "No active containment testing."
      });
    }
    const methodInfo = scoreContainmentTestMethods(slime, container, evaluated, profile, { ...pressureInfo, pressure: pressureInfo.score });
    const method = containmentTestMethodDef(methodInfo.methodId);
    return normalizeContainmentTestRecord({
      ...previous,
      active: true,
      method: method.id,
      methodLabel: method.label,
      activity: method.activity,
      pressure: pressureInfo.score,
      pressureBand: band.id,
      pressureLabel: band.label,
      reasons: [...methodInfo.reasons, ...pressureInfo.reasons].slice(0, 6),
      effects: previous.effects,
      lastEvaluatedAt: state.clock,
      lastResult: `${method.label}; ${band.label.toLowerCase()} escape pressure.`
    });
  }

  function containmentTestPressureScale(record) {
    const band = cleanContainmentTestBand(record?.pressureBand);
    return {
      quiet: 0,
      low: 0.35,
      moderate: 0.75,
      high: 1.15,
      critical: 1.6
    }[band] || 0;
  }

  function containmentTestResistanceFactor(container, damageTypes) {
    const types = damageTypes?.length ? damageTypes : [DAMAGE_TYPE_BY_ID.physical];
    const weakest = Math.min(...types.map((type) => containerDamageResistanceScore(container, type.id)));
    return clamp((105 - weakest) / 70, 0.18, 1.45);
  }

  function applyContainmentTestPractice(slime, record, damageTypes, scale, hours) {
    const practice = clamp(hours * scale, 0, 8);
    if (practice <= 0) {
      return 0;
    }
    let changes = 0;
    if (record.method === "attack") {
      changes += awardCreatureSkillXp(slime, "striking", CREATURE_PRACTICE_XP.strikingPerCycle * practice, "attacking containment", { outcome: "partial" }) > 0 ? 1 : 0;
    }
    if (["ability", "corrode", "shock"].includes(record.method)) {
      changes += awardCreatureDamageSkillXp(slime, damageTypes, CREATURE_PRACTICE_XP.elementalPerCycle * practice, "testing containment", { outcome: "partial" }) > 0 ? 1 : 0;
    }
    if (["press", "climb"].includes(record.method)) {
      changes += awardCreatureSkillXp(slime, "toughness", Math.max(0.2, practice * 0.4), "straining containment", { outcome: "failure" }) > 0 ? 1 : 0;
    }
    if (rememberCreatureExperience(slime, "containmentTested", Math.max(0.2, practice * 0.4), record.activity)) {
      changes += 1;
    }
    return changes;
  }

  function applyContainmentTestEffects(slime, container, record, elapsed) {
    if (!record.active || !elapsed) {
      return 0;
    }
    const method = containmentTestMethodDef(record.method);
    const days = secondsToDays(elapsed);
    const hours = secondsToHours(elapsed);
    const minutes = secondsToMinutes(elapsed);
    const scale = containmentTestPressureScale(record);
    const damageTypes = containmentTestDamageTypes(slime, method.id);
    const resistanceFactor = containmentTestResistanceFactor(container, damageTypes);
    let changes = 0;
    const effects = [];

    const progressBefore = record.progress;
    record.progress = clamp(
      record.progress + minutes * method.progressRate * scale * resistanceFactor,
      0,
      CONTAINMENT_TEST_PROGRESS_THRESHOLD * 1.5
    );
    if (Math.abs(record.progress - progressBefore) >= 0.01) {
      changes += 1;
    }

    const conditionDelta = -method.conditionPerDay * days * scale * resistanceFactor;
    if (Math.abs(conditionDelta) >= 0.01 && adjustContainerCondition(container, conditionDelta)) {
      changes += 1;
      effects.push("container wear");
      if (Math.abs(conditionDelta) >= 0.5) {
        rememberCreatureExperience(slime, "containmentDamage", Math.min(10, Math.abs(conditionDelta) * 2), method.activity);
      }
    }

    const contaminationDelta = method.contaminationPerDay * days * scale * resistanceFactor;
    if (contaminationDelta >= 0.01 && adjustContainerEnvironment(container, "contamination", contaminationDelta)) {
      changes += 1;
      effects.push("interior contamination");
    }

    if (["seep", "foul", "corrode"].includes(method.id) && (containerCondition(container) < 25 || record.pressureBand === "critical")) {
      const roomDelta = contaminationDelta * 0.2;
      if (roomDelta >= 0.02 && adjustRoomAttribute(container.roomId || slime.roomId || MAIN_ROOM_ID, "contamination", roomDelta)) {
        changes += 1;
        effects.push("room trace");
      }
    }

    const stressDelta = method.stressPerDay * days * scale;
    if (stressDelta >= 0.01) {
      const beforeStress = slimeStat(slime, "stress").current;
      adjustSlimeStat(slime, "stress", stressDelta);
      if (Math.abs(slimeStat(slime, "stress").current - beforeStress) >= 0.01) {
        changes += 1;
        effects.push("stress");
      }
    }

    changes += applyContainmentTestPractice(slime, record, damageTypes, scale, hours);
    record.effects = [...new Set(effects)].slice(0, 5);
    record.lastActedAt = state.clock;
    record.lastResult = effects.length
      ? `${method.label}; warning signs: ${record.effects.join(", ")}.`
      : `${method.label}; no obvious effect yet.`;
    return changes;
  }

  function maybeReportContainmentTesting(slime, container, record, previous) {
    if (!record.active) {
      return 0;
    }
    const methodChanged = previous?.method && previous.method !== record.method;
    const becameActive = !previous?.active;
    const highPressure = ["high", "critical"].includes(record.pressureBand);
    const cooldownReady = record.lastEventAt == null || state.clock - record.lastEventAt >= CONTAINMENT_TEST_EVENT_COOLDOWN;
    if (!cooldownReady && !methodChanged) {
      return 0;
    }
    if (!becameActive && !methodChanged && !highPressure && record.progress < CONTAINMENT_TEST_PROGRESS_THRESHOLD) {
      return 0;
    }

    const warning = `${slime.name} is ${record.activity} in ${container.name}. Escape pressure: ${record.pressureLabel}.`;
    addEvent(warning);
    record.lastEventAt = state.clock;
    return 1;
  }

  function containerBreachResult(type, overrides = {}) {
    const defs = {
      seepedSeal: {
        label: "Seeped seal",
        breachState: "compromised",
        reusable: true,
        setOpen: false,
        conditionDamage: 3,
        containerContamination: 6,
        roomContamination: 5,
        summary: "fluid body mass escaped through a weak seal or gap."
      },
      climbedOut: {
        label: "Climbed out",
        breachState: "compromised",
        reusable: true,
        setOpen: true,
        conditionDamage: 1,
        containerContamination: 2,
        roomContamination: 2,
        summary: "the slime used openings, gaps, or exposed edges to leave mostly intact containment."
      },
      forcedOpening: {
        label: "Forced opening",
        breachState: "compromised",
        reusable: true,
        setOpen: true,
        conditionDamage: 6,
        containerContamination: 3,
        roomContamination: 3,
        summary: "the slime forced a lid, latch, or weak access point open."
      },
      crackedContainer: {
        label: "Cracked container",
        breachState: "breached",
        reusable: false,
        setOpen: true,
        conditionDamage: 100,
        containerContamination: 8,
        roomContamination: 6,
        summary: "the container cracked open under direct pressure."
      },
      dissolvedWall: {
        label: "Dissolved wall",
        breachState: "breached",
        reusable: false,
        setOpen: true,
        conditionDamage: 100,
        containerContamination: 12,
        roomContamination: 8,
        summary: "corrosive force ate through the containment material."
      },
      overturnedSpill: {
        label: "Overturned spill",
        breachState: "compromised",
        reusable: true,
        setOpen: true,
        conditionDamage: 5,
        containerContamination: 5,
        roomContamination: 7,
        summary: "the container tipped or spilled enough for the slime to leave."
      },
      arcaneFittingFailure: {
        label: "Arcane fitting failure",
        breachState: "compromised",
        reusable: true,
        setOpen: true,
        conditionDamage: 5,
        containerContamination: 4,
        roomContamination: 4,
        summary: "unstable elemental force disrupted the container's fittings or seal."
      }
    };
    return { type, ...(defs[type] || defs.forcedOpening), ...overrides };
  }

  function chooseContainerBreachResult(slime, container, record) {
    const method = cleanContainmentTestMethod(record?.method);
    const evaluated = evaluateGenome(slime.genome);
    const profile = physicalProfile(slime.genome, evaluated);
    const type = containerTypeDef(container.typeId);
    const damageTypes = containmentTestDamageTypes(slime, method);
    const damageIds = new Set(damageTypes.map((damageType) => damageType.id));
    const runny = ["watery", "runny gel", "syrupy", "loose jelly", "mucous", "foamy", "grainy slurry"].includes(profile?.consistency);
    const hasAppendages = profile?.appendages && profile.appendages !== "none";
    const openOrGapped = type.geometry?.openTop || type.gap >= 60 || containerAccessOpen(container);
    const weakSeal = containerEffectiveSeal(container) < 45 || type.gap >= 45;
    const fragile = type.durability < 45 || /glass|jar|tray/i.test(type.label);
    const currentMass = clamp(slimeStat(slime, "currentMass").current, 1, 100) / 100;
    const effectiveWeight = (profile?.weightKg || 0) * currentMass;

    if (method === "corrode" || damageIds.has("corrosive")) {
      return containerBreachResult("dissolvedWall", {
        summary: `${slime.name}'s corrosive pressure ate through ${container.name}.`
      });
    }

    if (method === "seep" || (runny && weakSeal)) {
      return containerBreachResult("seepedSeal", {
        summary: `${slime.name} seeped through a weak seal or gap in ${container.name}.`
      });
    }

    if (method === "shock" || method === "ability" || damageIds.has("electrical") || damageIds.has("arcane") || damageIds.has("force")) {
      return containerBreachResult("arcaneFittingFailure", {
        summary: `${slime.name}'s ${damageTypeListText(damageTypes).toLowerCase()} force disrupted ${container.name}'s fittings.`
      });
    }

    if ((method === "climb" || hasAppendages) && openOrGapped) {
      return containerBreachResult("climbedOut", {
        summary: `${slime.name} climbed or gripped through an available opening in ${container.name}.`
      });
    }

    if ((method === "attack" || method === "press") && fragile && !type.geometry?.openTop && container.typeId !== "openTray") {
      return containerBreachResult("crackedContainer", {
        summary: `${slime.name} cracked ${container.name} open with direct pressure.`
      });
    }

    if ((method === "press" || method === "attack") && (type.geometry?.openTop || container.typeId === "openTray" || effectiveWeight > Math.max(4, type.maxWeightKg * 0.35))) {
      return containerBreachResult("overturnedSpill", {
        summary: `${slime.name} tipped or spilled ${container.name} enough to escape.`
      });
    }

    if ((method === "attack" || method === "press") && fragile) {
      return containerBreachResult("crackedContainer", {
        summary: `${slime.name} cracked ${container.name} open with direct pressure.`
      });
    }

    return containerBreachResult("forcedOpening", {
      summary: `${slime.name} forced an access point open on ${container.name}.`
    });
  }

  function applyContainerBreachResult(slime, container, record, result) {
    if (!slime || !container || !result) {
      return 0;
    }
    const containerId = container.id;
    const containerName = container.name;
    const roomId = container.roomId || slime.roomId || MAIN_ROOM_ID;
    const reusable = result.reusable !== false && result.breachState !== "breached";
    let finalReusable = reusable;
    const lastBreach = normalizeContainerLastBreach({
      type: result.type,
      label: result.label,
      slimeId: slime.id,
      slimeName: slime.name,
      method: record.method,
      at: state.clock,
      summary: result.summary,
      reusable
    });
    rememberCreatureExperience(slime, "containmentEscaped", reusable ? 12 : 18, result.label);
    releaseSlime(slime);
    const targetContainer = containerById(containerId) || container;
    targetContainer.breachState = reusable ? "compromised" : "breached";
    targetContainer.lastBreach = lastBreach;
    if (result.setOpen) {
      targetContainer.isOpen = true;
    }
    if (result.conditionDamage >= 100 || !reusable) {
      targetContainer.condition = 0;
    } else if (Number(result.conditionDamage) > 0) {
      adjustContainerCondition(targetContainer, -result.conditionDamage);
    }
    if (Number(result.containerContamination) > 0) {
      adjustContainerEnvironment(targetContainer, "contamination", result.containerContamination);
    }
    if (containerCondition(targetContainer) <= 0) {
      finalReusable = false;
      targetContainer.breachState = "breached";
      if (targetContainer.lastBreach) {
        targetContainer.lastBreach.reusable = false;
      }
    }
    if (Number(result.roomContamination) > 0) {
      adjustRoomAttribute(roomId, "contamination", result.roomContamination);
    }
    addEvent(`${slime.name} escaped ${containerName}: ${result.summary} ${finalReusable ? "The container is compromised but still physically usable." : "The container is breached and cannot hold specimens until future repair or replacement."}`);
    return 1;
  }

  function maybeResolveContainmentBreach(slime, container, record) {
    if (!record.active || record.pressureBand !== "critical") {
      return 0;
    }
    const weakEnough = containerCondition(container) <= 8;
    const progressedEnough = record.progress >= CONTAINMENT_TEST_PROGRESS_THRESHOLD;
    if (!weakEnough || !progressedEnough) {
      return 0;
    }
    const result = chooseContainerBreachResult(slime, container, record);
    return applyContainerBreachResult(slime, container, record, result);
  }

  function updateContainmentTesting(elapsed) {
    const seconds = Math.max(0, Number(elapsed) || 0);
    if (!seconds || !state?.started) {
      return 0;
    }
    let changes = 0;
    for (const slime of state.slimes || []) {
      if (!slime || slime.status !== "contained" || slime.status === "dead" || !slime.containerId) {
        continue;
      }
      const container = containerById(slime.containerId);
      if (!container || container.type === "synthesis") {
        slime.containmentTest = normalizeContainmentTestRecord({ active: false });
        continue;
      }
      const previous = normalizeContainmentTestRecord(slime.containmentTest);
      const next = evaluateContainmentTesting(slime, container);
      if (!next.active) {
        const beforeProgress = next.progress;
        next.progress = Math.max(0, previous.progress - CONTAINMENT_TEST_PROGRESS_DECAY_PER_HOUR * secondsToHours(seconds));
        if (Math.abs(next.progress - beforeProgress) >= 0.01) {
          changes += 1;
        }
        slime.containmentTest = next;
        continue;
      }

      slime.containmentTest = next;
      changes += applyContainmentTestEffects(slime, container, next, seconds);
      changes += maybeReportContainmentTesting(slime, container, next, previous);
      changes += maybeResolveContainmentBreach(slime, container, next);
    }
    return changes;
  }

  function adjustContainerEnvironment(container, attributeKey, amount) {
    if (!container) return false;
    container.environment = normalizeContainerEnvironment(container.environment);
    const attribute = container.environment?.[attributeKey];
    const delta = Number(amount);
    if (!attribute || !Number.isFinite(delta) || !delta) {
      return false;
    }
    const before = attribute.current;
    attribute.current = clamp(attribute.current + delta, 0, 100);
    return Math.abs(attribute.current - before) >= 0.01;
  }

  function activeContainmentRisk(slime, container) {
    if (!slime || !container || slime.status === "dead") {
      return {
        label: "Unknown",
        className: "container-band-unknown",
        score: 0,
        potential: 0,
        pressure: 0,
        potentialReasons: [],
        pressureReasons: ["No active containment risk can be assessed."],
        reasons: ["Pressure: No active containment risk can be assessed."]
      };
    }

    if (container.type === "synthesis") {
      return {
        label: "Suppressed by synthesis tube",
        className: "container-band-good",
        score: 5,
        potential: 5,
        pressure: 0,
        potentialReasons: ["The synthesis tube is built for temporary universal containment."],
        pressureReasons: ["Synthesis tube suppression keeps active containment risk low during temporary stabilization."],
        reasons: [
          "Potential: The synthesis tube is built for temporary universal containment.",
          "Pressure: Synthesis tube suppression keeps active containment risk low during temporary stabilization."
        ]
      };
    }

    const evaluated = evaluateGenome(slime.genome);
    const profile = physicalProfile(slime.genome, evaluated);
    const type = containerTypeDef(container.typeId);
    const condition = containerCondition(container);
    const revealed = slime.revealed || {};
    const stats = slime.stats || {};
    const physicalFit = physicalContainerFitPrediction(slime, container);
    const visibleCompatibility = containerCompatibilityAssessment(slime, container, { knownOnly: true });
    const actualCompatibility = containerCompatibilityAssessment(slime, container, { knownOnly: false });
    let potential = 0;
    let pressure = 0;
    const potentialReasons = [];
    const pressureReasons = [];
    const neutralReasons = [];
    const reasons = [];
    const addPotential = (points, text) => {
      potential += points;
      potentialReasons.push(text);
      reasons.push(`Potential: ${text}`);
    };
    const addPressure = (points, text) => {
      pressure += points;
      pressureReasons.push(text);
      reasons.push(`Pressure: ${text}`);
    };
    const addNeutral = (text) => {
      neutralReasons.push(text);
      reasons.push(text);
    };

    const physicalFitPotential = activeContainmentPotentialFromPhysicalFit(physicalFit);
    if (physicalFitPotential.points) {
      addPotential(physicalFitPotential.points, physicalFitPotential.text);
    }

    const compatibilityPotential = activeContainmentPotentialFromCompatibility(actualCompatibility, visibleCompatibility);
    if (compatibilityPotential.points) {
      addPotential(compatibilityPotential.points, compatibilityPotential.text);
    }

    const habitat = slimeHabitatFit(slime);
    if (habitat.band.id === "hostile") {
      addPressure(8, "hostile habitat is agitating the slime.");
    } else if (habitat.band.id === "poor" && slimeStat(slime, "stress").current >= 35) {
      addPressure(4, "poor habitat fit is making containment less comfortable.");
    }

    if (condition < 25) {
      addPotential(35, "container condition is critical.");
      addPressure(16, "damaged containment is actively straining.");
    } else if (condition < 50) {
      addPotential(22, "container condition is damaged.");
      addPressure(8, "wear is making containment less reliable.");
    } else if (condition < 75) {
      addPotential(8, "container condition is worn.");
    }

    if (isPitHoleContainer(container)) {
      const coverType = containerTypeDef(container.typeId).coverType || "none";
      const coverPotential = { none: 28, grate: 18, cap: 8 }[coverType] ?? 16;
      const coverPressure = { none: 10, grate: 6, cap: 2 }[coverType] ?? 5;
      addPotential(coverPotential, `${containerTypeDef(container.typeId).label} is a crude dirt-hole containment site.`);
      if (coverPressure) {
        addPressure(coverPressure, "pit-hole covers can be challenged by living creatures.");
      }
    }

    if (isContainerInTransit(container.id)) {
      addPressure(14, "the container is currently being hauled.");
    }

    if (containerAccessOpen(container)) {
      addPressure(18, "the container is open during direct handling.");
    }

    const localCorpses = containerCorpses(container.id);
    if (localCorpses.length) {
      addPotential(10 + localCorpses.length * 4, `${localCorpses.length} corpse${localCorpses.length === 1 ? "" : "s"} sharing this container.`);
      if (!localCorpses.some((corpse) => corpseFeedingRateForSlime(slime, corpse).rate > 0)) {
        addPressure(8, "nearby remains are fouling the container.");
      }
    }

    if (revealed.size && profile) {
      const massFraction = clamp(slimeStat(slime, "currentMass").current, 1, 100) / 100;
      const currentVolume = profile.volumeCm3 * massFraction;
      if (currentVolume > type.capacityCm3) {
        addPotential(30, "current body exceeds container capacity.");
      } else if (currentVolume > type.capacityCm3 * 0.85) {
        addPotential(14, "current body nearly fills the container.");
      } else if (profile.volumeCm3 > type.capacityCm3) {
        addPotential(18, "full-size body would outgrow the container.");
      }
    }

    if (revealed.consistency && profile) {
      const runny = ["watery", "runny gel", "syrupy", "loose jelly", "mucous", "foamy", "grainy slurry"];
      if (runny.includes(profile.consistency)) {
        if (type.gap >= 60) {
          addPotential(28, "runny body can exploit large gaps.");
        } else if (containerEffectiveSeal(container) < 50) {
          addPotential(18, "runny body strains the container seal.");
        }
      }
    }

    if (revealed.appendages && profile?.appendages && profile.appendages !== "none") {
      if (type.gap >= 60) {
        addPotential(12, "appendages can reach through large gaps.");
      }
      if (["spines", "hook claws"].includes(profile.appendages) && type.durability < 55) {
        addPotential(18, `${profile.appendages} can damage weaker materials.`);
      }
    }

    if (revealed.element && profile) {
      for (const hazard of elementContainerHazards(profile.element)) {
        const result = containerHazardCompatibility(container, hazard);
        if (result.score >= 16 && result.concern) {
          addPotential(result.score >= 28 ? 28 : 16, result.concern);
        }
      }
    }

    if (revealed.byproduct) {
      const byproduct = baseOutcomeLabel(evaluated.traits.byproduct);
      if (["acid droplets", "sterile solvent", "corrosive slime", "dissolved sludge", "smoke vapor", "numbing paste", "contaminated residue", "irritant film", "bitter sludge", "ether mist"].includes(byproduct)) {
        addPotential(14, `${byproduct} can turn disturbances into messes or exposure risks.`);
      }
      if (["adhesive gel", "black resin", "grease pearls", "coagulating wax", "warm tar", "dark mucus", "inky gel", "dissolved sludge", "plant mucus"].includes(byproduct) && !type.drainage) {
        addPotential(8, `${byproduct} can foul containers without drainage.`);
      }
    }

    const stress = Number(stats.stress?.current ?? slimeStat(slime, "stress").current) || 0;
    const nutrition = Number(stats.nutrition?.current ?? slimeStat(slime, "nutrition").current) || 0;
    const integrity = Number(stats.bodyIntegrity?.current ?? slimeStat(slime, "bodyIntegrity").current) || 0;
    const division = Number(stats.divisionPressure?.current ?? slimeStat(slime, "divisionPressure").current) || 0;

    if (stress >= 75) {
      addPressure(36, "high Stress is making the slime restless.");
    } else if (stress >= 55) {
      addPressure(22, "Stress is elevated.");
    } else if (stress >= 35) {
      addPressure(10, "Stress is rising.");
    }

    if (nutrition <= 15) {
      addPressure(26, "severe hunger may push the slime to test containment.");
    } else if (nutrition <= 30) {
      addPressure(14, "low nutrition increases containment pressure.");
    }

    if (integrity <= 30) {
      addPressure(14, "poor body integrity may make behavior less predictable.");
    }

    if (division >= 80) {
      addPressure(18, "high division pressure may soon overcrowd containment.");
    } else if (division >= 55) {
      addPressure(10, "division pressure is building.");
    }

    if (revealed.behavior) {
      const behavior = baseOutcomeLabel(evaluated.traits.behavior);
      const behaviorPressure = {
        "vibration hunting": 24,
        guarding: 18,
        swarming: 18,
        burrowing: 18,
        "still ambush": 14,
        "sound following": 10,
        "tool orbiting": 10,
        "heat seeking": 8,
        "light seeking": 8,
        hiding: 6,
        circling: 6
      };
      if (behaviorPressure[behavior]) {
        addPressure(behaviorPressure[behavior], `${behavior} behavior may test containment.`);
      }
      if (behavior === "cleaning") {
        addNeutral("Pressure: cleaning behavior may reduce some mess risk.");
      }
    }

    if (revealed.stability) {
      const risk = Number(evaluated.traits.stability.meta?.risk) || 5;
      if (risk >= 8) {
        addPressure(30, "stability profile is predatory or highly dangerous.");
      } else if (risk >= 7) {
        addPressure(22, "stability profile is volatile or erratic.");
      } else if (risk >= 6) {
        addPressure(14, "stability profile is somewhat fractious.");
      } else if (risk <= 2 && pressure > 0) {
        pressure = Math.max(0, pressure - 6);
        addNeutral("Pressure: stable temperament slightly reduces active pressure.");
      }
    }

    const testing = normalizeContainmentTestRecord(slime.containmentTest);
    if (testing.active) {
      const testingPoints = testing.pressureBand === "critical" ? 26
        : testing.pressureBand === "high" ? 18
          : testing.pressureBand === "moderate" ? 10
            : 4;
      addPressure(testingPoints, `${testing.methodLabel.toLowerCase()} is creating active escape pressure.`);
      if (testing.progress >= CONTAINMENT_TEST_PROGRESS_THRESHOLD * 0.75) {
        addPressure(8, "repeated containment testing has built up warning signs.");
      }
    }

    if (potential === 0 && pressure === 0) {
      addNeutral("No active containment concerns from discovered traits or current condition.");
    }

    const score = Math.round(potential + pressure);
    const label = score >= 110 ? "Failing"
      : score >= 75 ? "Dangerous"
        : score >= 45 ? "Strained"
          : score >= 20 ? "Watch"
            : "Stable";
    const className = score >= 110 ? "container-band-unsuitable"
      : score >= 75 ? "container-band-poor"
        : score >= 45 ? "container-band-questionable"
          : score >= 20 ? "container-band-questionable"
            : "container-band-good";

    return {
      label,
      className,
      score,
      potential: Math.round(potential),
      pressure: Math.round(pressure),
      potentialReasons: potentialReasons.slice(0, 4),
      pressureReasons: pressureReasons.slice(0, 4),
      reasons: reasons.slice(0, 6)
    };
  }


  function activeContainmentRiskBands() {
    return ["Stable", "Watch", "Strained", "Dangerous", "Failing"];
  }

  function activeContainmentRiskUnknownFactors(slime) {
    const unknownFactors = [];
    if (!slime) return ["creature state"];
    const revealed = slime.revealed || {};
    if (!revealed.size) unknownFactors.push("adult size");
    if (!revealed.consistency) unknownFactors.push("body consistency");
    if (!revealed.appendages) unknownFactors.push("appendages");
    if (!revealed.element) unknownFactors.push("elemental hazards");
    if (!revealed.byproduct) unknownFactors.push("byproduct");
    if (!revealed.behavior) unknownFactors.push("behavior");
    if (!revealed.stability) unknownFactors.push("stability");
    return unknownFactors;
  }

  function activeContainmentRiskKnownFactors(risk, container) {
    const factors = [];
    const potentialReasons = Array.isArray(risk?.potentialReasons) ? risk.potentialReasons : [];
    const pressureReasons = Array.isArray(risk?.pressureReasons) ? risk.pressureReasons : [];
    factors.push(...potentialReasons.slice(0, 3));
    factors.push(...pressureReasons.slice(0, 3));
    if (container) {
      factors.push(`container condition is ${containerConditionLabel(container)}`);
      if (containerAccessOpen(container)) factors.push("container is open");
      if (isContainerInTransit(container.id)) factors.push("container is in transit");
    }
    return [...new Set(factors)].filter(Boolean).slice(0, 6);
  }

  function activeContainmentRiskPrediction(risk, slime, container) {
    if (!risk) {
      const confidence = predictionConfidenceFromContext({
        unknownFactors: ["active containment state"],
        skillIds: ["analysis", "creatureLore", "creatureHandling"]
      });
      return {
        range: { low: "Stable", high: "Failing" },
        confidence,
        knownFactors: [],
        unknownFactors: ["active containment state"],
        concerns: []
      };
    }
    if (risk.label === "Suppressed by synthesis tube") {
      const confidence = predictionConfidenceFromContext({
        knownFactors: ["synthesis tube suppression", "temporary universal containment"],
        clearEvidence: 60,
        skillIds: ["analysis", "creatureLore", "creatureHandling"]
      });
      return {
        range: { low: "Stable", high: "Stable" },
        confidence: { ...confidence, label: "Strong" },
        knownFactors: ["synthesis tube suppression", "temporary universal containment"],
        unknownFactors: [],
        concerns: []
      };
    }
    const unknownFactors = activeContainmentRiskUnknownFactors(slime);
    const knownFactors = activeContainmentRiskKnownFactors(risk, container);
    const concerns = [];
    if (["Strained", "Dangerous", "Failing"].includes(risk.label)) {
      concerns.push(`current active risk assessment is ${risk.label.toLowerCase()}`);
    }
    const clearEvidence = Math.max(0, (knownFactors.length * 12) + (concerns.length * 8));
    const confidence = predictionConfidenceFromContext({
      unknownFactors,
      knownFactors,
      concerns,
      clearEvidence,
      skillIds: ["analysis", "creatureLore", "creatureHandling"]
    });
    return {
      range: predictionRangeFromBand(activeContainmentRiskBands(), risk.label, confidence.label, { unknownLow: "Stable", unknownHigh: "Failing" }),
      confidence,
      knownFactors,
      unknownFactors,
      concerns
    };
  }

  function activeContainmentRiskRangeTooltip(prediction, risk) {
    const lines = [
      `Active containment risk range: ${predictionRangeText(prediction?.range)}.`,
      "This is an assessment of possible active containment trouble, not a guaranteed escape outcome."
    ];
    if (prediction?.knownFactors?.length) {
      lines.push(`Known influences narrowing or shifting the range: ${prediction.knownFactors.join(" · ")}.`);
    }
    if (prediction?.concerns?.length) {
      lines.push(`Concerns raising or widening the range: ${prediction.concerns.join(" · ")}.`);
    }
    if (prediction?.unknownFactors?.length) {
      lines.push(`Unknown factors widening the range: ${prediction.unknownFactors.join(", ")}.`);
    }
    if (Number.isFinite(risk?.potential) || Number.isFinite(risk?.pressure)) {
      lines.push("Internal Potential and Pressure scores still drive incidents, but exact scores are not shown as precise predictions.");
    }
    return lines.join("\n");
  }

  function activeContainmentRiskPredictionEl(risk, slime, container) {
    const prediction = activeContainmentRiskPrediction(risk, slime, container);
    const details = document.createElement("div");
    details.className = "container-risk-details";
    details.dataset.activeRiskPrediction = slime?.id || container?.id || "unknown";

    const rangeSpan = document.createElement("span");
    rangeSpan.dataset.activeRiskRange = slime?.id || container?.id || "unknown";
    rangeSpan.textContent = `Active containment risk: ${predictionRangeText(prediction.range)}`;
    rangeSpan.title = activeContainmentRiskRangeTooltip(prediction, risk);

    const confidenceSpan = document.createElement("span");
    confidenceSpan.dataset.activeRiskConfidence = slime?.id || container?.id || "unknown";
    confidenceSpan.textContent = `Confidence: ${prediction.confidence.label}`;
    confidenceSpan.title = predictionConfidenceTooltip(prediction.confidence);

    details.title = `${rangeSpan.title}\n${confidenceSpan.title}`;
    details.append(rangeSpan, document.createTextNode(" | "), confidenceSpan);
    return details;
  }

  function activeContainmentRiskDetailsEl(risk) {
    const details = document.createElement("div");
    details.className = "container-risk-details";

    const addGroup = (label, value, reasons, emptyMessage) => {
      const group = document.createElement("div");
      group.className = "container-risk-group";
      group.append(textEl("strong", `${label}: `), chip(String(value)));

      const displayedReasons = reasons?.length ? reasons : [emptyMessage];
      group.append(document.createTextNode(" — "));
      displayedReasons.forEach((reason, index) => {
        if (index > 0) {
          group.append(document.createTextNode(" · "));
        }
        group.append(chip(reason));
      });

      details.append(group);
    };

    addGroup("Potential", risk?.potential ?? 0, risk?.potentialReasons || [], "no major physical mismatch identified");
    addGroup("Pressure", risk?.pressure ?? 0, risk?.pressureReasons || [], "no current active pressure identified");

    return details;
  }

  function containerCardEl(container) {
    const card = document.createElement("div");
    card.className = `container-card ${container.type}`;
    card.dataset.containerCard = container.id;
    card.classList.toggle("selected-map-target", selectedTargetMatchesCard("container", container.id));
    card.addEventListener("click", (event) => {
      if (event.target.closest("button, input, select, textarea")) {
        return;
      }
      setSelection({ kind: "container", id: container.id, source: "panel" });
      persist();
      render();
    });
    const occupants = containerOccupants(container.id);
    const corpses = containerCorpses(container.id);
    const title = document.createElement("div");
    title.className = "container-title";
    const typeLabel = container.type === "synthesis" ? "Synthesis Tube" : containerTypeLabel(container.typeId);
    title.append(
      textEl("strong", container.name),
      textEl("span", container.type === "synthesis" ? "temporary perfect containment" : `${typeLabel}; Location: ${roomName(container.roomId)}`)
    );

    const meta = document.createElement("div");
    meta.className = "container-meta";
    if (container.type === "synthesis") {
      meta.append(chip("universal temporary containment"), chip(`condition ${containerConditionLabel(container)}`), chip(`interior ${containerGeometrySummary(container)}`));
    } else {
      const type = containerTypeDef(container.typeId);
      meta.append(chip(type.label), chip(`condition ${containerConditionLabel(container)}`), chip(`capacity ${formatVolume(type.capacityCm3)}`), chip(`load ${formatWeight(containerEffectiveWeightLimit(container))}`), chip(`interior ${containerGeometrySummary(container)}`));
      const wards = containerWardLabels(container.wardIds);
      if (wards.length) {
        for (const ward of wards) {
          meta.append(chip(ward));
        }
      } else {
        meta.append(chip("no wards"));
      }
    }
    if (!isSynthesisTubeContainer(container)) {
      const footprint = containerFootprintDimensions(container);
      const cell = objectMapCell(container);
      const cellText = cell ? `cell ${cell.x},${cell.y}` : "cell unplaced";
      meta.append(chip(`${roomRoleLabel(container.roomId)} room`), chip(`access ${containerAccessLabel(container)}`), chip(`footprint ${footprint.width}x${footprint.height} m; ${cellText}`));
      const breachState = containerBreachState(container);
      if (breachState !== "intact") {
        const breachChip = chip(`breach ${containerBreachStateLabel(container)}`);
        breachChip.dataset.containerBreach = container.id;
        breachChip.title = containerBreachSummary(container) || `${container.name} is ${breachState}.`;
        meta.append(breachChip);
      }
      if (isPitHoleContainer(container)) {
        meta.append(chip(`pit corpses ${pitHoleCorpseCount(container)}/${pitHoleCorpseCapacity(container)}`));
        meta.append(chip(`pit Waste ${formatNumber(containerWasteAmount(container))}`));
      }
      const haulTask = containerHaulTask(container.id);
      if (haulTask) {
        meta.append(chip(`hauling to ${roomName(haulTask.data?.toRoomId)}`));
      }
      const roomControl = document.createElement("div");
      roomControl.className = "container-room-control";
      roomControl.append(textEl("span", "Queue move/stage to: "));
      const select = document.createElement("select");
      select.className = "container-room-select";
      select.dataset.containerRoomSelect = container.id;
      select.title = "Changing this queues a container haul task. The contained specimen and any contained remains move with the container when hauling completes.";
      for (const room of state.rooms) {
        const option = document.createElement("option");
        option.value = room.id;
        option.textContent = room.name;
        select.append(option);
      }
      select.value = roomById(container.roomId)?.id || MAIN_ROOM_ID;
      const selectorBlockedReason = haulTask
        ? `${container.name} is in transit to ${roomName(haulTask.data?.toRoomId)}.`
        : isPitHoleContainer(container)
          ? "Pit holes are built into the Pits and cannot be hauled."
          : physicalStateRiskBlockReason(`hauling ${container.name}`);
      select.disabled = Boolean(selectorBlockedReason);
      select.title = selectorBlockedReason || "Changing this queues a container haul task. The contained specimen and any contained remains move with the container when hauling completes.";
      select.addEventListener("change", () => {
        const destination = select.value;
        select.value = roomById(container.roomId)?.id || MAIN_ROOM_ID;
        moveContainerToRoom(container.id, destination);
      });
      roomControl.append(select);
      meta.append(roomControl);
    }

     // Add interior environment display
    if (container.environment) {
      const interior = document.createElement("div");
      interior.className = "container-interior";
      
      // Show container environment summary
      const envSummary = containerEnvironmentSummary(container);
      if (envSummary) {
        const summaryEl = document.createElement("div");
        summaryEl.className = "container-environment-summary";
        summaryEl.textContent = `Interior: ${envSummary}`;
        interior.append(summaryEl);
        
        // Add warnings if relevant
        const warnings = containerEnvironmentWarnings(container);
        if (warnings.length > 0) {
          const warningList = document.createElement("div");
          warningList.className = "container-environment-warnings";
          for (const [index, warning] of warnings.entries()) {
            if (index > 0) {
              warningList.append(document.createTextNode(" · "));
            }
            warningList.append(chip(warning));
          }
          interior.append(warningList);
        }
      }
      
      card.append(interior);
    }

    if (!isSynthesisTubeContainer(container)) {
      const resistanceEntries = damageResistanceEntriesForContainer(container);
      const resistance = document.createElement("div");
      resistance.className = "container-damage-resistance";
      resistance.dataset.containerDamageResistance = container.id;
      resistance.textContent = `Material resistance: ${damageResistanceSummary(resistanceEntries)}`;
      resistance.title = damageResistanceTooltip(resistanceEntries, `${container.name} material resistance`);
      card.append(resistance);

      const handling = document.createElement("div");
      handling.className = "container-handling-risk";
      const handlingAction = containerAccessOpen(container) ? "close" : "open";
      const handlingRisk = containerHandlingRisk(container, handlingAction, currentHandlingMethodId());
      const handlingPrediction = directHandlingRiskPrediction(handlingRisk);
      handling.textContent = handlingRiskSummary(container);
      handling.title = `${directHandlingRiskTooltip(handlingPrediction, handlingRisk)}
${handlingMethodInventoryTitle(handlingRisk.method.id)}`;
      handling.dataset.handlingRisk = predictionRangeText(handlingPrediction.riskRange);
      handling.dataset.handlingHarm = predictionRangeText(handlingPrediction.harmRange);
      handling.dataset.handlingConfidence = handlingPrediction.confidence.label;
      handling.dataset.handlingToolPreview = handlingMethodToolPreviewSummary(handlingRisk.method.id);
      handling.dataset.handlingInventory = handlingMethodInventorySummary(handlingRisk.method.id);
      handling.dataset.handlingProtocol = handlingMethodProtocolSummary(handlingRisk.method.id);
      handling.dataset.handlingRequirement = handlingMethodRequirementSummary(handlingRisk.method.id);
      card.append(handling);
    }

    if (container.type !== "synthesis" && container.lastBreach) {
      const breach = document.createElement("div");
      breach.className = "container-breach-summary";
      breach.dataset.containerBreachSummary = container.id;
      breach.textContent = `Last breach: ${containerBreachSummary(container)}`;
      card.append(breach);
    }

    const occupantList = document.createElement("div");
    occupantList.className = "container-occupants";
    if (!occupants.length && !corpses.length) {
      occupantList.append(emptyText(container.type === "synthesis" ? "Tube empty." : "Open."));
    } else {
      for (const corpse of corpses) {
        const row = document.createElement("div");
        row.className = "container-occupant-row corpse-row";
        row.append(corpseNameLink(corpse), textEl("span", `${corpseStateLabel(corpse)} corpse`), textEl("span", corpseDecayText(corpse)));
        occupantList.append(row);
      }
      for (const slime of occupants) {
        const row = document.createElement("div");
        row.className = "container-occupant-row";
        const physicalFit = physicalContainerFitPrediction(slime, container);
        const compatibility = containerCompatibilityAssessment(slime, container, { knownOnly: true });
        const risk = activeContainmentRisk(slime, container);
        const statusLabel = textEl("span", slime.mature ? slime.status : "immature");
        const fitLabel = textEl("span", `physical fit ${predictionRangeText(physicalFit.range)}`);
        fitLabel.className = physicalFit.className;
        fitLabel.title = physicalContainerFitTooltip(physicalFit);
        fitLabel.dataset.physicalFitRange = predictionRangeText(physicalFit.range);
        const compatibilityLabel = textEl("span", `compatibility ${predictionRangeText(compatibility.range)}`);
        compatibilityLabel.className = compatibility.className;
        compatibilityLabel.title = containerCompatibilityTooltip(compatibility);
        compatibilityLabel.dataset.containerCompatibilityRange = predictionRangeText(compatibility.range);
        const riskPrediction = activeContainmentRiskPrediction(risk, slime, container);
        const riskLabel = textEl("span", `active risk ${predictionRangeText(riskPrediction.range)}`);
        riskLabel.className = risk.className;
        riskLabel.title = activeContainmentRiskRangeTooltip(riskPrediction, risk);
        const testing = containmentTestRecordForSlime(slime);
        const testingLabel = textEl("span", testing.active ? `testing ${testing.methodLabel.toLowerCase()}` : `escape ${testing.pressureLabel.toLowerCase()}`);
        testingLabel.className = containmentTestPressureClassName(testing);
        testingLabel.title = [
          `Escape pressure: ${testing.pressureLabel}.`,
          testing.active ? `Observed behavior: ${testing.activity}.` : "No active testing observed.",
          testing.reasons?.length ? `Factors: ${testing.reasons.join(" | ")}.` : ""
        ].filter(Boolean).join("\n");
        testingLabel.dataset.containerTesting = slime.id;
        row.append(slimeNameLink(slime), statusLabel, fitLabel, compatibilityLabel, riskLabel, testingLabel);
        const warnings = document.createElement("div");
        warnings.className = "container-warning-list";
        warnings.append(physicalContainerFitPredictionEl(slime, container));
        warnings.append(containerCompatibilityPredictionEl(slime, container));
        warnings.append(activeContainmentRiskPredictionEl(risk, slime, container));
        occupantList.append(row, warnings);
      }
    }

    card.append(title, meta, occupantList);
    const residuePanel = feedingResiduePanelEl({ type: "container", containerId: container.id }, "Interior feeding residue");
    if (residuePanel) {
      card.append(residuePanel);
    }

    if (container.type !== "synthesis") {
      const actions = document.createElement("div");
      actions.className = "container-actions";
      const action = containerAccessOpen(container) ? "close" : "open";
      const button = document.createElement("button");
      button.type = "button";
      const interactionBaseCost = action === "close" ? CONTAINER_INTERACTION_CLOSE_STAMINA : CONTAINER_INTERACTION_OPEN_STAMINA;
      setButtonStaminaLabel(button, action === "close" ? "Close Container" : "Open Container", interactionBaseCost, ["creatureHandling"]);
      if (action === "open") {
        button.dataset.openContainerId = container.id;
      } else {
        button.dataset.closeContainerId = container.id;
      }
      const physicalRiskLabel = `${action === "close" ? "closing" : "opening"} ${container.name}`;
      const reason = containerInteractionBlockReason(container, action)
        || physicalStateRiskBlockReason(physicalRiskLabel)
        || handlingMethodMissingToolReason(currentHandlingMethodId())
        || staminaBlockReason(adjustedStaminaCost(interactionBaseCost, ["creatureHandling"]));
      setActionButtonState(button, Boolean(reason), reason);
      const physicalRiskTitle = physicalStateRiskTitle(physicalRiskLabel);
      const directHandlingTitle = handlingRiskTitle(container, action, currentHandlingMethodId());
      button.title = reason || `${handlingMethodActionTitle(currentHandlingMethodId())}\n${physicalRiskTitle ? `${physicalRiskTitle}\n` : ""}${directHandlingTitle}\n${adjustedStaminaCostBreakdown(interactionBaseCost, ["creatureHandling"]).title}`;
      button.addEventListener("click", () => startContainerInteraction(container.id, action));
      actions.append(button);

      if (!isPitHoleContainer(container) && containerCorpses(container.id).length) {
        for (const remainsAction of ["dumpRemains", "scrapeRemains"]) {
          const remainsBtn = document.createElement("button");
          remainsBtn.type = "button";
          const baseCost = remainsAction === "scrapeRemains" ? REMAINS_SCRAPE_STAMINA : REMAINS_DUMP_STAMINA;
          setButtonStaminaLabel(remainsBtn, remainsHandlingActionLabel(remainsAction), baseCost, ["creatureHandling"]);
          remainsBtn.dataset.remainsAction = remainsAction;
          remainsBtn.dataset.remainsContainerId = container.id;
          const remainsRiskLabel = `${remainsHandlingActionLabel(remainsAction).toLowerCase()} from ${container.name}`;
          const remainsReason = remainsHandlingBlockReason(container, remainsAction)
            || physicalStateRiskBlockReason(remainsRiskLabel)
            || handlingMethodMissingToolReason(currentHandlingMethodId())
            || staminaBlockReason(adjustedStaminaCost(baseCost, ["creatureHandling"]));
          setActionButtonState(remainsBtn, Boolean(remainsReason), remainsReason);
          const remainsRiskTitle = physicalStateRiskTitle(remainsRiskLabel);
          const directRemainsHandlingTitle = handlingRiskTitle(container, remainsAction, currentHandlingMethodId());
          remainsBtn.title = remainsReason || `${handlingMethodActionTitle(currentHandlingMethodId())}\n${remainsRiskTitle ? `${remainsRiskTitle}\n` : ""}${directRemainsHandlingTitle}\n${adjustedStaminaCostBreakdown(baseCost, ["creatureHandling"]).title}`;
          remainsBtn.addEventListener("click", () => startRemainsHandling(container.id, remainsAction));
          actions.append(remainsBtn);
        }
      }

      if (containerOccupants(container.id).length) {
        const transferWrap = document.createElement("div");
        transferWrap.className = "container-live-transfer";
        const transferSelect = document.createElement("select");
        transferSelect.dataset.liveTransferSelect = container.id;
        const candidates = liveTransferDestinationCandidates(container);
        if (candidates.length) {
          for (const candidate of candidates) {
            const option = document.createElement("option");
            option.value = candidate.id;
            option.textContent = `${candidate.name} (${roomName(candidate.roomId)})`;
            transferSelect.append(option);
          }
        } else {
          const option = document.createElement("option");
          option.value = "";
          option.textContent = "No open same-room destination";
          transferSelect.append(option);
        }

        const transferBtn = document.createElement("button");
        transferBtn.type = "button";
        setButtonStaminaLabel(transferBtn, liveTransferActionLabel(), LIVE_TRANSFER_STAMINA, ["creatureHandling"]);
        transferBtn.dataset.liveTransferContainerId = container.id;
        const selectedDestinationId = transferSelect.value;
        const transferRiskLabel = "transferring a living slime";
        const transferReason = liveTransferBlockReason(container, selectedDestinationId)
          || physicalStateRiskBlockReason(transferRiskLabel)
          || handlingMethodMissingToolReason(currentHandlingMethodId())
          || staminaBlockReason(adjustedStaminaCost(LIVE_TRANSFER_STAMINA, ["creatureHandling"]));
        setActionButtonState(transferBtn, Boolean(transferReason), transferReason);
        const transferRiskTitle = physicalStateRiskTitle(transferRiskLabel);
        const directTransferHandlingTitle = handlingRiskTitle(container, "transferLivingSlime", currentHandlingMethodId());
        transferBtn.title = transferReason || `${handlingMethodActionTitle(currentHandlingMethodId())}\n${transferRiskTitle ? `${transferRiskTitle}\n` : ""}${directTransferHandlingTitle}\n${adjustedStaminaCostBreakdown(LIVE_TRANSFER_STAMINA, ["creatureHandling"]).title}`;
        transferBtn.addEventListener("click", () => startLiveSlimeTransfer(container.id, transferSelect.value));
        transferWrap.append(textEl("span", "Destination: "), transferSelect, transferBtn);
        actions.append(transferWrap);
      }

      card.append(actions);
    }

    if (container.type === "synthesis" && occupants.length) {
      const actions = document.createElement("div");
      actions.className = "container-actions";
      const moveBtn = document.createElement("button");
      moveBtn.type = "button";
      const cost = adjustedStaminaCost(HANDLING_STAMINA, ["creatureHandling"]);
      setButtonStaminaLabel(moveBtn, "Move to Open Container", HANDLING_STAMINA, ["creatureHandling"]);
      const tubeMoveRiskLabel = `moving ${occupants[0].name} from the synthesis tube`;
      const reason = !firstOpenPermanentContainer()
        ? "No open permanent container is available."
        : physicalStateRiskBlockReason(tubeMoveRiskLabel)
          || handlingMethodMissingToolReason(currentHandlingMethodId())
          || staminaBlockReason(cost);
      setActionButtonState(moveBtn, Boolean(reason), reason);
      const tubeMoveRiskTitle = physicalStateRiskTitle(tubeMoveRiskLabel);
      moveBtn.title = reason || `${tubeMoveRiskTitle ? `${tubeMoveRiskTitle}\n` : ""}${adjustedStaminaCostBreakdown(HANDLING_STAMINA, ["creatureHandling"]).title}`;
      moveBtn.addEventListener("click", () => moveTubeOccupantToOpenContainer(occupants[0].id));
      actions.append(moveBtn);
      card.append(actions);
    }

    return card;
  }

  function moveTubeOccupantToOpenContainer(slimeId) {
    const slime = findSlime(slimeId);
    if (!slime || !isInSynthesisTube(slime)) {
      addEvent("No synthesis tube occupant is ready to move.");
      persist();
      render();
      return;
    }
    const toolReason = handlingMethodMissingToolReason(currentHandlingMethodId());
    if (toolReason) {
      addEvent(toolReason);
      persist();
      render();
      return false;
    }
    if (!confirmPhysicalStateRiskIfNeeded(`moving ${slime.name} from the synthesis tube`)) {
      return false;
    }
    const cost = adjustedStaminaCost(HANDLING_STAMINA, ["creatureHandling"]);
    if (!spendStamina(cost)) {
      addEvent(`Not enough stamina. ${cost} required.`);
      persist();
      render();
      return;
    }
    const container = moveSlimeToOpenPermanentContainer(slime);
    if (!container) {
      restoreStamina(cost);
      addEvent("No open permanent container is available.");
      persist();
      render();
      return;
    }
    applyHandlingToolWear(currentHandlingMethodId(), null, "transferLivingSlime", { score: 12 }, {
      slimes: [slime],
      reason: `moving ${slime.name} from the synthesis tube`
    });
    awardXp("creatureHandling", 5, "Creature handling");
    addEvent(`${slime.name} assigned to ${container.name}.`);
    persist();
    render();
  }

  function renderJobs() {
    dom.jobList.textContent = "";
    const living = state.slimes.filter((slime) => slime.status !== "dead");
    const active = living.filter((slime) => {
      normalizeSlimeJob(slime);
      return slime.job !== "idle";
    }).length;
    const eligibleCorpses = (state.corpses || []).filter(isCorpseProcessingTarget).length;
    const protectedCorpses = policyProtectedCorpseCount();
    const wasteUnits = resourceAmount("waste");
    const pitWasteUnits = containerWasteTotal();
    const residueUnits = feedingResidueTotal();
    dom.jobSummary.textContent = living.length
      ? `${active} active jobs; ${eligibleCorpses} eligible corpse${eligibleCorpses === 1 ? "" : "s"}${protectedCorpses ? `; ${protectedCorpses} protected by policy` : ""}; ${formatNumber(wasteUnits)} stockpiled Waste${pitWasteUnits ? `; ${formatNumber(pitWasteUnits)} pit Waste` : ""}${residueUnits ? `; ${formatNumber(residueUnits)} local residue` : ""}`
      : "No living creatures available for jobs.";

    if (!living.length) {
      dom.jobList.append(emptyText("No living workers."));
      return;
    }

    for (const slime of living) {
      normalizeSlimeJob(slime);
      const row = document.createElement("div");
      row.className = "job-row";

      const details = document.createElement("div");
      const header = document.createElement("div");
      header.className = "job-row-header";
      header.append(slimeNameLink(slime, "entity-link-strong"), textEl("span", slime.mature ? slimeStateLabel(slime) : "immature"));

      const meta = document.createElement("div");
      meta.className = "job-meta";
      meta.append(chip(creatureJobLabel(slime.job)));
      if (slime.job === "corpse") {
        const suitability = observedCorpseProcessingSuitability(slime);
        meta.append(chip(suitability.known ? `estimated ${suitability.band.toLowerCase()}` : "suitability unknown"));
        const target = findCorpse(slime.jobTargetCorpseId);
        meta.append(chip(`site ${pitJobSiteLabel(slime)}`));
        meta.append(isCorpseProcessingTargetForSlime(slime, target) ? targetCorpseChip(target) : chip(corpseProcessingUnavailableText(slime)));
        if (isCorpseProcessingTargetForSlime(slime, target)) {
          const remainingChip = chip(jobRemainingText(slime));
          remainingChip.dataset.jobRemaining = slime.id;
          meta.append(remainingChip);
        }
      } else if (slime.job === "disposal") {
        const suitability = observedWasteDisposalSuitability(slime);
        const pit = slimePitJobSite(slime);
        const localWaste = containerWasteAmount(pit);
        meta.append(chip(suitability.known ? `${suitability.band.toLowerCase()} fit` : "suitability unknown"));
        meta.append(chip(`site ${pitJobSiteLabel(slime)}`));
        meta.append(chip(localWaste > 0 ? `${formatNumber(localWaste)} Waste in ${pitJobSiteLabel(slime)}` : `no Waste in ${pitJobSiteLabel(slime)}`));
        if (localWaste > 0) {
          const remainingChip = chip(jobRemainingText(slime));
          remainingChip.dataset.jobRemaining = slime.id;
          meta.append(remainingChip);
        }
      } else if (slime.job === "cleanup") {
        const suitability = observedCleanupUseSuitability(slime);
        meta.append(chip(`cleanup ${predictionRangeText(suitability.range).toLowerCase()}`));
        meta.append(chip(`${suitability.confidence.label.toLowerCase()} confidence`));
        meta.append(chip(slimeIsUncontained(slime) ? "following instincts" : "must be released to roam"));
      } else {
        const pitsReason = slimeJobSpecificBlockReason(slime, "corpse");
        meta.append(chip(isInSynthesisTube(slime) ? "in synthesis tube" : slimeJobRoomBlockReason(slime) ? "not ready" : pitsReason ? "move to a pit for pit jobs" : canWorkJob(slime) ? "available" : "not ready"));
      }
      details.append(header, meta);

      if (slime.job === "cleanup") {
        details.append(cleanupUseSuitabilityPanel(slime));
      }

      if (shouldShowJobProgress(slime)) {
        const bar = document.createElement("div");
        bar.className = "job-progress";
        const fill = document.createElement("div");
        fill.className = "job-progress-fill";
        fill.dataset.jobFill = slime.id;
        fill.style.width = `${jobProgressPercent(slime)}%`;
        bar.append(fill);
        details.append(bar);
      }

      const select = document.createElement("select");
      select.className = "job-select";
      select.dataset.jobSlimeId = slime.id;
      const jobReason = jobAssignmentBlockReason(slime);
      select.disabled = Boolean(jobReason);
      select.title = jobReason;
      for (const job of CREATURE_JOBS) {
        const option = document.createElement("option");
        option.value = job.id;
        option.textContent = job.label;
        const optionReason = slimeJobSpecificBlockReason(slime, job.id);
        option.disabled = Boolean(optionReason);
        option.title = optionReason || (job.id === "cleanup" ? cleanupUseOptionTitle(slime) : "");
        select.append(option);
      }
      select.value = slime.job;
      select.addEventListener("change", () => {
        assignCreatureJob(slime.id, select.value);
      });

      row.append(details, select);
      dom.jobList.append(row);
    }
  }

  function startNecropsy(corpse) {
    const duration = necropsyDuration(corpse);
    startStaminaTask({
      type: "necropsy",
      label: `Necropsy ${corpse.name}`,
      baseDuration: duration,
      skillId: "medicine",
      baseXp: 35,
      baseCost: BASE_ACTION_STAMINA,
      data: { corpseId: corpse.id }
    });
  }

  function startLivingHarvest(slime, procedureId) {
    const procedure = SPECIMEN_HARVEST_PROCEDURE_BY_ID[procedureId];
    const cost = adjustedStaminaCost(procedure?.staminaCost || BASE_ACTION_STAMINA, ["medicine", "creatureHandling"]);
    const reason = livingHarvestBlockReason(slime, procedure, cost);
    if (reason) {
      addEvent(reason);
      persist();
      render();
      return false;
    }
    return startStaminaTask({
      type: "harvestSlime",
      label: `${procedure.livingLabel} ${slime.name}`,
      baseDuration: procedure.livingDuration,
      skillId: "medicine",
      baseXp: procedure.xp,
      baseCost: procedure.staminaCost,
      data: { slimeId: slime.id, procedureId: procedure.id }
    });
  }

  function startCorpseHarvest(corpse, procedureId) {
    const procedure = SPECIMEN_HARVEST_PROCEDURE_BY_ID[procedureId];
    const cost = adjustedStaminaCost(procedure?.staminaCost || BASE_ACTION_STAMINA, ["medicine", "creatureHandling"]);
    const reason = corpseHarvestBlockReason(corpse, procedure, cost);
    if (reason) {
      addEvent(reason);
      persist();
      render();
      return false;
    }
    return startStaminaTask({
      type: "harvestCorpse",
      label: `${procedure.corpseLabel} ${corpse.name}`,
      baseDuration: corpseHarvestDuration(corpse, procedure),
      skillId: "medicine",
      baseXp: procedure.xp,
      baseCost: procedure.staminaCost,
      data: { corpseId: corpse.id, procedureId: procedure.id }
    });
  }

  function refreshNecropsyButton(button, corpse) {
    const cost = adjustedStaminaCost(BASE_ACTION_STAMINA, ["medicine", "creatureHandling"]);
    const duration = adjustedDuration(necropsyDuration(corpse), "medicine");
    setButtonStaminaLabel(button, "Necropsy", BASE_ACTION_STAMINA, ["medicine", "creatureHandling"], { duration: formatDuration(duration) });
    const reason = necropsyBlockReason(corpse, cost);
    setActionButtonState(button, Boolean(reason), reason);
  }

  function necropsyBlockReason(corpse, cost) {
    if (!corpse || corpse.ruined) {
      return "Corpse is already ruined.";
    }
    if (hasPendingNecropsy(corpse.id)) {
      return "Necropsy already pending.";
    }
    if (hasPendingCorpseHarvest(corpse.id)) {
      return "Harvest already pending for this corpse.";
    }
    return staminaBlockReason(cost);
  }

  function refreshLivingHarvestButton(button, slime, procedure) {
    const cost = adjustedStaminaCost(procedure.staminaCost, ["medicine", "creatureHandling"]);
    const duration = adjustedDuration(procedure.livingDuration, "medicine");
    setButtonStaminaLabel(button, procedure.livingLabel, procedure.staminaCost, ["medicine", "creatureHandling"], { duration: formatDuration(duration) });
    const reason = livingHarvestBlockReason(slime, procedure, cost);
    setActionButtonState(button, Boolean(reason), reason);
    if (!reason) {
      button.title = livingHarvestProcedureTitle(slime, procedure);
    }
  }

  function refreshCorpseHarvestButton(button, corpse, procedure) {
    const cost = adjustedStaminaCost(procedure.staminaCost, ["medicine", "creatureHandling"]);
    const duration = adjustedDuration(corpseHarvestDuration(corpse, procedure), "medicine");
    setButtonStaminaLabel(button, procedure.corpseLabel, procedure.staminaCost, ["medicine", "creatureHandling"], { duration: formatDuration(duration) });
    const reason = corpseHarvestBlockReason(corpse, procedure, cost);
    setActionButtonState(button, Boolean(reason), reason);
    if (!reason) {
      button.title = corpseHarvestProcedureTitle(corpse, procedure);
    }
  }

  function livingHarvestBlockReason(slime, procedure, cost) {
    if (!slime || !procedure) {
      return "No living specimen selected.";
    }
    if (slime.status === "dead") {
      return "Specimen is dead.";
    }
    if (hasPendingLivingHarvest(slime.id)) {
      return "Harvest already pending for this specimen.";
    }
    if (isInSynthesisTube(slime)) {
      return "Move specimen out of the synthesis tube before harvesting.";
    }
    if (slime.containerId && isContainerInTransit(slime.containerId)) {
      return "Container is already being hauled.";
    }
    return physicalStateRiskBlockReason(`harvesting ${slime.name}`) || staminaBlockReason(cost);
  }

  function corpseHarvestBlockReason(corpse, procedure, cost) {
    if (!corpse || !procedure) {
      return "No corpse selected.";
    }
    if (corpse.ruined || corpse.harvestBlocked) {
      return "Corpse is ruined for harvesting.";
    }
    if (corpse.harvestedProcedures?.[procedure.id]) {
      return `${procedure.label} already performed.`;
    }
    if (hasPendingNecropsy(corpse.id)) {
      return "Necropsy already pending.";
    }
    if (hasPendingCorpseHarvest(corpse.id)) {
      return "Harvest already pending for this corpse.";
    }
    return physicalStateRiskBlockReason(`harvesting ${corpse.name} remains`) || staminaBlockReason(cost);
  }

  function necropsyDuration(corpse) {
    const freshness = corpseFreshness(corpse);
    if (freshness === "fresh") {
      return 18;
    }
    if (freshness === "decaying") {
      return 24;
    }
    return 30;
  }

  function corpseHarvestDuration(corpse, procedure) {
    const freshness = corpseFreshness(corpse);
    const multiplier = { fresh: 1, decaying: 1.15, spoiled: 1.35, ruined: 1.5 }[freshness] || 1.2;
    return Math.max(4, Math.round(procedure.corpseDuration * multiplier));
  }

  function livingHarvestProcedureTitle(slime, procedure) {
    const lines = [
      `${procedure.label} extracts harvested specimen material.`,
      "Separate from natural byproducts and feeding residue."
    ];
    if (procedure.terminal) {
      lines.push("Terminal procedure: the living specimen will be consumed.");
    } else {
      lines.push(`Expected strain: -${formatNumber(procedure.bodyDamage)} Body Integrity, -${formatNumber(procedure.massLoss)} Current Mass, +${formatNumber(procedure.stressGain)} Stress.`);
      if (slimeStat(slime, "bodyIntegrity").current <= procedure.bodyDamage) {
        lines.push("Warning: this may kill the specimen.");
      }
    }
    return lines.join("\n");
  }

  function corpseHarvestProcedureTitle(corpse, procedure) {
    const lines = [
      `${procedure.label} extracts harvested specimen material from ${corpseStateLabel(corpse).toLowerCase()} remains.`,
      "Necropsied or ruined corpses cannot be harvested."
    ];
    if (procedure.corpseConsumes) {
      lines.push("Consumes the corpse completely.");
    } else if (procedure.corpseRuins) {
      lines.push("Leaves a ruined corpse that still needs disposal.");
    }
    return lines.join("\n");
  }

  function dumpCorpseOutside(corpseId) {
    const corpse = findCorpse(corpseId);
    const reason = dumpCorpseBlockReason(corpse);
    if (reason) {
      addEvent(reason);
      persist();
      render();
      return;
    }
    removeCorpseRecord(corpse.id);
    addEvent(`${corpse.name} was dumped outside. Evidence risk increased.`);
    addSuspicion(dumpSuspicionForCorpse(corpse));
    persist();
    render();
  }

  function dumpCorpseBlockReason(corpse) {
    if (!corpse) {
      return "Corpse not found.";
    }
    if (hasPendingNecropsy(corpse.id)) {
      return "Necropsy already pending.";
    }
    if (hasPendingCorpseHarvest(corpse.id)) {
      return "Harvest already pending for this corpse.";
    }
    return "";
  }

  function dumpSuspicionForCorpse(corpse) {
    return DUMP_SUSPICION[corpseFreshness(corpse)] || DUMP_SUSPICION.decaying;
  }

  function assignCreatureJob(slimeId, jobId) {
    const slime = findSlime(slimeId);
    if (!slime) {
      return;
    }
    normalizeSlimeJob(slime);
    const nextJob = CREATURE_JOBS.some((job) => job.id === jobId) ? jobId : "idle";
    const jobReason = jobAssignmentBlockReason(slime);
    if (nextJob !== "idle" && jobReason) {
      addEvent(`${slime.name} cannot be assigned: ${jobReason}`);
      persist();
      render();
      return;
    }
    const jobSpecificReason = slimeJobSpecificBlockReason(slime, nextJob);
    if (nextJob !== "idle" && jobSpecificReason) {
      addEvent(`${slime.name} cannot be assigned: ${jobSpecificReason}`);
      persist();
      render();
      return;
    }
    slime.job = nextJob;
    slime.jobProgress = 0;
    slime.jobTargetCorpseId = null;
    if (nextJob === "corpse") {
      assignCorpseTarget(slime, reservedCorpseTargets(slime.id));
      addEvent(slime.jobTargetCorpseId
        ? `${slime.name} assigned to corpse processing.`
        : `${slime.name} assigned to corpse processing; ${corpseProcessingUnavailableText(slime)} is waiting in ${pitJobSiteLabel(slime)}.`);
    } else if (nextJob === "disposal") {
      ensureJobKnowledge(slime, "disposal");
      const pit = slimePitJobSite(slime);
      addEvent(containerWasteAmount(pit) > 0
        ? `${slime.name} assigned to waste disposal.`
        : `${slime.name} assigned to waste disposal; no Waste is waiting in ${pitJobSiteLabel(slime)}.`);
    } else if (nextJob === "cleanup") {
      ensureJobKnowledge(slime, "cleanup");
      addEvent(`${slime.name} marked for cleanup use. It will still follow instincts; use doors to limit roaming.`);
    } else {
      addEvent(`${slime.name} set to idle.`);
    }
    persist();
    render();
  }

  function updateCreatureJobs(minutes) {
    const elapsed = Math.max(0, Number(minutes) || 0);
    if (!elapsed) {
      return 0;
    }
    return updateCorpseProcessingJobs(elapsed) + updateWasteDisposalJobs(elapsed);
  }

  function updateFeedstockIncome(minutes) {
    const elapsed = Math.max(0, Number(minutes) || 0);
    if (!elapsed) {
      return 0;
    }
    state.feedstockIncomeProgress = normalizeFeedstockIncomeProgress(state.feedstockIncomeProgress);
    let changes = 0;
    for (const feedstock of FEEDSTOCK_DEFS.filter((candidate) => candidate.passive)) {
      const gain = elapsed * (PASSIVE_FEEDSTOCK_INCOME_PER_DAY / SECONDS_PER_DAY);
      const nextProgress = (state.feedstockIncomeProgress[feedstock.key] || 0) + gain;
      const wholeUnits = Math.floor(nextProgress);
      state.feedstockIncomeProgress[feedstock.key] = nextProgress - wholeUnits;
      if (wholeUnits > 0 && addResource(feedstock.key, wholeUnits)) {
        changes += 1;
      }
    }
    return changes;
  }

  function updateAutoFeeding() {
    state.policies = normalizePolicies(state.policies);
    const policy = state.policies.feeding;
    if (policy.mode === "disabled") {
      return 0;
    }
    let changes = 0;
    for (const slime of state.slimes || []) {
      if (!canAutoFeedSlime(slime, policy)) {
        continue;
      }
      let guard = 0;
      while (guard < 12 && shouldAutoFeedSlime(slime, policy)) {
        const feedstockKey = chooseAutoFeedstock(slime, policy);
        if (!feedstockKey) {
          break;
        }
        if (!feedSlime(slime, feedstockKey, { source: "auto", requireLocal: true })) {
          break;
        }
        changes += 1;
        guard += 1;
        if (!canAutoFeedSlime(slime, policy)) {
          break;
        }
      }
    }
    return changes;
  }

  function canAutoFeedSlime(slime, policy) {
    return Boolean(slime && slime.status !== "dead" && !slime.automationExcluded && policy.mode !== "disabled");
  }

  function shouldAutoFeedSlime(slime, policy) {
    if (environmentCanCurrentlyFeed(slime)) {
      return false;
    }
    const nutrition = slimeStat(slime, "nutrition").current;
    const mass = slimeStat(slime, "currentMass").current;
    const target = autoFeedTargetNutrition(policy);
    if (nutrition >= target) {
      return false;
    }
    const threshold = autoFeedThreshold(policy);
    if (nutrition < threshold) {
      return true;
    }
    if (policy.mode === "emergency") {
      return false;
    }
    if (policy.mode === "reproduction" && policy.allowReproductionPressure) {
      return true;
    }
    if (["regrow", "full"].includes(policy.massGoal) && mass < 100) {
      return true;
    }
    if (policy.mode === "growth" && mass < 100) {
      return true;
    }
    return false;
  }

  function autoFeedThreshold(policy) {
    const base = clamp(Math.round(Number(policy.feedBelow) || AUTO_FEED_DEFAULTS.feedBelow), 1, 100);
    return policy.mode === "emergency" ? Math.min(base, 25) : base;
  }

  function autoFeedTargetNutrition(policy) {
    let target = clamp(Math.round(Number(policy.feedUntil) || AUTO_FEED_DEFAULTS.feedUntil), 1, 100);
    if (policy.mode === "emergency") {
      target = Math.min(target, 35);
    }
    if (policy.mode === "reproduction" && policy.allowReproductionPressure) {
      target = Math.max(target, 95);
    }
    if (!policy.allowReproductionPressure) {
      target = Math.min(target, DIVISION_NUTRITION_THRESHOLD - 1);
    }
    return target;
  }

  function chooseAutoFeedstock(slime, policy) {
    const known = Boolean(slime.revealed?.sustenance);
    if (!known && !policy.allowUnknownSustenance) {
      return "";
    }
    const roomId = slimeEffectiveRoomId(slime);
    const available = allowedFeedstockDefs(policy, roomId);
    if (!available.length) {
      return "";
    }
    if (known && policy.usePreferredWhenKnown) {
      const preferred = preferredFeedstockKeys(slime)
        .map((key) => FEEDSTOCK_BY_KEY[key])
        .filter(Boolean)
        .filter((feedstock) => feedstockAllowedByPolicy(feedstock, policy) && feedstockAvailable(feedstock.key, policy, roomId));
      if (preferred.length) {
        return preferred[0].key;
      }
    }
    if (!known) {
      return available[0]?.key || "";
    }
    const ranked = available
      .map((feedstock) => ({ feedstock, match: feedstockMatch(slime, feedstock.key) }))
      .filter((entry) => policyAllowsFeedMatch(entry.match.quality, policy))
      .sort((a, b) => feedMatchRank(b.match.quality) - feedMatchRank(a.match.quality));
    return ranked[0]?.feedstock.key || "";
  }

  function allowedFeedstockDefs(policy, roomId = null) {
    return FEEDSTOCK_DEFS.filter((feedstock) => feedstockAllowedByPolicy(feedstock, policy) && feedstockAvailable(feedstock.key, policy, roomId));
  }

  function feedstockAllowedByPolicy(feedstock, policy) {
    if (feedstock.key === "carrionFeedstock" && !policy.allowCarrion) {
      return false;
    }
    if (feedstock.key === "contaminatedFeedstock" && !policy.allowContaminated) {
      return false;
    }
    return true;
  }

  function feedstockAvailable(feedstockKey, policy = null, roomId = null) {
    const reserve = Math.max(0, Math.floor(Number(policy?.preserveReserve) || 0));
    const amount = roomId ? resourceAmountInRoom(feedstockKey, roomId) : resourceAmount(feedstockKey);
    return amount > reserve;
  }

  function policyAllowsFeedMatch(quality, policy) {
    if (quality === "good") {
      return true;
    }
    if (quality === "partial") {
      return policy.allowPartialMatches;
    }
    if (quality === "bad") {
      return policy.allowBadMatches;
    }
    if (quality === "harmful") {
      return policy.allowHarmfulFeeding;
    }
    return false;
  }

  function feedMatchRank(quality) {
    return { harmful: 0, bad: 1, partial: 2, good: 3 }[quality] || 0;
  }

  function feedstockResidueOutcome(feedstock, match, effects) {
    if (!feedstock || match?.quality === "good") {
      return null;
    }
    const tags = new Set(feedstock.tags || []);
    const amount = Math.max(1, Math.round(Number(effects?.waste) || (match?.quality === "partial" ? 1 : 1)));
    if (tags.has("hazardous") || tags.has("contaminated") || tags.has("volatile") || match?.quality === "harmful") {
      return { typeKey: "hazardousSludge", amount: Math.max(1, amount) };
    }
    if (tags.has("decay") || tags.has("corpse")) {
      return { typeKey: "contaminatedResidue", amount };
    }
    if (tags.has("organic")) {
      return { typeKey: "looseBiomatter", amount };
    }
    if (tags.has("arcane") || tags.has("mana")) {
      return { typeKey: "elementalTrace", amount };
    }
    if (tags.has("mineral") || tags.has("metal") || tags.has("silicate")) {
      return { typeKey: "inertResidue", amount };
    }
    return { typeKey: "slimeTrace", amount };
  }

  function applyFeedstockResidue(slime, feedstock, match, effects, source) {
    const outcome = feedstockResidueOutcome(feedstock, match, effects);
    if (!outcome) {
      return false;
    }
    return addFeedingResidue(outcome.typeKey, outcome.amount, {
      slime,
      sourceLabel: `${source === "auto" ? "Auto-feed" : "Manual feed"}: ${feedstock.label}`,
      tags: ["feeding", match.quality, ...feedstock.tags, ...(match.sharedTags || [])]
    });
  }

  function feedSlimeOrQueueDelivery(slime, feedstockKey, options = {}) {
    const feedstock = FEEDSTOCK_BY_KEY[feedstockKey];
    if (!slime || slime.status === "dead" || !feedstock || resourceAmount(feedstock.key) <= 0) {
      return false;
    }
    const roomId = slimeEffectiveRoomId(slime);
    if (resourceAmountInRoom(feedstock.key, roomId) > 0) {
      return feedSlime(slime, feedstockKey, { ...options, requireLocal: true });
    }
    return queueResourceHaulForContinuation({
      costs: { [feedstock.key]: 1 },
      toRoomId: roomId,
      actionLabel: `feeding ${slime.name}`,
      continuation: {
        kind: "feedSlime",
        slimeId: slime.id,
        feedstockKey: feedstock.key,
        options
      }
    });
  }

  function feedSlime(slime, feedstockKey, options = {}) {
    const feedstock = FEEDSTOCK_BY_KEY[feedstockKey];
    const roomId = slime ? slimeEffectiveRoomId(slime) : MAIN_ROOM_ID;
    const available = options.requireLocal ? resourceAmountInRoom(feedstock?.key, roomId) : resourceAmount(feedstock?.key);
    if (!slime || slime.status === "dead" || !feedstock || available <= 0) {
      return false;
    }
    const match = feedstockMatch(slime, feedstock.key);
    const effects = FEED_MATCH_EFFECTS[match.quality] || FEED_MATCH_EFFECTS.bad;
    addResource(feedstock.key, -1, roomId);
    const nutritionGain = adjustedSlimeNutritionGain(slime, effects.nutrition);
    adjustSlimeStat(slime, "nutrition", nutritionGain);
    const mass = slimeStat(slime, "currentMass");
    const massGain = Math.max(0, Math.min(effects.mass, mass.max - mass.current));
    if (massGain > 0) {
      adjustSlimeStat(slime, "currentMass", massGain);
    }
    if (effects.stress) {
      adjustSlimeStat(slime, "stress", effects.stress);
    }
    if (effects.bodyDamage) {
      if (slimeStat(slime, "bodyIntegrity").current - effects.bodyDamage <= 0) {
        slime.deathCause = "bad feeding";
      }
      adjustSlimeStat(slime, "bodyIntegrity", -effects.bodyDamage);
    }
    if (effects.waste) {
      addWaste(effects.waste, ["feeding", ...feedstock.tags], roomId);
    }
    const leftResidue = applyFeedstockResidue(slime, feedstock, match, effects, options.source);
    addEvent(`${slime.name} ${options.source === "auto" ? "auto-fed" : "fed"} ${feedstock.label}: ${effects.label}, +${formatNumber(nutritionGain)} Nutrition${massGain ? `, +${formatNumber(massGain)} Current Mass` : ""}${leftResidue ? ", left local residue" : ""}.`);
    expireSlimes();
    return true;
  }

  function feedstockMatch(slime, feedstockKey) {
    const feedstock = FEEDSTOCK_BY_KEY[feedstockKey];
    const evaluated = evaluateGenome(slime.genome);
    const label = baseOutcomeLabel(evaluated.traits.sustenance);
    const preferred = preferredFeedstockKeys(slime);
    if (preferred.includes(feedstockKey)) {
      return { quality: "good", label, sharedTags: [...feedstock.tags] };
    }
    const sustenanceTags = new Set(evaluated.traits.sustenance.meta?.tags || []);
    const sharedTags = feedstock.tags.filter((tag) => sustenanceTags.has(tag) && !["material", "waste", "clean"].includes(tag));
    if (sharedTags.length) {
      return { quality: "partial", label, sharedTags };
    }
    if (feedstock.tags.some((tag) => ["hazardous", "contaminated", "volatile"].includes(tag))) {
      return { quality: "harmful", label, sharedTags: [] };
    }
    return { quality: "bad", label, sharedTags: [] };
  }

  function preferredFeedstockKeys(slime) {
    const evaluated = evaluateGenome(slime.genome);
    const label = baseOutcomeLabel(evaluated.traits.sustenance);
    return [...(PREFERRED_FEEDSTOCKS_BY_SUSTENANCE[label] || [])];
  }

  function bestAvailableFeedstockKey(slime) {
    return preferredFeedstockKeys(slime).find((key) => resourceAmount(key) > 0) || "";
  }



  function scientistRoomId() {
    state.scientist = normalizeScientist(state.scientist);
    return state.scientist.roomId || MAIN_ROOM_ID;
  }

  function scientistObservesRoom(roomId) {
    return (roomId || MAIN_ROOM_ID) === scientistRoomId();
  }


  function scientistMoveTask() {
    return (state.tasks || []).find((task) => task.type === "scientistMove") || null;
  }

  function scientistMoveBlockReason(toRoomId, options = {}) {
    const target = roomById(toRoomId);
    if (!target) {
      return "No connected room selected.";
    }
    if (scientistIsDead()) {
      return "The scientist is dead.";
    }
    if (scientistMoveTask()) {
      return "The scientist is already moving.";
    }
    const fromRoomId = scientistRoomId();
    const fromCell = scientistMapCell();
    const targetCell = options.toCell
      ? options.allowUnassignedCell && labMapCellIsWalkable(options.toCell)
        ? cleanMapCell(options.toCell)
        : normalizeMapCellForRoom(options.toCell, target.id)
      : null;
    if (fromRoomId === target.id && (!targetCell || mapCellKey(fromCell) === mapCellKey(targetCell))) {
      return "The scientist is already there.";
    }
    if (!options.allowMultiRoom && fromRoomId !== target.id && !roomConnectedIds(fromRoomId).includes(target.id)) {
      return "The scientist can only move to connected rooms.";
    }
    const securityRoute = roomRouteBetween(fromRoomId, target.id, {
      ignoreDoors: true,
      ignoreDoorSecurity: true,
      requireReachable: true,
      fromCell,
      toCell: targetCell || undefined,
      allowUnassignedCell: options.allowUnassignedCell
    });
    const doorBlock = firstDoorSecurityBlockReason(securityRoute);
    if (doorBlock) {
      return doorBlock;
    }
    if (!roomPathBetween(fromRoomId, target.id, { ignoreDoors: true, fromCell, toCell: targetCell || undefined, allowUnassignedCell: options.allowUnassignedCell }).length) {
      return `No physical walking route exists from ${roomArticleName(fromRoomId)} to ${roomArticleName(target.id)}.`;
    }
    return "";
  }

  function scientistMoveDuration(fromRoomId, toRoomId, options = {}) {
    const fromCell = options.fromCell || scientistMapCell();
    const toCell = options.toCell || nearestOpenMapCellInRoom(toRoomId, labMapRoomAnchor(toRoomId));
    const distance = roomPathDistanceMeters(fromRoomId, toRoomId, { ignoreDoors: true, fromCell, toCell, allowUnassignedCell: options.allowUnassignedCell });
    const route = roomRouteBetween(fromRoomId, toRoomId, { ignoreDoors: true, fromCell, toCell, allowUnassignedCell: options.allowUnassignedCell });
    const doorDelay = Math.max(0, route.length - 1) * SCIENTIST_DOOR_TRANSIT_SECONDS;
    const travelSeconds = Number.isFinite(distance) ? distance / scientistMoveSpeedMps() : 0;
    return adjustedSecondsDuration(Math.max(SCIENTIST_MOVE_MIN_DURATION, travelSeconds + doorDelay), "analysis");
  }

  function startScientistMove(toRoomId, options = {}) {
    const target = roomById(toRoomId);
    const reason = scientistMoveBlockReason(toRoomId, options);
    if (reason) {
      addEvent(reason);
      if (!options.deferRender) {
        persist();
        render();
      }
      return null;
    }
    const cost = adjustedStaminaCost(SCIENTIST_MOVE_BASE_STAMINA, ["analysis"]);
    if (!spendStamina(cost)) {
      addEvent(`Not enough stamina. ${cost} required.`);
      if (!options.deferRender) {
        persist();
        render();
      }
      return null;
    }
    const fromRoomId = scientistRoomId();
    const fromCell = scientistMapCell();
    const toCell = options.toCell
      ? options.allowUnassignedCell && labMapCellIsWalkable(options.toCell)
        ? cleanMapCell(options.toCell)
        : normalizeMapCellForRoom(options.toCell, target.id)
      : nearestOpenMapCellInRoom(target.id, labMapRoomAnchor(target.id), { preferredCell: fromCell });
    const duration = scientistMoveDuration(fromRoomId, target.id, { fromCell, toCell, allowUnassignedCell: options.allowUnassignedCell });
    const route = roomRouteBetween(fromRoomId, target.id, { ignoreDoors: true, fromCell, toCell, allowUnassignedCell: options.allowUnassignedCell });
    const mapPath = roomPathBetween(fromRoomId, target.id, { ignoreDoors: true, fromCell, toCell, allowUnassignedCell: options.allowUnassignedCell });
    const task = {
      id: `task-${state.nextTaskNumber++}`,
      type: "scientistMove",
      label: String(options.label || `Move scientist to ${target.name}`).trim(),
      createdAt: state.clock,
      dueAt: state.clock + duration,
      data: {
        fromRoomId,
        toRoomId: target.id,
        route,
        fromCell,
        toCell,
        allowUnassignedCell: Boolean(options.allowUnassignedCell),
        mapPath,
        doorTransit: doorTransitPlan(route),
        staminaCost: cost,
        incidentId: String(options.incidentId || "").trim()
      }
    };
    state.tasks.push(task);
    const closedDoors = task.data.doorTransit.filter((step) => step.previousState === DOOR_STATE_CLOSED).length;
    addEvent(`${options.eventLabel || "Scientist movement started"}: ${roomName(fromRoomId)} to ${target.name}${closedDoors ? "; closed doors will be opened and handled by policy" : ""}.`);
    if (!options.deferRender) {
      persist();
      render();
    }
    return task;
  }

  function completeScientistMove(task) {
    const target = roomById(task.data?.toRoomId);
    if (!target) {
      addEvent("Scientist movement could not complete; the room no longer exists.");
      return false;
    }
    const fromRoomId = state.scientist?.roomId || task.data?.fromRoomId || MAIN_ROOM_ID;
    state.scientist = normalizeScientist(state.scientist);
    state.scientist.roomId = target.id;
    state.scientist.mapCell = task.data?.allowUnassignedCell && labMapCellIsWalkable(task.data?.toCell)
      ? cleanMapCell(task.data.toCell)
      : normalizeMapCellForRoom(task.data?.toCell, target.id);
    applyDoorTransitPolicy(task.data?.doorTransit, "Scientist movement");
    addEvent(`Arrived in ${target.name}.`);
    const incident = incidentById(task.data?.incidentId);
    if (incident && incidentIsUnresolved(incident)) {
      incident.responseTaskId = "";
      incident.responseArrivedAt = state.clock;
      incident.acknowledgedAt ??= task.createdAt;
      incident.updatedAt = state.clock;
      addEvent(`Incident response reached ${incident.label}.`);
    }
    observeScientistRoom({ discoverChanges: true });
    return true;
  }


  function roomExposureBand(value) {
    const score = clamp(Number(value) || 0, 0, 100);
    return ROOM_EXPOSURE_BANDS.find((band) => score <= band.max) || ROOM_EXPOSURE_BANDS[ROOM_EXPOSURE_BANDS.length - 1];
  }

  function roomExposureScore(roomOrId) {
    const room = typeof roomOrId === "string" ? roomById(roomOrId) : roomOrId;
    if (!room) {
      return 0;
    }
    const contamination = roomContaminationValue(room.id);
    const crowdingPressure = Math.max(0, roomCrowdingPressureScore(room)) * 0.65;
    const freePressure = freeCreaturesInRoom(room.id).length ? Math.min(14, freeCreaturesInRoom(room.id).length * 5) : 0;
    return clamp(contamination + crowdingPressure + freePressure, 0, 100);
  }

  function currentRoomExposureFactors(room) {
    const roomId = room?.id || MAIN_ROOM_ID;
    const contamination = roomContaminationValue(roomId);
    const knownFactors = [];
    const unknownFactors = [];
    if (contamination >= 78) {
      knownFactors.push("hazardous contamination");
    } else if (contamination >= 55) {
      knownFactors.push("fouled air");
    } else if (contamination >= 30) {
      knownFactors.push("tainted residue");
    } else if (contamination <= 8) {
      knownFactors.push("cleaner air");
    } else {
      knownFactors.push("stale air");
    }

    const crowding = roomCrowdingLabel(roomId);
    if (["Busy", "Crowded", "Overpacked"].includes(crowding)) {
      knownFactors.push(`room is ${crowding.toLowerCase()}`);
    }

    const freeCreatures = freeCreaturesInRoom(roomId);
    if (freeCreatures.length) {
      knownFactors.push(`${freeCreatures.length} uncontained creature${freeCreatures.length === 1 ? "" : "s"} observed`);
      for (const slime of freeCreatures.slice(0, 2)) {
        if (slimeHuntingInclination(slime) && (skillLevel("creatureLore") >= FREE_CREATURE_PRESSURE_HIGH_SKILL || slimeTraitKnown(slime, "behavior"))) {
          knownFactors.push(`${slime.name} shows hunting behavior`);
        } else if (!slimeTraitKnown(slime, "behavior") && skillLevel("creatureLore") < FREE_CREATURE_PRESSURE_HIGH_SKILL) {
          unknownFactors.push(`${slime.name} behavior`);
        }
        if (!slimeTraitKnown(slime, "byproduct") && skillLevel("alchemy") < FREE_CREATURE_PRESSURE_HIGH_SKILL) {
          unknownFactors.push(`${slime.name} contact hazards`);
        }
      }
    }

    return {
      knownFactors: [...new Set(knownFactors)].slice(0, 5),
      unknownFactors: [...new Set(unknownFactors)].slice(0, 5)
    };
  }

  function roomObservationReliabilityScore(room, observation) {
    if (!observation) {
      return 0;
    }
    if (scientistObservesRoom(room.id)) {
      return 100;
    }
    let score = 72;
    const age = Math.max(0, state.clock - (Number(observation.observedAt) || 0));
    if (age > minutesToSeconds(360)) score -= 36;
    else if (age > minutesToSeconds(60)) score -= 22;
    else if (age > minutesToSeconds(15)) score -= 12;
    else if (age > minutesToSeconds(3)) score -= 5;

    if (observation.freeCreatureCount > 0) {
      score -= 18;
    }
    if (observation.crowdingLabel === "Crowded" || observation.crowdingLabel === "Overpacked") {
      score -= 10;
    }
    if (observation.exposureScore >= 65) {
      score -= 8;
    }
    score += Math.min(12, skillLevel("analysis") * 3);
    return clamp(score, 0, 100);
  }

  function roomObservationReliabilityLabel(score) {
    return (ROOM_OBSERVATION_RELIABILITY_BANDS.find((band) => score >= band.min) || ROOM_OBSERVATION_RELIABILITY_BANDS[ROOM_OBSERVATION_RELIABILITY_BANDS.length - 1]).label;
  }

  function roomObservationReliabilityFactors(room, observation, score) {
    if (!observation) {
      return ["no prior observation"];
    }
    if (scientistObservesRoom(room.id)) {
      return ["current observation"];
    }
    const factors = [];
    const age = Math.max(0, state.clock - (Number(observation.observedAt) || 0));
    if (age > minutesToSeconds(360)) factors.push("old observation");
    else if (age > minutesToSeconds(60)) factors.push("aging observation");
    else factors.push("recent observation");

    const creatureUncertaintyKnown =
      observation.freeCreatureCount > 0 ||
      (observation.knownFactors || []).some((factor) => /creature|RG-|hunting/i.test(factor)) ||
      (observation.unknownFactors || []).some((factor) => /creature|behavior|contact hazards|RG-/i.test(factor));

    if (creatureUncertaintyKnown || !scientistObservesRoom(room.id)) {
      factors.push("creature movement may have changed conditions");
    }
    if (observation.exposureScore >= 65) {
      factors.push("hazardous rooms change quickly");
    }
    if (observation.crowdingLabel === "Crowded" || observation.crowdingLabel === "Overpacked") {
      factors.push("crowded room");
    }
    if (score >= 58) {
      factors.push("stable enough to use cautiously");
    }
    return [...new Set(factors)].slice(0, 4);
  }

  function roomObservationCreatureIds(roomId, filterFn = null) {
    return freeCreaturesInRoom(roomId)
      .filter((slime) => !filterFn || filterFn(slime))
      .map((slime) => slime.id)
      .filter(Boolean);
  }

  function makeRoomObservation(room) {
    const exposureScore = roomExposureScore(room);
    const exposureBand = roomExposureBand(exposureScore);
    const factors = currentRoomExposureFactors(room);
    const contaminationValue = roomContaminationValue(room.id);
    const freeCreatureIds = roomObservationCreatureIds(room.id);
    const cleanupActorIds = roomObservationCreatureIds(room.id, (slime) =>
      ["feedingOnContamination", "seekingContamination", "leavingResidue"].includes(slime.roomActivity?.type)
    );
    const residueActorIds = roomObservationCreatureIds(room.id, (slime) =>
      slime.roomActivity?.type === "leavingResidue"
    );
    return {
      observedAt: state.clock,
      exposureScore: Math.round(exposureScore),
      exposureBand: exposureBand.label,
      effect: exposureBand.effect,
      knownFactors: factors.knownFactors,
      unknownFactors: factors.unknownFactors,
      contaminationValue: Math.round(contaminationValue * 10) / 10,
      contaminationBand: roomAttributeBand("contamination", contaminationValue).label,
      crowdingLabel: roomCrowdingLabel(room.id),
      freeCreatureCount: freeCreatureIds.length,
      freeCreatureIds,
      cleanupActorIds,
      residueActorIds
    };
  }

  function slimeEffectiveRoomIdForContext(slime, context = state) {
    if (!slime) {
      return MAIN_ROOM_ID;
    }
    if (slime.status !== "released" && slime.containerId) {
      const container = (context?.containers || []).find((candidate) => candidate.id === slime.containerId);
      return container?.roomId || slime.roomId || MAIN_ROOM_ID;
    }
    return slime.roomId || MAIN_ROOM_ID;
  }

  function cleanCreatureRecord(candidate, slime, context = state) {
    const clock = Number.isFinite(Number(context?.clock)) ? Number(context.clock) : 0;
    const roomId = slimeEffectiveRoomIdForContext(slime, context);
    const fallbackObservedAt = slime.status === "released"
      ? finiteTime(slime.createdAt, clock)
      : clock;
    const lastObservedAt = finiteTime(candidate?.lastObservedAt ?? candidate?.observedAt, fallbackObservedAt);
    return {
      specimenId: slime.id,
      name: String(candidate?.name || slime.name || slime.id).trim(),
      lastObservedAt,
      lastKnownRoomId: cleanRoomId(candidate?.lastKnownRoomId || candidate?.roomId) || roomId,
      lastKnownContainerId: cleanContainerId(candidate?.lastKnownContainerId || candidate?.containerId) || (slime.containerId || ""),
      lastKnownStatus: String(candidate?.lastKnownStatus || slime.status || "contained").trim(),
      lastKnownMapCell: cleanMapCell(candidate?.lastKnownMapCell || candidate?.mapCell) || cleanMapCell(slime.mapCell),
      lastKnownActivity: String(candidate?.lastKnownActivity || slime.roomActivity?.label || slime.status || "unknown").trim(),
      updatedAt: finiteTime(candidate?.updatedAt, lastObservedAt)
    };
  }

  function normalizeCreatureRecords(candidate = {}, context = state) {
    const source = candidate && typeof candidate === "object" ? candidate : {};
    const records = {};
    for (const slime of context?.slimes || []) {
      if (!slime || slime.status === "dead") {
        continue;
      }
      records[slime.id] = cleanCreatureRecord(source[slime.id], slime, context);
    }
    return records;
  }

  function ensureCreatureRecords() {
    state.creatureRecords = normalizeCreatureRecords(state.creatureRecords, state);
    return state.creatureRecords;
  }

  function creatureRecordForSlime(slime) {
    if (!slime) {
      return null;
    }
    const records = ensureCreatureRecords();
    records[slime.id] ||= cleanCreatureRecord(null, slime, state);
    return records[slime.id];
  }

  function observeCreatureRecord(slime, options = {}) {
    if (!slime || slime.status === "dead") {
      return null;
    }
    const record = creatureRecordForSlime(slime);
    if (!record) {
      return null;
    }
    record.name = slime.name || record.name || slime.id;
    record.lastObservedAt = finiteTime(options.observedAt, state.clock);
    record.lastKnownRoomId = slimeEffectiveRoomId(slime);
    record.lastKnownContainerId = slime.containerId || "";
    record.lastKnownStatus = slime.status || "contained";
    record.lastKnownMapCell = cleanMapCell(slime.mapCell);
    record.lastKnownActivity = slimeActivityLabel(slime);
    record.updatedAt = state.clock;
    return record;
  }

  function observeCreaturesInRoom(roomId) {
    const resolvedRoomId = roomById(roomId)?.id || MAIN_ROOM_ID;
    for (const slime of state.slimes || []) {
      if (slime.status !== "dead" && slimeEffectiveRoomId(slime) === resolvedRoomId) {
        observeCreatureRecord(slime);
      }
    }
  }

  function creatureRecordAgeSeconds(record) {
    return Math.max(0, state.clock - finiteTime(record?.lastObservedAt, state.clock));
  }

  function creatureRecordAgeText(record) {
    const age = creatureRecordAgeSeconds(record);
    return age <= 0 ? "current observation" : `last seen ${formatDuration(age)} ago`;
  }

  function isUnknownCreatureRecord(slime) {
    if (!slime || slime.status !== "released") {
      return false;
    }
    const roomId = slimeEffectiveRoomId(slime);
    if (scientistObservesRoom(roomId)) {
      return false;
    }
    const record = creatureRecordForSlime(slime);
    return creatureRecordAgeSeconds(record) >= CREATURE_UNKNOWN_STALE_SECONDS;
  }

  function livingCreatureRecords() {
    ensureCreatureRecords();
    return (state.slimes || []).filter((slime) => slime.status !== "dead" && !isUnknownCreatureRecord(slime));
  }

  function unknownCreatureRecords() {
    ensureCreatureRecords();
    return (state.slimes || []).filter((slime) => slime.status !== "dead" && isUnknownCreatureRecord(slime));
  }

  function idList(value) {
    return Array.isArray(value) ? value.map(String).filter(Boolean) : [];
  }

  function cleanLineageId(value) {
    return String(value || "").replace(/[^a-zA-Z0-9:_-]/g, "-").replace(/-+/g, "-").replace(/^-|-$/g, "");
  }

  function idListsDiffer(a, b) {
    const left = [...new Set(idList(a))].sort();
    const right = [...new Set(idList(b))].sort();
    return left.length !== right.length || left.some((id, index) => id !== right[index]);
  }

  function namesForSlimeIds(ids) {
    return idList(ids)
      .map((id) => findSlime(id)?.name || "")
      .filter(Boolean);
  }

  function formatNameList(names) {
    const clean = [...new Set((names || []).map(String).filter(Boolean))];
    if (clean.length <= 1) {
      return clean[0] || "";
    }
    if (clean.length === 2) {
      return `${clean[0]} and ${clean[1]}`;
    }
    return `${clean.slice(0, -1).join(", ")}, and ${clean[clean.length - 1]}`;
  }

  function roomChangeSentence(parts) {
    const clean = (parts || []).filter(Boolean);
    if (!clean.length) {
      return "";
    }
    if (clean.length === 1) {
      return clean[0];
    }
    if (clean.length === 2) {
      return `${clean[0]}, but ${clean[1]}`;
    }
    return `${clean.slice(0, -1).join(", ")}, and ${clean[clean.length - 1]}`;
  }

  function roomChangeDiscoveryMessage(room, previousObservation, currentObservation) {
    const previous = normalizeRoomObservation(previousObservation);
    const current = normalizeRoomObservation(currentObservation);
    if (!room || !previous || !current || current.observedAt <= previous.observedAt) {
      return "";
    }

    const changes = [];
    const previousContamination = Number(previous.contaminationValue);
    const currentContamination = Number(current.contaminationValue);
    if (Number.isFinite(previousContamination) && Number.isFinite(currentContamination)) {
      const delta = currentContamination - previousContamination;
      if (delta <= -2) {
        changes.push("the contamination is lower");
      } else if (delta >= 2) {
        changes.push("the contamination is higher");
      }
    }

    if (idListsDiffer(previous.residueActorIds, current.residueActorIds) && current.residueActorIds.length) {
      changes.push("there is more trace slime");
    }

    if (idListsDiffer(previous.freeCreatureIds, current.freeCreatureIds)) {
      changes.push("free creature presence changed");
    }

    if (!changes.length) {
      return "";
    }

    const details = [];
    const cleanupNames = namesForSlimeIds(current.cleanupActorIds);
    const residueNames = namesForSlimeIds(current.residueActorIds);
    const freeNames = namesForSlimeIds(current.freeCreatureIds);
    const contaminationLower = changes.includes("the contamination is lower");
    const traceHigher = changes.includes("there is more trace slime");

    if (contaminationLower && cleanupNames.length) {
      const names = formatNameList(cleanupNames.slice(0, 3));
      details.push(`${names} ${cleanupNames.length === 1 ? "is" : "are"} present; biological cleanup is a plausible cause.`);
    } else if (contaminationLower && freeNames.length) {
      const names = formatNameList(freeNames.slice(0, 3));
      details.push(`${names} ${freeNames.length === 1 ? "is" : "are"} present; involvement uncertain.`);
    } else if (contaminationLower) {
      details.push("Cause uncertain.");
    }

    if (traceHigher && residueNames.length) {
      const names = formatNameList(residueNames.slice(0, 3));
      details.push(`${names} may be leaving residue.`);
    }

    return [`This room changed: ${roomChangeSentence(changes)}.`, ...details].join(" ");
  }

  function observeScientistRoom(options = {}) {
    const room = roomById(scientistRoomId());
    if (!room) {
      return null;
    }
    const previous = normalizeRoomObservation(room.observation || state.roomObservations?.[room.id]);
    const observation = normalizeRoomObservation(makeRoomObservation(room));
    if (options.discoverChanges) {
      const message = roomChangeDiscoveryMessage(room, previous, observation);
      if (message && state.events.at(-1)?.message !== message) {
        addEvent(message);
      }
    }
    room.observation = observation;
    state.roomObservations ||= {};
    state.roomObservations[room.id] = observation;
    for (const stack of ensurePhysicalItemStacks().filter((entry) => entry.roomId === room.id)) {
      stack.knownQuantity = stack.quantity;
      stack.observedAt = state.clock;
    }
    state.physicalItemStacks = ensurePhysicalItemStacks().filter((stack) => stack.quantity > 0 || stack.knownQuantity > 0);
    observeCreaturesInRoom(room.id);
    return observation;
  }

  function roomExposurePanelEl(room) {
    const panel = document.createElement("div");
    panel.className = "room-exposure-panel";
    panel.dataset.roomExposurePanel = room.id;

    if (scientistObservesRoom(room.id)) {
      const observation = room.observation || makeRoomObservation(room);
      const exposureLine = document.createElement("strong");
      exposureLine.append(document.createTextNode("Room exposure: "), tooltipKeywordEl(observation.exposureBand));
      panel.append(exposureLine);
      panel.append(textEl("div", "Information: Current observation"));
      const reliabilityLine = document.createElement("div");
      reliabilityLine.append(document.createTextNode("Reliability: "), tooltipKeywordEl("High"));
      panel.append(reliabilityLine);
      if (observation.knownFactors?.length) {
        panel.append(textEl("div", `Known factors: ${observation.knownFactors.join(" · ")}`));
      }
      if (observation.unknownFactors?.length) {
        panel.append(textEl("div", `Unknown factors: ${observation.unknownFactors.join(", ")}`));
      }
      panel.append(textEl("div", `Effect: ${observation.effect}`));
      return panel;
    }

    const observation = room.observation || state.roomObservations?.[room.id] || null;
    if (!observation) {
      const unknownLine = document.createElement("strong");
      unknownLine.append(document.createTextNode("Room exposure: "), tooltipKeywordEl("Unknown"));
      panel.append(unknownLine);
      panel.append(textEl("div", "Information: No observation"));
      const unknownReliability = document.createElement("div");
      unknownReliability.append(document.createTextNode("Reliability: "), tooltipKeywordEl("Unknown"));
      panel.append(unknownReliability);
      panel.append(textEl("div", "Unknown factors: current contamination, creature movement, residue"));
      panel.append(textEl("div", "Effect: cannot assess from here"));
      return panel;
    }

    const score = roomObservationReliabilityScore(room, observation);
    const reliability = roomObservationReliabilityLabel(score);
    const factors = roomObservationReliabilityFactors(room, observation, score);

    const thenLine = document.createElement("strong");
    thenLine.append(document.createTextNode("Room exposure then: "), tooltipKeywordEl(observation.exposureBand));
    panel.append(thenLine);
    panel.append(textEl("div", "Information: Previously observed"));
    const previousReliability = document.createElement("div");
    previousReliability.append(document.createTextNode("Reliability: "), tooltipKeywordEl(reliability));
    panel.append(previousReliability);
    if (observation.knownFactors?.length) {
      panel.append(textEl("div", `Known factors then: ${observation.knownFactors.join(" · ")}`));
    }
    const uncertainFactors = [
      ...(observation.unknownFactors || []),
      "current contamination",
      "current creature movement"
    ];
    panel.append(textEl("div", `Uncertain factors: ${[...new Set(uncertainFactors)].slice(0, 5).join(", ")}`));
    panel.append(textEl("div", `Reliability factors: ${factors.join(" · ")}`));
    panel.append(textEl("div", `Effect then: ${observation.effect}`));
    return panel;
  }

  function roomMoveWarningText(roomId) {
    const room = roomById(roomId);
    if (!room) {
      return "Unknown destination.";
    }
    if (scientistObservesRoom(room.id)) {
      const observation = room.observation || makeRoomObservation(room);
      return `Current observation. Room exposure: ${observation.exposureBand}. Reliability: High.`;
    }
    const observation = room.observation || state.roomObservations?.[room.id];
    if (!observation) {
      return "No observation. Room exposure unknown. Current contamination, creature movement, and residue are unknown.";
    }
    const score = roomObservationReliabilityScore(room, observation);
    const reliability = roomObservationReliabilityLabel(score);
    return `Previously observed. Room exposure then: ${observation.exposureBand}. Reliability: ${reliability}. Current contamination and creature movement may have changed.`;
  }

  function restQualityInfo(roomId = scientistRoomId()) {
    const room = roomById(roomId);
    const exposureScore = roomExposureScore(room || roomId);
    const exposureBand = roomExposureBand(exposureScore);
    const contamination = roomContaminationValue(roomId);
    const knownFactors = [];
    const freeCount = freeCreaturesInRoom(roomId).length;

    if (contamination <= 8) {
      knownFactors.push("cleaner air");
    } else if (contamination < 30) {
      knownFactors.push("low room exposure");
    } else if (contamination < 55) {
      knownFactors.push("tainted residue");
    } else if (contamination < 78) {
      knownFactors.push("fouled air");
    } else {
      knownFactors.push("hazardous contamination");
    }

    const crowding = roomCrowdingLabel(roomId);
    if (["Crowded", "Overpacked"].includes(crowding)) {
      knownFactors.push(`room is ${crowding.toLowerCase()}`);
    }

    if (freeCount > 0) {
      knownFactors.push("uncontained creature activity");
    }

    let label = "Good";
    let expectedEffect = "Physical State may improve";
    if (exposureBand.label === "Hazardous" || exposureBand.label === "Unlivable" || contamination >= 78 || freeCount > 0) {
      label = "Unsafe";
      expectedEffect = "Physical State may continue worsening";
    } else if (["Tainted", "Fouled"].includes(exposureBand.label) || contamination >= 30) {
      label = "Poor";
      expectedEffect = "Physical State recovery may be weak";
    }

    const title = `${label}\nKnown factors: ${[...new Set(knownFactors)].join(" · ") || "no major hazards observed"}\nExpected effect: ${expectedEffect}`;
    return {
      label,
      exposureBand: exposureBand.label,
      exposureScore: Math.round(exposureScore),
      knownFactors: [...new Set(knownFactors)],
      expectedEffect,
      title,
      unsafe: label === "Unsafe",
      roomId
    };
  }

  function restQualityPanelEl() {
    const info = restQualityInfo();
    const panel = document.createElement("div");
    panel.className = "rest-quality-panel";
    panel.dataset.restQualityPanel = "scientist";
    const line = document.createElement("div");
    line.append(document.createTextNode("Rest quality: "), tooltipKeywordEl(info.label, info.title));
    line.dataset.restQuality = info.label;
    panel.append(line);
    return panel;
  }

  function confirmUnsafeRestIfNeeded(minutes) {
    const info = restQualityInfo();
    if (!info.unsafe) {
      return true;
    }
    const message = `Resting here is unsafe.\n${info.expectedEffect}.\n\nContinue resting?`;
    const accepted = window.confirm(message);
    if (accepted) {
      addEvent(`Unsafe rest confirmed in ${roomName(info.roomId)}. Physical State may continue worsening.`);
    } else {
      addEvent("Unsafe rest cancelled.");
    }
    return accepted;
  }




  function scientistLocationPanelEl(room) {
    const panel = document.createElement("div");
    panel.className = "scientist-location-panel";
    panel.dataset.scientistLocationPanel = room.id;
    if (scientistRoomId() === room.id) {
      panel.append(textEl("strong", "Scientist present"));
      const moveTargets = roomConnectedIds(room.id);
      if (moveTargets.length) {
        const moves = document.createElement("div");
        moves.className = "scientist-move-actions";
        moves.append(textEl("span", "Move to: "));
        for (const [index, targetId] of moveTargets.entries()) {
          const target = roomById(targetId);
          const button = document.createElement("button");
          button.type = "button";
          const moveDuration = scientistMoveDuration(room.id, target.id);
          const routeSummary = roomPathSummary(room.id, target.id, { fromCell: scientistMapCell(), toCell: labMapRoomAnchor(target.id), ignoreDoors: true });
          const moveCost = setButtonStaminaLabel(button, target.name, SCIENTIST_MOVE_BASE_STAMINA, ["analysis"], { duration: formatDuration(moveDuration) });
          button.dataset.scientistMoveRoomId = target.id;
          const reason = scientistMoveBlockReason(target.id) || staminaBlockReason(moveCost);
          setActionButtonState(button, Boolean(reason), reason);
          if (!reason) {
            button.title = `${roomMoveWarningText(target.id)}\nRoute: ${routeSummary}\n${adjustedStaminaCostBreakdown(SCIENTIST_MOVE_BASE_STAMINA, ["analysis"]).title}`;
          }
          button.addEventListener("click", () => startScientistMove(target.id));
          if (index > 0) {
            moves.append(document.createTextNode(" · "));
          }
          moves.append(button);
        }
        panel.append(moves);
      }
    } else {
      panel.append(textEl("span", "Scientist absent"));
    }
    return panel;
  }


  function freeCreaturesInRoom(roomId) {
    return (state.slimes || []).filter((slime) => slimeIsUncontained(slime) && slime.status !== "dead" && slimeEffectiveRoomId(slime) === roomId);
  }

  function freeCreatureActualPressureScore(slime) {
    let score = 6;
    const stress = slimeStat(slime, "stress").current;
    if (stress >= 85) score += 18;
    else if (stress >= 60) score += 10;

    if (slimeHuntingInclination(slime)) score += 20;
    const info = slimeContaminationTraitInfo(slime);
    if (info.spreadsContamination) score += 10;

    const evaluated = evaluateGenome(slime.genome);
    const appendages = String(evaluated.traits.appendages?.id || "");
    if (appendages && appendages !== "none") score += 8;

    const stability = String(evaluated.traits.stability?.label || "").toLowerCase();
    if (/unstable|volatile|fragile|failing/.test(stability)) score += 8;

    return score;
  }

  function freeCreaturePressureBand(score) {
    if (score >= 50) return "Severe";
    if (score >= 32) return "Dangerous";
    if (score >= 16) return "Watch";
    return "Low";
  }

  function observedFreeCreaturePressure(room) {
    const roomId = room?.id || MAIN_ROOM_ID;
    if (!scientistObservesRoom(roomId)) {
      return {
        label: "Unobserved",
        className: "container-band-unknown",
        knownFactors: [],
        unknownFactors: ["scientist is not in this room"],
        estimate: "cannot assess from here",
        observed: false
      };
    }

    const creatures = freeCreaturesInRoom(roomId);
    if (!creatures.length) {
      return {
        label: "None",
        className: "container-band-good",
        knownFactors: ["no uncontained creatures observed"],
        unknownFactors: [],
        estimate: "no free-creature pressure observed",
        observed: true
      };
    }

    let score = creatures.length * 4 + roomCrowdingPressureScore(room);
    let unknownMajor = 0;
    const knownFactors = [`${creatures.length} uncontained creature${creatures.length === 1 ? "" : "s"} observed`];
    const crowdingReason = roomCrowdingPressureReason(room);
    if (crowdingReason) {
      knownFactors.push(crowdingReason);
    }
    const unknownFactors = [];
    const skill = Math.max(skillLevel("analysis"), skillLevel("creatureLore"), skillLevel("creatureHandling"));
    const highSkill = skill >= FREE_CREATURE_PRESSURE_HIGH_SKILL;

    for (const slime of creatures) {
      score += freeCreatureActualPressureScore(slime);
      const stress = slimeStat(slime, "stress").current;
      if (stress >= 80) {
        knownFactors.push(`${slime.name} appears highly stressed`);
      } else if (stress >= 55) {
        knownFactors.push(`${slime.name} appears agitated`);
      }

      if (highSkill || slimeTraitKnown(slime, "behavior")) {
        if (slimeHuntingInclination(slime)) {
          knownFactors.push(`${slime.name} shows hunting behavior`);
        } else {
          knownFactors.push(`${slime.name}'s behavior has been observed`);
        }
      } else {
        unknownFactors.push(`${slime.name} behavior`);
        unknownMajor += 1;
      }

      if (highSkill || slimeTraitKnown(slime, "appendages")) {
        const appendages = String(evaluateGenome(slime.genome).traits.appendages?.id || "");
        if (appendages && appendages !== "none") {
          knownFactors.push(`${slime.name} has reaching appendages`);
        }
      } else {
        unknownFactors.push(`${slime.name} appendages`);
        unknownMajor += 1;
      }

      if (highSkill || slimeTraitKnown(slime, "element") || slimeTraitKnown(slime, "byproduct")) {
        const info = slimeContaminationTraitInfo(slime);
        if (info.spreadsContamination) {
          knownFactors.push(`${slime.name} may leave residue`);
        }
      } else {
        unknownFactors.push(`${slime.name} contact hazards`);
        unknownMajor += 1;
      }
    }

    const band = freeCreaturePressureBand(score);
    let label = band;
    let estimate = `${band.toLowerCase()} pressure`;
    if (!highSkill && unknownMajor >= 3) {
      label = "Unknown";
      estimate = "cannot assess safely";
    } else if (!highSkill && unknownMajor > 0) {
      label = `Estimated ${band}`;
      estimate = `${band.toLowerCase()} pressure estimate`;
    }

    return {
      label,
      className: band === "Severe" || band === "Dangerous" ? "container-band-bad" : band === "Watch" ? "container-band-watch" : "container-band-good",
      knownFactors: [...new Set(knownFactors)].slice(0, 5),
      unknownFactors: [...new Set(unknownFactors)].slice(0, 5),
      estimate,
      observed: true
    };
  }

  function freeCreaturePressureEl(room) {
    const pressure = observedFreeCreaturePressure(room);
    const panel = document.createElement("div");
    panel.className = "room-free-pressure";
    panel.dataset.freeCreaturePressureRoom = room.id;
    panel.append(textEl("strong", `Free creature pressure: ${pressure.label}`));
    if (pressure.knownFactors.length) {
      panel.append(textEl("div", `Known factors: ${pressure.knownFactors.join(" · ")}`));
    }
    if (pressure.unknownFactors.length) {
      panel.append(textEl("div", `Unknown factors: ${pressure.unknownFactors.join(", ")}`));
    }
    if (pressure.estimate) {
      panel.append(textEl("div", `Estimate: ${pressure.estimate}`));
    }
    return panel;
  }

  function normalizeSlimeAutonomousMovement(candidate, clock = state?.clock || 0) {
    if (!candidate || typeof candidate !== "object") {
      return null;
    }
    const map = ensureLabMap();
    const path = (Array.isArray(candidate.path) ? candidate.path : [])
      .map(cleanMapCell)
      .filter(Boolean);
    if (path.length < 2) {
      return null;
    }
    const startAt = finiteTime(candidate.startAt, clock);
    const arriveAt = finiteTime(candidate.arriveAt, startAt + CREATURE_AUTONOMOUS_MIN_MOVE_SECONDS);
    if (arriveAt <= startAt) {
      return null;
    }
    const targetCell = cleanMapCell(candidate.targetCell) || path[path.length - 1];
    const distanceMeters = Number.isFinite(Number(candidate.distanceMeters))
      ? Math.max(0, Number(candidate.distanceMeters))
      : Math.max(0, path.length - 1) * map.tileSizeM;
    const impliedSpeed = distanceMeters > 0 ? distanceMeters / Math.max(1, arriveAt - startAt) : CREATURE_AUTONOMOUS_MIN_SPEED_MPS;
    const speedMps = clamp(
      Number.isFinite(Number(candidate.speedMps)) ? Number(candidate.speedMps) : impliedSpeed,
      CREATURE_AUTONOMOUS_MIN_SPEED_MPS,
      CREATURE_AUTONOMOUS_MAX_SPEED_MPS
    );
    const baseSpeedMps = clamp(
      Number.isFinite(Number(candidate.baseSpeedMps)) ? Number(candidate.baseSpeedMps) : speedMps,
      CREATURE_AUTONOMOUS_MIN_SPEED_MPS,
      CREATURE_AUTONOMOUS_MAX_SPEED_MPS
    );
    return {
      intent: String(candidate.intent || "wander"),
      label: String(candidate.label || "moving"),
      targetKind: String(candidate.targetKind || ""),
      targetId: String(candidate.targetId || ""),
      targetLabel: String(candidate.targetLabel || ""),
      fromRoomId: cleanRoomId(candidate.fromRoomId),
      targetRoomId: cleanRoomId(candidate.targetRoomId),
      targetCell,
      path,
      distanceMeters,
      speedMps,
      baseSpeedMps,
      conditionFactor: Number.isFinite(Number(candidate.conditionFactor)) ? Math.max(0, Number(candidate.conditionFactor)) : speedMps / Math.max(CREATURE_AUTONOMOUS_MIN_SPEED_MPS, baseSpeedMps),
      movementStyle: String(candidate.movementStyle || ""),
      movementFactors: Array.isArray(candidate.movementFactors)
        ? candidate.movementFactors.map((factor) => String(factor || "").trim()).filter(Boolean).slice(0, 6)
        : [],
      startAt,
      arriveAt,
      updatedAt: finiteTime(candidate.updatedAt, startAt)
    };
  }

  function slimeAutonomousMovementActive(slime) {
    if (!slime?.autonomousMovement) {
      return false;
    }
    const movement = normalizeSlimeAutonomousMovement(slime.autonomousMovement);
    slime.autonomousMovement = movement;
    return Boolean(movement && state.clock < movement.arriveAt);
  }

  function slimeMoveSpeedMps(slime) {
    return slimeMovementProfile(slime).speedMps;
  }

  function slimeMovementProfile(slime) {
    const profile = physicalProfile(slime?.genome || "");
    const baseSpeedMps = clamp(
      Number(profile?.speedMps) || 0.12,
      CREATURE_AUTONOMOUS_MIN_SPEED_MPS,
      CREATURE_AUTONOMOUS_MAX_SPEED_MPS
    );
    const factors = [];
    let conditionFactor = 1;
    const addFactor = (factor, label) => {
      conditionFactor *= factor;
      factors.push(label);
    };

    if (slime && !slime.mature) {
      addFactor(0.45, "immature body");
    }

    const mass = slime ? slimeStatPercent(slime, "currentMass") : 100;
    if (mass < 25) {
      addFactor(0.45, "very low mass");
    } else if (mass < 50) {
      addFactor(0.65, "low mass");
    } else if (mass < 80) {
      addFactor(0.85, "reduced mass");
    }

    const integrity = slime ? slimeStatPercent(slime, "bodyIntegrity") : 100;
    if (integrity < 15) {
      addFactor(0.25, "failing integrity");
    } else if (integrity < 35) {
      addFactor(0.45, "damaged integrity");
    } else if (integrity < 60) {
      addFactor(0.72, "strained integrity");
    } else if (integrity < 85) {
      addFactor(0.9, "worn integrity");
    }

    const stress = slime ? slimeStatPercent(slime, "stress") : 0;
    if (stress >= 90) {
      addFactor(0.55, "panic stress");
    } else if (stress >= 70) {
      addFactor(0.7, "high stress");
    } else if (stress >= 45) {
      addFactor(0.88, "stress");
    }

    const speedMps = roundOutputValue(clamp(
      baseSpeedMps * conditionFactor,
      CREATURE_AUTONOMOUS_MIN_SPEED_MPS,
      CREATURE_AUTONOMOUS_MAX_SPEED_MPS
    ));
    return {
      movementStyle: profile?.movement || "oozes",
      baseSpeedMps,
      speedMps,
      conditionFactor,
      factors
    };
  }

  function movementSpeedText(speedMps) {
    return formatSpeed(Math.max(0, Number(speedMps) || 0) * 100);
  }

  function movementDistanceText(distanceMeters) {
    return formatLength(Math.max(0, Number(distanceMeters) || 0) * 100);
  }

  function movementRouteText(movement) {
    if (!movement) {
      return "";
    }
    const distance = movementDistanceText(movement.distanceMeters);
    const speed = movementSpeedText(movement.speedMps);
    return `${distance} route at ${speed}`;
  }

  function slimeMovementChip(slime) {
    const movement = normalizeSlimeAutonomousMovement(slime?.autonomousMovement);
    if (!movement || state.clock >= movement.arriveAt) {
      return null;
    }
    const element = chip(`Move: ${movementSpeedText(movement.speedMps)}`);
    element.dataset.slimeMovement = slime.id;
    const lines = [
      movementRouteText(movement),
      movement.movementStyle ? `Style: ${movement.movementStyle}` : "",
      movement.movementFactors?.length ? `Condition modifiers: ${movement.movementFactors.join(", ")}` : "Condition modifiers: none",
      `Arrives in ${formatDuration(Math.max(0, movement.arriveAt - state.clock))}`
    ].filter(Boolean);
    element.title = lines.join("\n");
    return element;
  }

  function autonomousMovementProgress(movement) {
    const duration = Math.max(1, movement.arriveAt - movement.startAt);
    return clamp((state.clock - movement.startAt) / duration, 0, 1);
  }

  function firstBlockedDoorOnPath(path, map = ensureLabMap(), startIndex = 0) {
    const firstIndex = clamp(Math.floor(Number(startIndex) || 0), 0, Math.max(0, (path || []).length - 1));
    for (let index = firstIndex; index < (path || []).length - 1; index += 1) {
      const current = path[index];
      const next = path[index + 1];
      const door = labMapDoorForCells(current, next, map);
      if (door && !doorFixtureAllowsPassage(door)) {
        const [fromRoomId, toRoomId] = door.roomIds;
        return {
          fromRoomId,
          toRoomId,
          door,
          state: door ? doorStateLabelByFixture(door) : "missing"
        };
      }
    }
    return null;
  }

  function setSlimeBlockedDoorActivity(slime, block, target = {}) {
    if (!slime || !block) {
      return false;
    }
    slime.autonomousMovement = null;
    slime.roomActivity = {
      type: "pressingClosedDoor",
      label: `pressing against ${block.state || "blocked"} door`,
      roomId: slime.roomId || MAIN_ROOM_ID,
      targetRoomId: target.roomId || block.toRoomId,
      targetKind: target.kind || "",
      targetId: target.id || "",
      targetLabel: target.label || "",
      doorKey: block.door?.key || doorKey(block.fromRoomId, block.toRoomId),
      updatedAt: state.clock
    };
    slime.nextAutonomousDecisionAt = state.clock + CREATURE_AUTONOMOUS_BLOCK_RECHECK_INTERVAL;
    recordCleanupObservation(slime, "pressingClosedDoor", 0, slime.roomId);
    rememberCreatureExperience(slime, "blockedDoor", 2, slime.roomActivity.label);
    return true;
  }

  function targetCellForRoomTarget(roomId, preferredCell = null) {
    return nearestOpenMapCellInRoom(roomId, preferredCell || labMapRoomAnchor(roomId), { ignoreObjects: false });
  }

  function slimeHasFeedingNeed(slime) {
    if (!slime || slime.status === "dead") {
      return false;
    }
    return slimeStatPercent(slime, "nutrition") <= 75 || slimeStatPercent(slime, "currentMass") < 100;
  }

  function looseFoodMatch(slime, sourceTags = []) {
    const evaluated = evaluateGenome(slime.genome);
    const label = baseOutcomeLabel(evaluated.traits.sustenance);
    const foodTags = new Set(normalizeResidueTags(sourceTags));
    const preferredTags = new Set(preferredFeedstockKeys(slime)
      .flatMap((key) => FEEDSTOCK_BY_KEY[key]?.tags || [])
      .filter((tag) => !["material", "clean"].includes(tag)));
    const preferredShared = [...foodTags].filter((tag) => preferredTags.has(tag));
    if (preferredShared.length) {
      return { quality: "good", label, sharedTags: preferredShared };
    }
    const sustenanceTags = new Set(evaluated.traits.sustenance.meta?.tags || []);
    const sharedTags = [...foodTags].filter((tag) => sustenanceTags.has(tag) && !["material", "clean"].includes(tag));
    if (sharedTags.length) {
      return { quality: "partial", label, sharedTags };
    }
    if ([...foodTags].some((tag) => ["hazardous", "contaminated", "volatile", "chemical", "toxic"].includes(tag))) {
      return { quality: "harmful", label, sharedTags: [] };
    }
    return { quality: "bad", label, sharedTags: [] };
  }

  function physicalResourceFoodTags(key) {
    if (FEEDSTOCK_BY_KEY[key]) return [...FEEDSTOCK_BY_KEY[key].tags];
    if (key === "biomass") return ["material", "organic", "clean"];
    if (key === "geneticMaterial") return ["material", "organic", "arcane"];
    if (key === "elementalResidue") return ["material", "mineral", "arcane"];
    if (["stoneBlocks", "bricks"].includes(key)) return ["material", "mineral", "inert"];
    if (["steelPanels", "metalParts"].includes(key)) return ["material", "metal", "mineral"];
    if (key === "lumber") return ["material", "organic", "plant"];
    return ["material"];
  }

  function looseFeedingResidueType(sourceTags = [], match = null) {
    const tags = new Set(normalizeResidueTags(sourceTags));
    if (match?.quality === "harmful" || tags.has("hazardous") || tags.has("toxic")) {
      return "hazardousSludge";
    }
    if (tags.has("contaminated") || tags.has("waste") || tags.has("chemical")) {
      return "contaminatedResidue";
    }
    if (tags.has("mineral") || tags.has("metal") || tags.has("silicate") || tags.has("inert")) {
      return "inertResidue";
    }
    if (tags.has("arcane") || tags.has("mana")) {
      return "elementalTrace";
    }
    return "contaminatedResidue";
  }

  function applyLooseFoodEffects(slime, units, match, options = {}) {
    const count = Math.max(0, Math.floor(Number(units) || 0));
    if (!slime || !count) {
      return { nutritionGain: 0, massGain: 0, residueLeft: false };
    }
    const effects = LOOSE_FEED_MATCH_EFFECTS[match?.quality] || LOOSE_FEED_MATCH_EFFECTS.bad;
    const nutritionGain = adjustedSlimeNutritionGain(slime, count * effects.nutrition);
    if (nutritionGain > 0) {
      adjustSlimeStat(slime, "nutrition", nutritionGain);
    }
    const mass = slimeStat(slime, "currentMass");
    const massGain = Math.max(0, Math.min(count * effects.mass, mass.max - mass.current));
    if (massGain > 0) {
      adjustSlimeStat(slime, "currentMass", massGain);
    }
    if (effects.stress) {
      adjustSlimeStat(slime, "stress", count * effects.stress);
    }
    if (effects.bodyDamage) {
      const damage = count * effects.bodyDamage;
      if (slimeStat(slime, "bodyIntegrity").current - damage <= 0) {
        slime.deathCause = "bad feeding";
      }
      adjustSlimeStat(slime, "bodyIntegrity", -damage);
    }
    let residueLeft = false;
    if (effects.residue > 0) {
      residueLeft = addFeedingResidue(looseFeedingResidueType(options.tags, match), count * effects.residue, {
        slime,
        location: { type: "room", roomId: options.roomId || slimeEffectiveRoomId(slime) },
        sourceLabel: `Uncontrolled feeding: ${options.label || "local food"}`,
        tags: ["loose-feeding", match?.quality || "bad", ...(options.tags || [])]
      });
    }
    return { nutritionGain, massGain, residueLeft };
  }

  function localFoodTargetCandidates(slime, roomId = slimeEffectiveRoomId(slime)) {
    const candidates = [];
    const addTarget = (target) => {
      const room = roomById(target.roomId);
      if (!room) {
        return;
      }
      const cell = cleanMapCell(target.cell) || targetCellForRoomTarget(room.id);
      candidates.push({
        ...target,
        roomId: room.id,
        cell,
        score: Math.max(1, Number(target.score) || 1)
      });
    };

    state.feedingResidues = normalizeFeedingResidues(state.feedingResidues);
    for (const residue of feedingResiduesForLocation({ type: "room", roomId })) {
      if (residue.amount <= 0) {
        continue;
      }
      addTarget({
        kind: "residue",
        id: residue.id,
        roomId,
        label: feedingResidueLabel(residue.typeKey),
        tags: residueFoodTags(residue),
        score: 70 + residue.amount * 8
      });
    }

    for (const stack of ensurePhysicalItemStacks().filter((entry) =>
      entry.section === "resources"
      && entry.key !== "waste"
      && entry.roomId === roomId
      && entry.quantity > 0
      && physicalStackExposed(entry)
    )) {
      const tags = physicalResourceFoodTags(stack.key);
      const match = looseFoodMatch(slime, tags);
      const qualityScore = { good: 42, partial: 30, bad: 12, harmful: 4 }[match.quality] || 8;
      addTarget({
        kind: "physicalStack",
        id: stack.id,
        roomId,
        cell: stockpileHaulAccessCell(stack),
        label: `exposed ${physicalStackLabel(stack).toLowerCase()}`,
        tags,
        score: qualityScore + Math.min(30, stack.quantity * 2)
      });
    }

    const waste = roomId === STORAGE_ROOM_ID ? 0 : resourceAmountInRoom("waste", roomId);
    if (waste > 0) {
      addTarget({
        kind: "waste",
        id: "waste",
        roomId,
        label: "loose waste",
        tags: ["waste", "contaminated", "hazardous", "chemical"],
        score: 55 + waste * 6
      });
    }

    for (const corpse of accessibleCorpsesInRoom(roomId)) {
      addTarget({
        kind: "corpse",
        id: corpse.id,
        roomId: corpse.roomId || MAIN_ROOM_ID,
        cell: objectMapCell(corpse),
        label: `${corpse.name} remains`,
        tags: ["corpse", "organic", "decay", corpseFreshness(corpse)],
        score: 75 + (corpseFreshness(corpse) === "fresh" ? 18 : corpseFreshness(corpse) === "spoiled" ? 6 : 10)
      });
    }

    const info = slimeContaminationTraitInfo(slime);
    if (info.seeksContamination) {
      const contamination = roomContaminationValue(roomId);
      if (contamination > OUT_OF_CONTAINER_CONTAMINATION_FLOOR + OUT_OF_CONTAINER_CONTAMINATION_MOVE_THRESHOLD) {
        addTarget({
          kind: "contamination",
          id: roomId,
          roomId,
          label: "visible contamination",
          tags: ["contaminated", "waste", "chemical"],
          score: 35 + contamination
        });
      }
    }
    return candidates;
  }

  function traceFoodTargetCandidates(slime) {
    const currentRoomId = slimeEffectiveRoomId(slime);
    const candidates = [];
    for (const connectedId of roomConnectedIds(currentRoomId)) {
      for (const source of foodTraceSourcesForRoom(connectedId, slime).slice(0, 3)) {
        const intensity = adjustedFoodTraceIntensity(source.baseIntensity, currentRoomId, connectedId);
        if (!intensity) {
          continue;
        }
        const rank = perceptionIntensityRank(intensity) + 1;
        candidates.push({
          kind: source.targetKind,
          id: "",
          roomId: connectedId,
          cell: targetCellForRoomTarget(connectedId),
          label: `${source.traceLabel} trace from ${roomName(connectedId)}`,
          tags: source.tags,
          score: Math.max(1, source.score * (rank / SLIME_PERCEPTION_INTENSITIES.length))
        });
      }
    }
    return candidates.sort((a, b) => b.score - a.score);
  }

  function accessibleFoodTargetCandidates(slime) {
    if (!slimeHasFeedingNeed(slime)) {
      return [];
    }
    const local = localFoodTargetCandidates(slime);
    if (local.length) {
      return local;
    }
    return traceFoodTargetCandidates(slime);
  }

  function pathToAutonomousTarget(slime, target) {
    const map = ensureLabMap();
    const fromRoomId = slimeEffectiveRoomId(slime);
    const fromCell = objectMapCell(slime) || nearestOpenMapCellInRoom(fromRoomId, labMapRoomAnchor(fromRoomId), { map });
    const toCell = normalizeMapCellForRoom(target.cell, target.roomId, map);
    return roomPathBetween(fromRoomId, target.roomId, {
      map,
      fromCell,
      toCell,
      ignoreDoors: false,
      ignoreDoorSecurity: false,
      requireReachable: true
    });
  }

  function blockedDoorTowardTarget(slime, target) {
    const route = roomRouteBetween(slimeEffectiveRoomId(slime), target.roomId, {
      ignoreDoors: true,
      ignoreDoorSecurity: true,
      requireReachable: true
    });
    if (route.length < 2) {
      return null;
    }
    for (let index = 0; index < route.length - 1; index += 1) {
      const fromRoomId = route[index];
      const toRoomId = route[index + 1];
      const mapDoor = labMapDoorForRoomPair(fromRoomId, toRoomId);
      if (mapDoor && !doorIsOpen(fromRoomId, toRoomId)) {
        return {
          fromRoomId,
          toRoomId,
          door: doorForConnection(fromRoomId, toRoomId),
          state: doorStateLabel(fromRoomId, toRoomId)
        };
      }
    }
    return null;
  }

  function chooseAutonomousFoodTarget(slime) {
    const targets = accessibleFoodTargetCandidates(slime);
    if (!targets.length) {
      return null;
    }
    const reachable = [];
    const blocked = [];
    for (const target of targets) {
      const path = pathToAutonomousTarget(slime, target);
      if (path.length) {
        const distance = Math.max(0, path.length - 1);
        reachable.push({ target, path, value: target.score - distance * 2 });
      } else {
        const block = blockedDoorTowardTarget(slime, target);
        if (block) {
          blocked.push({ target, block, value: target.score });
        }
      }
    }
    if (reachable.length) {
      return reachable.sort((a, b) => b.value - a.value || a.path.length - b.path.length)[0];
    }
    if (blocked.length) {
      return blocked.sort((a, b) => b.value - a.value)[0];
    }
    return null;
  }

  function chooseAutonomousHabitatTarget(slime) {
    const targets = adjacentHabitatTraceTargets(slime)
      .filter((target) => target.improvement >= HABITAT_MOVEMENT_IMPROVEMENT_THRESHOLD);
    if (!targets.length) {
      return null;
    }
    const reachable = [];
    const blocked = [];
    for (const target of targets) {
      const path = pathToAutonomousTarget(slime, target);
      if (path.length) {
        const distance = Math.max(0, path.length - 1);
        reachable.push({ target, path, value: target.score - distance * 2 });
      } else {
        const block = blockedDoorTowardTarget(slime, target);
        if (block) {
          blocked.push({ target, block, value: target.score });
        }
      }
    }
    if (reachable.length) {
      return reachable.sort((a, b) => b.value - a.value || a.path.length - b.path.length)[0];
    }
    if (blocked.length) {
      return blocked.sort((a, b) => b.value - a.value)[0];
    }
    return null;
  }

  function chooseAutonomousWanderTarget(slime) {
    const currentRoomId = slimeEffectiveRoomId(slime);
    const map = ensureLabMap();
    const rng = seedRng(`${state.seed}:wander:${slime.id}:${Math.floor(state.clock / CREATURE_AUTONOMOUS_DECISION_INTERVAL)}`);
    if (rng() > CREATURE_AUTONOMOUS_WANDER_CHANCE) {
      return null;
    }
    const roomIds = [
      currentRoomId,
      ...roomConnectedIds(currentRoomId)
    ];
    const options = [];
    for (const roomId of roomIds) {
      const room = labMapRoom(roomId, map);
      if (!room) {
        continue;
      }
      const cells = roomCellsSortedForPlacement(room, {
        x: room.x + Math.floor(rng() * Math.max(1, room.width)),
        y: room.y + Math.floor(rng() * Math.max(1, room.height))
      }).slice(0, 8);
      for (const cell of cells) {
        if (labMapCellIsDoor(cell, map) || labMapCellIsPathBlocked(cell, { map })) {
          continue;
        }
        const path = roomPathBetween(currentRoomId, roomId, {
          map,
          fromCell: objectMapCell(slime),
          toCell: cell,
          ignoreDoors: false,
          ignoreDoorSecurity: false,
          requireReachable: true
        });
        if (path.length > 1) {
          options.push({
            target: { kind: "wander", id: "", roomId, cell, label: "open floor", score: 1 },
            path,
            value: rng()
          });
          break;
        }
      }
    }
    return options.sort((a, b) => b.value - a.value)[0] || null;
  }

  function startSlimeAutonomousMovement(slime, target, path) {
    if (!slime || !target || !Array.isArray(path) || path.length < 2) {
      return false;
    }
    const map = ensureLabMap();
    const distanceMeters = mapPathTravelDistanceMeters(path, map);
    const movementProfile = slimeMovementProfile(slime);
    const duration = Math.max(CREATURE_AUTONOMOUS_MIN_MOVE_SECONDS, distanceMeters / movementProfile.speedMps);
    const label = target.kind === "wander"
      ? `wandering toward ${roomName(target.roomId)}`
      : target.kind === "contamination"
        ? `moving toward contamination in ${roomName(target.roomId)}`
        : target.kind === "habitat"
          ? `moving toward better habitat in ${roomName(target.roomId)}`
          : target.kind === "threat"
            ? `fleeing from ${target.label || "threat"}`
            : `seeking ${target.label}`;
    slime.autonomousMovement = {
      intent: target.kind === "wander" ? "wander" : target.kind === "habitat" ? "seekHabitat" : target.kind === "threat" ? "flee" : "seekFood",
      label,
      targetKind: target.kind,
      targetId: target.id || "",
      targetLabel: target.label || "",
      fromRoomId: slimeEffectiveRoomId(slime),
      targetRoomId: target.roomId,
      targetCell: path[path.length - 1],
      path,
      distanceMeters,
      speedMps: movementProfile.speedMps,
      baseSpeedMps: movementProfile.baseSpeedMps,
      conditionFactor: movementProfile.conditionFactor,
      movementStyle: movementProfile.movementStyle,
      movementFactors: movementProfile.factors,
      startAt: state.clock,
      arriveAt: state.clock + duration,
      updatedAt: state.clock
    };
    slime.roomActivity = {
      type: target.kind === "wander" ? "moving" : target.kind === "habitat" ? "seekingHabitat" : target.kind === "threat" ? "fleeingThreat" : "seekingFood",
      label,
      roomId: slime.roomId || MAIN_ROOM_ID,
      targetRoomId: target.roomId,
      targetKind: target.kind,
      targetId: target.id || "",
      targetLabel: target.label || "",
      updatedAt: state.clock
    };
    return true;
  }

  function arriveAtAutonomousTarget(slime, movement) {
    const path = movement.path || [];
    const destination = path[path.length - 1];
    const roomId = labMapCellRoomId(destination) || movement.targetRoomId || slime.roomId || MAIN_ROOM_ID;
    slime.mapCell = destination;
    slime.roomId = roomId;
    slime.autonomousMovement = null;
    const target = {
      kind: movement.targetKind,
      id: movement.targetId,
      roomId,
      label: movement.targetLabel
    };
    const activityType = target.kind === "contamination"
      ? "seekingContamination"
      : target.kind === "habitat"
        ? "seekingHabitat"
      : target.kind === "threat"
        ? "threatResponse"
      : target.kind === "wander"
        ? "exploring"
        : "seekingFood";
    slime.roomActivity = {
      type: activityType,
      label: target.kind === "wander" ? "exploring" : target.kind === "contamination" ? "seeking contamination" : target.kind === "habitat" ? "settling into better habitat" : target.kind === "threat" ? `recoiling from ${target.label || "threat"}` : `seeking ${target.label || "food"}`,
      roomId,
      targetRoomId: movement.targetRoomId,
      targetKind: target.kind,
      targetId: target.id || "",
      targetLabel: target.label || "",
      updatedAt: state.clock
    };
    return true;
  }

  function updateSlimeAutonomousMovement(slime) {
    const movement = normalizeSlimeAutonomousMovement(slime.autonomousMovement);
    if (!movement) {
      slime.autonomousMovement = null;
      return 0;
    }
    slime.autonomousMovement = movement;
    const progress = autonomousMovementProgress(movement);
    const currentIndex = clamp(Math.floor(progress * (movement.path.length - 1)), 0, movement.path.length - 1);
    const blocked = firstBlockedDoorOnPath(movement.path, ensureLabMap(), currentIndex);
    if (blocked) {
      setSlimeBlockedDoorActivity(slime, blocked, {
        kind: movement.targetKind,
        id: movement.targetId,
        roomId: movement.targetRoomId,
        label: movement.targetLabel
      });
      return 1;
    }
    const previousKey = mapCellKey(objectMapCell(slime) || movement.path[0]);
    if (state.clock >= movement.arriveAt) {
      arriveAtAutonomousTarget(slime, movement);
      return 1;
    }
    const index = clamp(Math.floor(progress * (movement.path.length - 1)), 0, movement.path.length - 1);
    const cell = movement.path[index];
    const roomId = labMapCellRoomId(cell) || slime.roomId || MAIN_ROOM_ID;
    slime.mapCell = cell;
    slime.roomId = roomId;
    slime.roomActivity = {
      type: "moving",
      label: movement.label,
      roomId,
      targetRoomId: movement.targetRoomId,
      targetKind: movement.targetKind,
      targetId: movement.targetId,
      targetLabel: movement.targetLabel,
      updatedAt: state.clock
    };
    return mapCellKey(cell) === previousKey ? 0 : 1;
  }

  function localAccessibleFoodTarget(slime) {
    if (!slimeHasFeedingNeed(slime)) {
      return null;
    }
    return localFoodTargetCandidates(slime)
      .sort((a, b) => b.score - a.score)[0] || null;
  }

  function consumeFeedingResidueForSlime(slime, target, elapsed) {
    state.feedingResidues = normalizeFeedingResidues(state.feedingResidues);
    const roomId = slimeEffectiveRoomId(slime);
    const residue = state.feedingResidues.find((entry) =>
      entry.id === target.id && entry.location?.type === "room" && entry.location.roomId === roomId
    ) || state.feedingResidues.find((entry) =>
      entry.location?.type === "room" && entry.location.roomId === roomId && entry.amount > 0
    );
    if (!residue) {
      return 0;
    }
    const match = looseFoodMatch(slime, residueFoodTags(residue));
    const effects = LOOSE_FEED_MATCH_EFFECTS[match.quality] || LOOSE_FEED_MATCH_EFFECTS.bad;
    slime.accessibleFeedingProgress = Math.max(0, Number(slime.accessibleFeedingProgress) || 0)
      + CREATURE_AUTONOMOUS_RESIDUE_UNITS_PER_HOUR * effects.rate * secondsToHours(elapsed);
    const units = Math.min(residue.amount, Math.floor(slime.accessibleFeedingProgress));
    slime.roomActivity = {
      type: "feedingResidue",
      label: `feeding on ${feedingResidueLabel(residue.typeKey).toLowerCase()}`,
      roomId,
      targetKind: "residue",
      targetId: residue.id,
      targetLabel: feedingResidueLabel(residue.typeKey),
      updatedAt: state.clock
    };
    if (units <= 0) {
      return 0;
    }
    slime.accessibleFeedingProgress -= units;
    residue.amount -= units;
    applyLooseFoodEffects(slime, units, match, {
      roomId,
      label: feedingResidueLabel(residue.typeKey),
      tags: residueFoodTags(residue)
    });
    if (residue.amount <= 0) {
      state.feedingResidues = state.feedingResidues.filter((entry) => entry.id !== residue.id);
    }
    return 1;
  }

  function consumeWasteForLooseSlime(slime, elapsed) {
    const roomId = slimeEffectiveRoomId(slime);
    if (resourceAmountInRoom("waste", roomId) <= 0 || roomId === STORAGE_ROOM_ID) {
      return 0;
    }
    const tags = ["waste", "contaminated", "hazardous", "chemical"];
    const match = looseFoodMatch(slime, tags);
    const effects = LOOSE_FEED_MATCH_EFFECTS[match.quality] || LOOSE_FEED_MATCH_EFFECTS.bad;
    slime.accessibleFeedingProgress = Math.max(0, Number(slime.accessibleFeedingProgress) || 0)
      + CREATURE_AUTONOMOUS_WASTE_UNITS_PER_HOUR * effects.rate * secondsToHours(elapsed);
    const units = Math.min(resourceAmountInRoom("waste", roomId), Math.floor(slime.accessibleFeedingProgress));
    slime.roomActivity = {
      type: "feedingWaste",
      label: "feeding on loose waste",
      roomId,
      targetKind: "waste",
      targetId: "waste",
      targetLabel: "loose waste",
      updatedAt: state.clock
    };
    if (units <= 0) {
      return 0;
    }
    slime.accessibleFeedingProgress -= units;
    spendWaste(units, roomId);
    applyLooseFoodEffects(slime, units, match, {
      roomId,
      label: "loose waste",
      tags
    });
    return 1;
  }

  function consumePhysicalResourceStackForSlime(slime, target, elapsed) {
    const roomId = slimeEffectiveRoomId(slime);
    const stack = ensurePhysicalItemStacks().find((entry) => entry.id === target.id);
    if (!stack || stack.section !== "resources" || stack.roomId !== roomId || stack.quantity <= 0 || !physicalStackExposed(stack)) return 0;
    const tags = physicalResourceFoodTags(stack.key);
    const match = looseFoodMatch(slime, tags);
    const effects = LOOSE_FEED_MATCH_EFFECTS[match.quality] || LOOSE_FEED_MATCH_EFFECTS.bad;
    slime.accessibleFeedingProgress = Math.max(0, Number(slime.accessibleFeedingProgress) || 0)
      + CREATURE_AUTONOMOUS_WASTE_UNITS_PER_HOUR * effects.rate * secondsToHours(elapsed);
    const units = Math.min(stack.quantity, Math.floor(slime.accessibleFeedingProgress));
    slime.roomActivity = {
      type: "feedingStockpile",
      label: `feeding on exposed ${physicalStackLabel(stack).toLowerCase()}`,
      roomId,
      targetKind: "physicalStack",
      targetId: stack.id,
      targetLabel: physicalStackLabel(stack),
      updatedAt: state.clock
    };
    if (units <= 0) return 0;
    slime.accessibleFeedingProgress -= units;
    ensureRoomStockpiles();
    const localMap = state.roomStockpiles?.[roomId]?.resources || {};
    localMap[stack.key] = Math.max(0, (Number(localMap[stack.key]) || 0) - units);
    if (localMap[stack.key] <= 0) delete localMap[stack.key];
    state.resources[stack.key] = Math.max(0, (Number(state.resources[stack.key]) || 0) - units);
    stack.quantity -= units;
    if (scientistObservesRoom(roomId)) {
      stack.knownQuantity = stack.quantity;
      stack.observedAt = state.clock;
    }
    applyLooseFoodEffects(slime, units, match, { roomId, label: physicalStackLabel(stack), tags });
    if (stack.quantity <= 0 && scientistObservesRoom(roomId)) {
      state.physicalItemStacks = ensurePhysicalItemStacks().filter((entry) => entry.id !== stack.id);
    }
    return 1;
  }

  function feedLooseSlimeOnCorpse(slime, target, elapsed) {
    const corpse = findCorpse(target.id);
    if (!corpse || !["room", "overflow"].includes(corpse.storage) || (corpse.roomId || MAIN_ROOM_ID) !== slimeEffectiveRoomId(slime)) {
      return 0;
    }
    const feeding = corpseFeedingRateForSlime(slime, corpse);
    slime.roomActivity = {
      type: "feedingCorpse",
      label: `feeding on ${corpse.name} remains`,
      roomId: slimeEffectiveRoomId(slime),
      targetKind: "corpse",
      targetId: corpse.id,
      targetLabel: `${corpse.name} remains`,
      updatedAt: state.clock
    };
    if (feeding.rate <= 0) {
      adjustSlimeStat(slime, "stress", 0.1 * secondsToHours(elapsed));
      return 0;
    }
    const rawNutritionGain = feeding.rate * secondsToDays(elapsed);
    const nutritionGain = adjustedSlimeNutritionGain(slime, rawNutritionGain);
    if (nutritionGain <= 0) {
      return 0;
    }
    adjustSlimeStat(slime, "nutrition", nutritionGain);
    adjustSlimeStat(slime, "currentMass", nutritionGain * 0.2);
    adjustSlimeStat(slime, "stress", -nutritionGain * 0.1);
    corpse.consumedProgress = clamp((Number(corpse.consumedProgress) || 0) + nutritionGain * feeding.consumption, 0, 100);
    accumulateCorpseFeedingResidue(slime, corpse, feeding, nutritionGain);
    if (!corpse.feedingNoticed && scientistObservesRoom(slimeEffectiveRoomId(slime))) {
      corpse.feedingNoticed = true;
      addEvent(`${slime.name} began feeding on ${corpse.name} remains in ${corpseLocationLabel(corpse)}.`);
    }
    if (corpse.consumedProgress >= 100) {
      addEvent(`${corpse.name} remains were fully consumed in ${corpseLocationLabel(corpse)}.`);
      removeCorpseRecord(corpse.id);
    }
    return 1;
  }

  function updateAccessibleSlimeFeeding(slime, elapsed) {
    const target = localAccessibleFoodTarget(slime);
    if (!target) {
      return 0;
    }
    if (target.kind === "residue") {
      return consumeFeedingResidueForSlime(slime, target, elapsed);
    }
    if (target.kind === "waste") {
      return consumeWasteForLooseSlime(slime, elapsed);
    }
    if (target.kind === "physicalStack") {
      return consumePhysicalResourceStackForSlime(slime, target, elapsed);
    }
    if (target.kind === "corpse") {
      return feedLooseSlimeOnCorpse(slime, target, elapsed);
    }
    return 0;
  }

  function applyLooseThreatResponseActivity(slime) {
    const response = evaluateSlimeThreatResponse(slime);
    if (!["pained", "panicked", "desperate"].includes(response.state) || response.intent === "feedDesperate") {
      return false;
    }
    const labels = {
      hide: "hiding under stress",
      freeze: "freezing under stress",
      flee: "recoiling from threat",
      lashOut: "lashing out defensively",
      recover: "contracting around injury",
      endure: "enduring threat"
    };
    slime.roomActivity = {
      type: "threatResponse",
      label: labels[response.intent] || `${response.label.toLowerCase()} threat response`,
      roomId: slimeEffectiveRoomId(slime),
      targetKind: "self",
      targetId: slime.id,
      targetLabel: response.label,
      updatedAt: state.clock
    };
    if (response.intent === "flee") {
      awardCreatureSkillXp(slime, "evasion", CREATURE_PRACTICE_XP.evasion, "fleeing threat", { outcome: "partial" });
      rememberCreatureExperience(slime, "fledThreat", 3, response.reasons?.[0] || response.label);
    }
    return true;
  }

  function fleeTargetForCombatDecision(slime, decision) {
    if (!slimeIsUncontained(slime)) {
      return null;
    }
    const current = objectMapCell(slime);
    const threat = cleanMapCell(decision?.target?.cell);
    if (!current || !threat) {
      return null;
    }
    const currentDistance = mapCellDistance(current, threat);
    const candidates = labMapNeighborCells(current, {
      ignoreDoors: false,
      ignoreDoorSecurity: false,
      requireReachable: true
    })
      .map((cell) => ({
        cell,
        distance: mapCellDistance(cell, threat)
      }))
      .filter((entry) => entry.distance > currentDistance)
      .sort((a, b) => b.distance - a.distance || a.cell.y - b.cell.y || a.cell.x - b.cell.x);
    const best = candidates[0]?.cell;
    if (!best) {
      return null;
    }
    const roomId = labMapCellRoomId(best) || slimeEffectiveRoomId(slime);
    return {
      kind: "threat",
      id: decision?.target?.id || "",
      label: decision?.target?.label || "threat",
      roomId,
      cell: best
    };
  }

  function applyLooseCombatDecisionActivity(slime) {
    if (!slimeIsUncontained(slime) || slimeAutonomousMovementActive(slime)) {
      return false;
    }
    const decision = currentSlimeCombatDecision(slime);
    if (!decision || ["none", "avoid"].includes(decision.intent)) {
      return false;
    }
    const targetLabel = decision.target?.label || "nearby target";
    if (SLIME_COMBAT_ACTION_INTENTS.has(decision.intent)) {
      slime.roomActivity = {
        type: "combatAttack",
        combatIntent: decision.intent,
        label: decision.intent === "feedAttack" ? `trying to feed on ${targetLabel}` : `attacking ${targetLabel}`,
        roomId: slimeEffectiveRoomId(slime),
        targetKind: decision.target?.kind || "target",
        targetId: decision.target?.id || "",
        targetLabel,
        updatedAt: state.clock
      };
      return true;
    }
    if (decision.intent === "flee") {
      const target = fleeTargetForCombatDecision(slime, decision);
      if (target) {
        const path = [objectMapCell(slime), target.cell].filter(Boolean);
        if (startSlimeAutonomousMovement(slime, target, path)) {
          awardCreatureSkillXp(slime, "evasion", CREATURE_PRACTICE_XP.evasion, "fleeing combat", { outcome: "partial" });
          rememberCreatureExperience(slime, "fledThreat", 3, decision.reasons?.[0] || "combat threat");
          return true;
        }
      }
      slime.roomActivity = {
        type: "threatResponse",
        combatIntent: "freeze",
        label: `cornered by ${targetLabel}`,
        roomId: slimeEffectiveRoomId(slime),
        targetKind: decision.target?.kind || "target",
        targetId: decision.target?.id || "",
        targetLabel,
        updatedAt: state.clock
      };
      return true;
    }
    const responseOverridesActivity = decision.intent === "panic"
      || (decision.intent === "freeze" && decision.score >= 55)
      || (decision.intent === "threaten" && decision.score >= 40)
      || (decision.intent === "defend" && decision.score >= 40);
    if (responseOverridesActivity) {
      const labels = {
        freeze: `freezing near ${targetLabel}`,
        panic: `panicking near ${targetLabel}`,
        threaten: `threatening ${targetLabel}`,
        defend: `defending against ${targetLabel}`
      };
      slime.roomActivity = {
        type: "threatResponse",
        combatIntent: decision.intent,
        label: labels[decision.intent] || `watching ${targetLabel}`,
        roomId: slimeEffectiveRoomId(slime),
        targetKind: decision.target?.kind || "target",
        targetId: decision.target?.id || "",
        targetLabel,
        updatedAt: state.clock
      };
      return true;
    }
    return false;
  }

  function chooseAutonomousSlimeActivity(slime) {
    if (applyLooseCombatDecisionActivity(slime)) {
      return true;
    }
    const food = chooseAutonomousFoodTarget(slime);
    if (food?.block) {
      setSlimeBlockedDoorActivity(slime, food.block, food.target);
      return true;
    }
    if (food?.target && food.path?.length) {
      if (food.path.length <= 1) {
        slime.roomActivity = {
          type: food.target.kind === "contamination" ? "seekingContamination" : "seekingFood",
          label: food.target.kind === "contamination" ? "seeking contamination" : `seeking ${food.target.label}`,
          roomId: slimeEffectiveRoomId(slime),
          targetRoomId: food.target.roomId,
          targetKind: food.target.kind,
          targetId: food.target.id || "",
          targetLabel: food.target.label || "",
          updatedAt: state.clock
        };
        return true;
      }
      return startSlimeAutonomousMovement(slime, food.target, food.path);
    }
    const habitat = chooseAutonomousHabitatTarget(slime);
    if (habitat?.block) {
      setSlimeBlockedDoorActivity(slime, habitat.block, habitat.target);
      return true;
    }
    if (habitat?.target && habitat.path?.length) {
      if (habitat.path.length <= 1) {
        slime.roomActivity = {
          type: "seekingHabitat",
          label: "settling into better habitat",
          roomId: slimeEffectiveRoomId(slime),
          targetRoomId: habitat.target.roomId,
          targetKind: "habitat",
          targetId: habitat.target.id || "",
          targetLabel: habitat.target.label || "",
          updatedAt: state.clock
        };
        return true;
      }
      return startSlimeAutonomousMovement(slime, habitat.target, habitat.path);
    }
    if (applyLooseThreatResponseActivity(slime)) {
      return true;
    }
    const wander = chooseAutonomousWanderTarget(slime);
    if (wander?.target && wander.path?.length > 1) {
      return startSlimeAutonomousMovement(slime, wander.target, wander.path);
    }
    return false;
  }

  function updateUncontainedSlimeBehavior(minutes) {
    const elapsed = Math.max(0, Number(minutes) || 0);
    if (!elapsed) {
      return 0;
    }

    let changes = 0;
    for (const slime of state.slimes || []) {
      if (!slimeIsUncontained(slime) || slime.status === "dead") {
        continue;
      }
      slime.roomId ||= MAIN_ROOM_ID;
      slime.autonomousMovement = normalizeSlimeAutonomousMovement(slime.autonomousMovement);
      const info = slimeContaminationTraitInfo(slime);
      const currentRoom = roomById(slime.roomId);
      if (!currentRoom) {
        slime.roomId = MAIN_ROOM_ID;
      }

      if (slime.autonomousMovement) {
        changes += updateSlimeAutonomousMovement(slime);
        if (slime.autonomousMovement || slime.roomActivity?.type === "pressingClosedDoor") {
          if (slime.roomActivity?.targetKind === "contamination") {
            recordCleanupObservation(slime, "seekingContamination", elapsed, slime.roomId);
          } else if (slime.roomActivity?.type === "pressingClosedDoor") {
            recordCleanupObservation(slime, "pressingClosedDoor", elapsed, slime.roomId);
          }
          continue;
        }
      }

      if (applyLooseCombatDecisionActivity(slime)) {
        slime.nextAutonomousDecisionAt = state.clock + CREATURE_AUTONOMOUS_DECISION_INTERVAL;
        changes += 1;
        continue;
      }

      changes += updateAccessibleSlimeFeeding(slime, elapsed);

      const room = roomById(slime.roomId);
      const contamination = room?.attributes?.contamination;
      const current = Number(contamination?.current) || 0;
      if (room && contamination && info.eatsContamination && current > OUT_OF_CONTAINER_CONTAMINATION_FLOOR) {
        const eatRate = OUT_OF_CONTAINER_CONTAMINATION_CLEAN_PER_HOUR * roomEffectScale(room) * secondsToHours(elapsed);
        const drained = Math.min(eatRate, current - OUT_OF_CONTAINER_CONTAMINATION_FLOOR);
        if (drained > 0) {
          const before = contamination.current;
          contamination.current = clamp(contamination.current - drained, 0, 100);
          adjustSlimeStat(slime, "nutrition", drained * 0.4);
          adjustSlimeStat(slime, "stress", -drained * 0.05);
          slime.roomActivity = {
            type: "feedingOnContamination",
            label: "feeding on contamination",
            roomId: slime.roomId,
            targetKind: "contamination",
            targetId: room.id,
            targetLabel: "visible contamination",
            updatedAt: state.clock
          };
          recordCleanupObservation(slime, "feedingOnContamination", elapsed, room.id);
          if (before > OUT_OF_CONTAINER_CONTAMINATION_FLOOR && contamination.current <= OUT_OF_CONTAINER_CONTAMINATION_FLOOR && !room.biologicalCleanupClearedNotifiedAt) {
            const observation = ensureCleanupObservation(slime);
            observation.clearEvents += 1;
            room.biologicalCleanupClearedNotifiedAt = state.clock;
            if (scientistObservesRoom(room.id)) {
              addEvent(`${room.name} visible contamination cleared by biological cleanup.`);
            }
          } else if (contamination.current > OUT_OF_CONTAINER_CONTAMINATION_FLOOR + 0.5) {
            room.biologicalCleanupClearedNotifiedAt = 0;
          }
          if (Math.abs(before - contamination.current) >= 0.01) {
            changes += 1;
          }
        }
        continue;
      }

      if (state.clock >= finiteTime(slime.nextAutonomousDecisionAt, 0)) {
        if (chooseAutonomousSlimeActivity(slime)) {
          slime.nextAutonomousDecisionAt = state.clock + CREATURE_AUTONOMOUS_DECISION_INTERVAL;
          if (slime.roomActivity?.type === "seekingContamination" || slime.roomActivity?.targetKind === "contamination") {
            recordCleanupObservation(slime, "seekingContamination", elapsed, slime.roomId);
          } else if (slime.roomActivity?.type === "pressingClosedDoor") {
            recordCleanupObservation(slime, "pressingClosedDoor", elapsed, slime.roomId);
          }
          changes += 1;
          continue;
        }
        slime.nextAutonomousDecisionAt = state.clock + CREATURE_AUTONOMOUS_DECISION_INTERVAL;
      }

      if (slimeHuntingInclination(slime)) {
        slime.roomActivity = {
          type: "hunting",
          label: "hunting sensed prey",
          roomId: slime.roomId,
          updatedAt: state.clock
        };
        changes += 1;
        continue;
      }

      if (info.spreadsContamination) {
        const room = roomById(slime.roomId);
        const contamination = room?.attributes?.contamination;
        if (room && contamination) {
          const before = contamination.current;
          const residue = OUT_OF_CONTAINER_RESIDUE_PER_HOUR * roomEffectScale(room) * secondsToHours(elapsed);
          contamination.current = clamp(contamination.current + residue, 0, 100);
          slime.roomActivity = {
            type: "leavingResidue",
            label: "leaving residue",
            roomId: slime.roomId,
            updatedAt: state.clock
          };
          recordCleanupObservation(slime, "leavingResidue", elapsed, room.id);
          if (contamination.current > OUT_OF_CONTAINER_CONTAMINATION_FLOOR + 0.5) {
            room.biologicalCleanupClearedNotifiedAt = 0;
          }
          if (Math.abs(before - contamination.current) >= 0.01) {
            changes += 1;
          }
        }
        continue;
      }

      slime.roomActivity ||= {
        type: "exploring",
        label: "exploring",
        roomId: slime.roomId,
        updatedAt: state.clock
      };
    }
    return changes;
  }

  function socialStressRatePerDay(social) {
    if (!social?.nonKinCount) {
      return 0;
    }
    if (social.pressureBand === "critical") return 4;
    if (social.pressureBand === "high") return 2;
    if (social.pressureBand === "moderate") return 0.75;
    if (social.pressureBand === "low") return 0.2;
    return 0;
  }

  function updateSlimeSocialEffects(elapsed) {
    const seconds = Math.max(0, Number(elapsed) || 0);
    if (!seconds) {
      return 0;
    }
    let changes = 0;
    for (const slime of state.slimes || []) {
      if (!slime || slime.status === "dead") {
        continue;
      }
      const social = evaluateSlimeSocialContext(slime);
      const stressRate = socialStressRatePerDay(social);
      if (stressRate <= 0) {
        continue;
      }
      const before = slimeStat(slime, "stress").current;
      adjustSlimeStat(slime, "stress", stressRate * secondsToDays(seconds));
      if (Math.abs(slimeStat(slime, "stress").current - before) >= 0.01) {
        changes += 1;
      }
    }
    return changes;
  }

  function updateSlimeMetabolism(minutes) {
    const elapsed = Math.max(0, Number(minutes) || 0);
    if (!elapsed) {
      return 0;
    }
    let changes = 0;
    for (const slime of [...(state.slimes || [])]) {
      if (!slime || slime.status === "dead") {
        continue;
      }
      const massBefore = slimeStat(slime, "currentMass").current;
      const pressureBefore = slimeStat(slime, "divisionPressure").current;
      const sustained = updateEnvironmentalSustenance(slime, elapsed);
      const regrew = updateSlimeMassRegrowth(slime, elapsed);
      const pressureChanged = updateDivisionPressure(slime, elapsed, massBefore >= 100);
      const split = tryNaturalSplit(slime);
      if (sustained || regrew || pressureChanged || split) {
        changes += 1;
      }
      const massAfter = slimeStat(slime, "currentMass").current;
      const pressureAfter = slimeStat(slime, "divisionPressure").current;
      if (massBefore < 100 && massAfter >= 100 && pressureAfter <= pressureBefore) {
        addEvent(`${slime.name} regrew to full mass.`);
      }
    }
    return changes;
  }

  /*  ─────────────────────────────────────────────────────────────
   *  Phase 4: Immediate-environment source for environmental feeding
   *  Released slime  → room.attributes
   *  Contained slime → container.environment (including synthesis tube)
   *  ─────────────────────────────────────────────────────────────
   */

  function environmentalSustenanceSource(slime) {
    if (!slime) return null;
    const room = roomById(slime.roomId || MAIN_ROOM_ID);
    if (!room) return null;

    if (slime.status === "contained" && slime.containerId) {
      const container = containerById(slime.containerId);
      if (container) {
        if (!container.environment || Object.keys(container.environment).length === 0) {
          container.environment = normalizeContainerEnvironment(container.environment);
        }
        return {
          type: "container",
          label: container.name || container.type || "container",
          attributes: container.environment,
          container,
          room
        };
      }
    }

    return {
      type: "room",
      label: room.name || "room",
      attributes: roomEnvironmentAttributes(room.id, objectMapCell(slime)),
      room
    };
  }

  function updateEnvironmentalSustenance(slime, minutes) {
    const profile = environmentalSustenanceProfile(slime);
    const source = profile ? environmentalSustenanceSource(slime) : null;
    const room = source?.room || null;
    const supply = source ? environmentalSustenanceSupply({ attributes: source.attributes }, profile) : null;
    const rate = supply?.rate || 0;
    const nutrition = slimeStat(slime, "nutrition");
    const mass = slimeStat(slime, "currentMass");
    if (!profile || !source || !room || !supply || rate <= 0 || (nutrition.current >= nutrition.max && mass.current >= mass.max)) {
      return false;
    }
    const before = nutrition.current;
    const attribute = source.attributes[profile.attributeKey];
    if (!attribute) {
      return false;
    }
    const beforeBand = roomAttributeBand(profile.attributeKey, attribute.current);
    const possibleGain = Math.min(nutrition.max - nutrition.current, minutes * (rate / slimeFoodDemandModifier(slime)));
    const maxDrain = Math.max(0, attribute.current - profile.floor);
    const drainPerNutrition = Math.max(0.1, profile.drainPerNutrition);
    const roomLimitedGain = Math.min(possibleGain, maxDrain / drainPerNutrition);
    const gain = Math.max(0, roomLimitedGain);
    if (gain <= 0) {
      return false;
    }
    adjustSlimeStat(slime, "nutrition", gain);
    const drained = gain * drainPerNutrition;
    if (source.type === "room") {
      adjustRoomAttribute(room.id, profile.attributeKey, -drained);
    } else {
      /* Contained slime: drain container interior, not the room */
      source.attributes[profile.attributeKey].current = clamp(
        (source.attributes[profile.attributeKey].current || 0) - drained,
        0, 100
      );
    }
    const changed = slimeStat(slime, "nutrition").current !== before;
    const afterAttribute = source.attributes[profile.attributeKey];
    const afterBand = roomAttributeBand(profile.attributeKey, afterAttribute.current);
    if (changed && slime.revealed?.sustenance && beforeBand.label !== afterBand.label) {
      const def = ROOM_ATTRIBUTE_BY_KEY[profile.attributeKey];
      addEvent(`${slime.name} ${profile.actionLabel} from ${source.label}. ${def.label} dropped to ${afterBand.label}.`);
    }
    return changed;
  }

  function environmentalSustenanceRate(slime) {
    const profile = environmentalSustenanceProfile(slime);
    if (!profile) return 0;
    const source = environmentalSustenanceSource(slime);
    if (!source) return 0;
    /* Pass a room-like object with the correct environment (container interior or room) */
    return environmentalSustenanceSupply({ attributes: source.attributes }, profile).rate / slimeFoodDemandModifier(slime);
  }

  function environmentalSustenanceProfile(slime) {
    if (!slime?.genome) {
      return null;
    }
    const tags = new Set(evaluateGenome(slime.genome).traits.sustenance.meta?.tags || []);
    if (!tags.has("environmental")) {
      return null;
    }
    return ENVIRONMENTAL_SUSTENANCE_DEFS.find((profile) => profile.matchTags.some((tag) => tags.has(tag))) || null;
  }

  function environmentalSustenanceSupply(room, profile) {
    const attribute = room?.attributes?.[profile?.attributeKey];
    if (!attribute) {
      return { availability: 0, rate: 0 };
    }
    const current = clamp(Number(attribute.current) || 0, 0, 100);
    const floor = clamp(Number(profile.floor) || 0, 0, 100);
    const fullAt = Math.max(floor + 1, clamp(Number(profile.fullAt) || 100, 0, 100));
    const rawAvailability = clamp((current - floor) / (fullAt - floor), 0, 1);
    if (rawAvailability <= 0) {
      return { availability: 0, rate: 0 };
    }
    const availability = Math.pow(rawAvailability, ENVIRONMENTAL_SUSTENANCE_AVAILABILITY_POWER);
    return {
      availability,
      rate: (ENVIRONMENTAL_SUSTENANCE_NUTRITION_PER_DAY / SECONDS_PER_DAY) * availability
    };
  }

  function hasAvailableEnvironmentalSustenance(slime) {
    const nutrition = slimeStat(slime, "nutrition");
    const mass = slimeStat(slime, "currentMass");
    if (nutrition.current >= nutrition.max && mass.current >= mass.max) {
      return true;
    }
    return environmentalSustenanceRate(slime) > 0;
  }


  function environmentalSustenanceStatus(slime) {
    const profile = environmentalSustenanceProfile(slime);
    if (!profile) {
      return "";
    }
    const source = environmentalSustenanceSource(slime);
    if (!source) {
      return "";
    }
    const def = ROOM_ATTRIBUTE_BY_KEY[profile.attributeKey];
    const attribute = source.attributes[profile.attributeKey];
    const band = roomAttributeBand(profile.attributeKey, attribute.current);
    /* Pass a room-like object with the correct environment (container interior or room) */
    const supply = environmentalSustenanceSupply({ attributes: source.attributes }, profile);
    if (supply.rate <= 0) {
      return `${def.label}: depleted`;
    }
    if (supply.availability < 0.2) {
      return `${def.label}: barely feeding`;
    }
    // Check if we're dealing with a container interior
    if (source.type === "container") {
      // For contained slimes, show "from {container} interior"
      return `Absorbing ${def.label.toLowerCase()} from ${source.label || source.container?.name || "container"} interior.`;
    } else {
      // For room-based slimes, show "from {room name}"
      return `Absorbing ${def.label.toLowerCase()} from ${source.label || source.room?.name || "room"}.`;
    }
  }

  function environmentalSustenanceLabel(slime) {
    const profile = environmentalSustenanceProfile(slime);
    if (!profile) {
      return "";
    }
    return `${profile.sourceLabel} feeder`;
  }

  function isEnvironmentalSustenance(slime) {
    return Boolean(environmentalSustenanceProfile(slime));
  }

  function environmentalSustenanceIsFull(slime) {
    const nutrition = slimeStat(slime, "nutrition");
    const mass = slimeStat(slime, "currentMass");
    return nutrition.current >= nutrition.max && mass.current >= mass.max;
  }

  function environmentCanCurrentlyFeed(slime) {
    if (!isEnvironmentalSustenance(slime)) {
      return false;
    }
    if (environmentalSustenanceIsFull(slime)) {
      return true;
    }
    return hasAvailableEnvironmentalSustenance(slime);
  }

  function updateSlimeMassRegrowth(slime, minutes) {
    const elapsedMinutes = secondsToMinutes(minutes);
    const mass = slimeStat(slime, "currentMass");
    const nutrition = slimeStat(slime, "nutrition");
    if (mass.current >= mass.max || nutrition.current <= MASS_REGROWTH_NUTRITION_FLOOR) {
      return false;
    }
    const evaluated = evaluateGenome(slime.genome);
    const growthMinutes = Math.max(1, Number(evaluated.traits.growth.meta?.growthMinutes) || 12);
    const growthRate = mass.max / (growthMinutes * 12);
    const availableNutrition = Math.max(0, nutrition.current - MASS_REGROWTH_NUTRITION_FLOOR);
    const nutritionCost = adjustedMassRegrowthNutritionCost(slime);
    const gain = Math.min(
      mass.max - mass.current,
      elapsedMinutes * growthRate,
      availableNutrition / nutritionCost
    );
    if (gain <= 0) {
      return false;
    }
    adjustSlimeStat(slime, "currentMass", gain);
    adjustSlimeStat(slime, "nutrition", -gain * nutritionCost);
    return true;
  }

  function updateDivisionPressure(slime, minutes, startedAtFullMass) {
    const pressure = slimeStat(slime, "divisionPressure");
    const conditions = divisionReadiness(slime);
    const required = divisionPressureDuration(slime);
    if (conditions.ready && startedAtFullMass) {
      slime.splitBlocked = false;
      const gain = minutes * (pressure.max / required);
      const before = pressure.current;
      adjustSlimeStat(slime, "divisionPressure", gain);
      const after = slimeStat(slime, "divisionPressure").current;
      if (before < pressure.max && after >= pressure.max) {
        addEvent(`${slime.name} reached natural division pressure.`);
      }
      return after !== before;
    }
    if (pressure.current <= 0) {
      slime.splitBlocked = false;
      return false;
    }
    const decay = minutes * (pressure.max / Math.max(minutesToSeconds(60), required / 2));
    adjustSlimeStat(slime, "divisionPressure", -decay);
    slime.splitBlocked = false;
    return true;
  }

  function divisionReadiness(slime) {
    if (!slime || slime.status === "dead" || !slime.mature) {
      return { ready: false, reason: "immature" };
    }
    if (slimeStat(slime, "currentMass").current < 100) {
      return { ready: false, reason: "not full mass" };
    }
    if (slimeStat(slime, "nutrition").current < DIVISION_NUTRITION_THRESHOLD) {
      return { ready: false, reason: "not fed enough" };
    }
    if (slimeStat(slime, "bodyIntegrity").current < DIVISION_INTEGRITY_THRESHOLD) {
      return { ready: false, reason: "body integrity too low" };
    }
    if (slimeStat(slime, "stress").current > DIVISION_STRESS_LIMIT) {
      return { ready: false, reason: "too stressed" };
    }
    return { ready: true, reason: "" };
  }

  function divisionPressureMinutes(slime) {
    const evaluated = evaluateGenome(slime.genome);
    const brood = Math.max(1, Number(evaluated.traits.brood.meta?.count) || 1);
    const growth = Math.max(1, Number(evaluated.traits.growth.meta?.growthMinutes) || 12);
    const stabilityRisk = Math.max(1, Number(evaluated.traits.stability.meta?.risk) || 5);
    return clamp(Math.round(360 + brood * 90 + growth * 4 + Math.max(0, stabilityRisk - 3) * 30), 360, 2880);
  }

  function divisionPressureDuration(slime) {
    return minutesToSeconds(divisionPressureMinutes(slime));
  }

  function tryNaturalSplit(slime) {
    if (slimeStat(slime, "divisionPressure").current < 100 || !divisionReadiness(slime).ready) {
      return false;
    }
    const evaluated = evaluateGenome(slime.genome);
    const broodCount = Math.max(1, Number(evaluated.traits.brood.meta?.count) || 1);
    const bodyCount = broodCount + 1;
    const massShare = slimeStat(slime, "currentMass").current / bodyCount;
    const nutritionShare = slimeStat(slime, "nutrition").current / bodyCount;
    const parentIntegrity = slimeStat(slime, "bodyIntegrity").current;
    const parentStress = slimeStat(slime, "stress").current;
    const rng = seedRng(`${state.seed}:split:${slime.id}:${state.clock}:${state.nextSlimeNumber}`);
    const growthMinutes = Math.max(4, Number(evaluated.traits.growth.meta?.growthMinutes) || 12);
    const created = [];
    const broodId = cleanLineageId(`split-${slime.id}-${state.clock}-${state.nextSlimeNumber}`);
    for (let i = 0; i < broodCount; i += 1) {
      const childGenome = naturalSplitGenome(slime, rng, i);
      const growthSeconds = Math.round(minutesToSeconds(growthMinutes * (0.75 + rng() * 0.5)));
      const child = createSlime(childGenome, "Split", {
        mature: false,
        matureAt: state.clock + growthSeconds,
        status: slime.status,
        containerId: slime.containerId,
        roomId: slime.roomId,
        parentIds: [slime.id],
        broodId,
        stats: {
          bodyIntegrity: { current: clamp(parentIntegrity - 5, 20, 100), max: 100 },
          nutrition: { current: nutritionShare, max: 100 },
          currentMass: { current: massShare, max: 100 },
          divisionPressure: { current: 0, max: 100 },
          stress: { current: clamp(parentStress + 5, 0, 100), max: 100 }
        }
      });
      created.push(child);
      createTask({
        type: "mature",
        label: `Mature ${child.name}`,
        duration: Math.max(1, child.matureAt - state.clock),
        data: { slimeId: child.id }
      });
    }
    setSlimeStat(slime, "currentMass", massShare);
    setSlimeStat(slime, "nutrition", nutritionShare);
    adjustSlimeStat(slime, "stress", Math.min(20, 4 + broodCount));
    setSlimeStat(slime, "divisionPressure", 0);
    slime.splitBlocked = false;
    addEvent(`${slime.name} split into ${broodCount} offspring, dividing its mass across ${bodyCount} bodies.`);
    return created.length > 0;
  }

  function naturalSplitGenome(slime, rng, offset) {
    const evaluated = evaluateGenome(slime.genome);
    const brood = Math.max(1, Number(evaluated.traits.brood.meta?.count) || 1);
    const stabilityRisk = Math.max(1, Number(evaluated.traits.stability.meta?.risk) || 5);
    let mutationCount = 1;
    if (rng() < 0.25 + stabilityRisk * 0.035) {
      mutationCount += 1;
    }
    if (brood >= 5 && rng() < 0.35) {
      mutationCount += 1;
    }
    return mutateGenome(slime.genome, rng, mutationCount + (offset % 2 === 0 && rng() < 0.2 ? 1 : 0));
  }

  function corpseProcessingInventoryRecovery(corpse) {
    const freshness = corpseFreshness(corpse);
    if (freshness === "ruined") {
      return { key: "ruinedOrganicMatter", amount: 1, source: "corpse processing" };
    }
    return { key: "biomass", amount: 1, source: "corpse processing" };
  }

  function addCorpseProcessingInventoryRecovery(corpse, roomId = STORAGE_ROOM_ID) {
    const recovery = corpseProcessingInventoryRecovery(corpse);
    return addInventoryItem(recovery.key, recovery.amount, recovery.source, roomId);
  }

  function updateCorpseProcessingJobs(elapsed) {
    let changes = 0;
    const workers = state.slimes.filter((slime) => {
      normalizeSlimeJob(slime);
      return slime.job === "corpse" && canWorkJob(slime);
    });
    const reserved = new Set();
    for (const slime of workers) {
      if (isCorpseProcessingTargetForSlime(slime, findCorpse(slime.jobTargetCorpseId)) && !reserved.has(slime.jobTargetCorpseId)) {
        reserved.add(slime.jobTargetCorpseId);
      } else {
        slime.jobTargetCorpseId = null;
        slime.jobProgress = 0;
      }
    }
    for (const slime of workers) {
      if (!slime.jobTargetCorpseId && assignCorpseTarget(slime, reserved)) {
        changes += 1;
      }
      if (!slime.jobTargetCorpseId) {
        continue;
      }
      let remaining = elapsed;
      while (remaining > 0 && slime.jobTargetCorpseId) {
        const target = findCorpse(slime.jobTargetCorpseId);
        if (!isCorpseProcessingTargetForSlime(slime, target)) {
          reserved.delete(slime.jobTargetCorpseId);
          slime.jobTargetCorpseId = null;
          slime.jobProgress = 0;
          slime.jobNutritionGained = 0;
          changes += 1;
          break;
        }
        const suitability = corpseProcessingSuitability(slime);
        const effects = corpseProcessingEffects(slime, target, suitability);
        const duration = corpseProcessingDuration(slime);
        const needed = Math.max(0, duration - slime.jobProgress);
        if (remaining < needed) {
          const fromProgress = slime.jobProgress;
          slime.jobProgress += remaining;
          applyCorpseProcessingNutrition(slime, effects, fromProgress, slime.jobProgress, duration);
          remaining = 0;
          changes += 1;
          break;
        }
        applyCorpseProcessingNutrition(slime, effects, slime.jobProgress, duration, duration);
        remaining -= needed;
        const nutritionGained = slime.jobNutritionGained || 0;
        const workRoomId = slimeEffectiveRoomId(slime);
        const pit = slimePitJobSite(slime);
        addCorpseProcessingInventoryRecovery(target, workRoomId);
        removeCorpseRecord(target.id);
        reserved.delete(target.id);
        addResources({ biomass: CORPSE_PROCESSING_BIOMASS_GAIN }, workRoomId);
        addResource("carrionFeedstock", CARRION_FEEDSTOCK_PER_CORPSE, workRoomId);
        if (!addContainerWaste(pit, CORPSE_PROCESSING_WASTE_GAIN + effects.extraWaste, corpseWasteTags(target))) {
          addWaste(CORPSE_PROCESSING_WASTE_GAIN + effects.extraWaste, corpseWasteTags(target), workRoomId);
        }
        const leftResidue = applyCorpseProcessingResidue(slime, target, suitability, effects);
        applyCorpseProcessingEffects(slime, target, suitability, effects);
        addEvent(`${slime.name} processed ${target.name} remains${nutritionGained ? ` after gaining ${formatNumber(nutritionGained)} Nutrition` : ""}${leftResidue ? ", leaving local residue" : ""}.`);
        slime.jobProgress = 0;
        slime.jobTargetCorpseId = null;
        slime.jobNutritionGained = 0;
        changes += 1;
        if (!canWorkJob(slime)) {
          break;
        }
        assignCorpseTarget(slime, reserved);
      }
    }
    return changes;
  }

  function updateWasteDisposalJobs(elapsed) {
    let changes = 0;
    const workers = state.slimes.filter((slime) => {
      normalizeSlimeJob(slime);
      return slime.job === "disposal" && canWorkJob(slime);
    });
    for (const slime of workers) {
      const pit = slimePitJobSite(slime);
      const pitId = pit?.id || "";
      if (containerWasteAmount(pitId) <= 0) {
        slime.jobProgress = 0;
        continue;
      }
      const knowledge = ensureJobKnowledge(slime, "disposal");
      const suitability = wasteDisposalSuitability(slime);
      let remaining = elapsed;
      while (remaining > 0 && containerWasteAmount(pitId) > 0 && canWorkJob(slime)) {
        const duration = wasteDisposalDuration(slime);
        const needed = Math.max(0, duration - slime.jobProgress);
        if (needed <= 0) {
          slime.jobProgress = 0;
          if (!spendContainerWaste(pitId, WASTE_DISPOSAL_UNIT)) {
            break;
          }
          completeWasteDisposalUnit(slime, suitability);
          continue;
        }
        const step = Math.min(remaining, needed || duration);
        if (step <= 0) {
          break;
        }
        slime.jobProgress += step;
        knowledge.observedMinutes = Math.max(0, Number(knowledge.observedMinutes) || 0) + step;
        applyWasteDisposalExposure(slime, suitability, step);
        observeSlowWasteDisposal(slime, suitability);
        remaining -= step;
        changes += 1;
        if (!canWorkJob(slime)) {
          break;
        }
        if (slime.jobProgress < duration) {
          continue;
        }
        slime.jobProgress = 0;
        if (!spendContainerWaste(pitId, WASTE_DISPOSAL_UNIT)) {
          break;
        }
        completeWasteDisposalUnit(slime, suitability);
      }
    }
    return changes;
  }

  function nextCreatureJobEvent() {
    const events = [];
    for (const slime of state.slimes) {
      normalizeSlimeJob(slime);
      if (slime.job === "corpse" && canWorkJob(slime) && isCorpseProcessingTargetForSlime(slime, findCorpse(slime.jobTargetCorpseId))) {
        events.push({
          time: state.clock + Math.max(0, corpseProcessingDuration(slime) - slime.jobProgress),
          label: `${slime.name} corpse processing`,
          type: "job"
        });
      }
      if (slime.job === "disposal" && canWorkJob(slime) && containerWasteAmount(slimePitJobSite(slime)) > 0) {
        const completion = state.clock + Math.max(0, wasteDisposalDuration(slime) - slime.jobProgress);
        events.push({
          time: completion,
          label: `${slime.name} waste disposal`,
          type: "job"
        });
        const exposure = nextWasteExposureEvent(slime);
        if (exposure) {
          events.push(exposure);
        }
      }
    }
    return events
      .filter((event) => Number.isFinite(event.time) && event.time >= state.clock)
      .sort((a, b) => a.time - b.time)[0] || null;
  }

  function nextSlimeMetabolismEvent() {
    const events = [];
    for (const slime of state.slimes || []) {
      if (!slime || slime.status === "dead") {
        continue;
      }
      const massEvent = nextSlimeFullMassEvent(slime);
      if (massEvent) {
        events.push(massEvent);
      }
      const sustenanceEvent = nextEnvironmentalSustenanceEvent(slime);
      if (sustenanceEvent) {
        events.push(sustenanceEvent);
      }
      const divisionEvent = nextDivisionPressureEvent(slime);
      if (divisionEvent) {
        events.push(divisionEvent);
      }
    }
    return events
      .filter((event) => Number.isFinite(event.time) && event.time >= state.clock)
      .sort((a, b) => a.time - b.time)[0] || null;
  }

  function nextSlimeFullMassEvent(slime) {
    const mass = slimeStat(slime, "currentMass");
    const nutrition = slimeStat(slime, "nutrition");
    if (mass.current >= mass.max || nutrition.current <= MASS_REGROWTH_NUTRITION_FLOOR) {
      const envRate = environmentalSustenanceRate(slime);
      if (mass.current >= mass.max || envRate <= 0) {
        return null;
      }
    }
    const evaluated = evaluateGenome(slime.genome);
    const growthMinutes = Math.max(1, Number(evaluated.traits.growth.meta?.growthMinutes) || 12);
    const growthRate = (mass.max / (growthMinutes * 12)) / SECONDS_PER_MINUTE;
    const availableNutrition = Math.max(0, nutrition.current - MASS_REGROWTH_NUTRITION_FLOOR);
    const nutritionCost = adjustedMassRegrowthNutritionCost(slime);
    const possibleGain = availableNutrition / nutritionCost;
    const needed = mass.max - mass.current;
    if (possibleGain < needed) {
      const envRate = environmentalSustenanceRate(slime);
      const sustainedMassRate = envRate / nutritionCost;
      if (envRate <= 0 || sustainedMassRate <= 0) {
        return null;
      }
      const startDelay = Math.max(0, MASS_REGROWTH_NUTRITION_FLOOR - nutrition.current) / envRate;
      const fastMass = Math.max(0, possibleGain);
      const fastTime = fastMass / growthRate;
      const remainingMass = Math.max(0, needed - fastMass);
      const sustainedTime = remainingMass / Math.min(growthRate, sustainedMassRate);
      return {
        time: state.clock + startDelay + fastTime + sustainedTime,
        label: `${slime.name} full mass`,
        type: "metabolism"
      };
    }
    return {
      time: state.clock + needed / growthRate,
      label: `${slime.name} full mass`,
      type: "metabolism"
    };
  }

  function nextEnvironmentalSustenanceEvent(slime) {
    const rate = environmentalSustenanceRate(slime);
    if (rate <= 0 || slimeStat(slime, "currentMass").current < 100) {
      return null;
    }
    const nutrition = slimeStat(slime, "nutrition");
    if (nutrition.current >= DIVISION_NUTRITION_THRESHOLD) {
      return null;
    }
    return {
      time: state.clock + (DIVISION_NUTRITION_THRESHOLD - nutrition.current) / rate,
      label: `${slime.name} sustenance threshold`,
      type: "metabolism"
    };
  }

  function nextDivisionPressureEvent(slime) {
    const pressure = slimeStat(slime, "divisionPressure");
    if (pressure.current >= pressure.max || !divisionReadiness(slime).ready) {
      return null;
    }
    const required = divisionPressureDuration(slime);
    const seconds = (pressure.max - pressure.current) / (pressure.max / required);
    return {
      time: state.clock + seconds,
      label: `${slime.name} division pressure`,
      type: "metabolism"
    };
  }

  function assignCorpseTarget(slime, reserved = reservedCorpseTargets(slime.id)) {
    const target = chooseCorpseProcessingTarget(slime, reserved);
    if (!target) {
      slime.jobTargetCorpseId = null;
      slime.jobProgress = 0;
      return false;
    }
    slime.jobTargetCorpseId = target.id;
    slime.jobProgress = 0;
    slime.jobNutritionGained = 0;
    reserved.add(target.id);
    return true;
  }

  function reservedCorpseTargets(exceptSlimeId = null) {
    const reserved = new Set();
    for (const slime of state.slimes || []) {
      if (slime.id === exceptSlimeId) {
        continue;
      }
      normalizeSlimeJob(slime);
      if (slime.job === "corpse" && isCorpseProcessingTargetForSlime(slime, findCorpse(slime.jobTargetCorpseId))) {
        reserved.add(slime.jobTargetCorpseId);
      }
    }
    return reserved;
  }

  function chooseCorpseProcessingTarget(slime, reserved = new Set()) {
    const pit = slimePitJobSite(slime);
    if (!pit) {
      return null;
    }
    return containerCorpses(pit.id)
      .filter((corpse) => isCorpseProcessingTarget(corpse) && !reserved.has(corpse.id))
      .sort((a, b) => wasteTargetPriority(a) - wasteTargetPriority(b) || a.diedAt - b.diedAt)
      [0] || null;
  }

  function wasteTargetPriority(corpse) {
    const priority = { ruined: 0, spoiled: 1, decaying: 2, fresh: 3 };
    return priority[corpseFreshness(corpse)] ?? 4;
  }

  function isCorpseProcessingTarget(corpse) {
    if (!isCorpseProcessingCandidate(corpse)) {
      return false;
    }
    return Boolean(corpseProcessingTargets()[corpseFreshness(corpse)]);
  }

  function isCorpseProcessingTargetForSlime(slime, corpse) {
    const pit = slimePitJobSite(slime);
    return Boolean(pit && corpse?.storage === "container" && corpse.containerId === pit.id && isCorpseProcessingTarget(corpse));
  }


  function isCorpseProcessingCandidate(corpse) {
    if (!corpse || !CORPSE_STATE_POLICY_DEFS.some((stateDef) => stateDef.key === corpseFreshness(corpse))) {
      return false;
    }
    if (corpse.storage === "container" && isPitHoleContainer(containerById(corpse.containerId))) {
      return true;
    }
    return false;
  }


  function policyProtectedCorpseCount(containerId = null) {
    return (state.corpses || []).filter((corpse) => (
      isCorpseProcessingCandidate(corpse)
      && (!containerId || corpse.containerId === containerId)
      && !isCorpseProcessingTarget(corpse)
    )).length;
  }

  function corpseProcessingUnavailableText(slime = null) {
    const pit = slime ? slimePitJobSite(slime) : null;
    if (slime && !pit) {
      return "no pit job site";
    }
    const containerId = pit?.id || null;
    return policyProtectedCorpseCount(containerId) ? "no policy-approved corpse" : "no eligible corpse";
  }

  function refreshCorpseProcessingTargets() {
    for (const slime of state.slimes || []) {
      normalizeSlimeJob(slime);
      if (slime.job === "corpse" && !isCorpseProcessingTargetForSlime(slime, findCorpse(slime.jobTargetCorpseId))) {
        slime.jobTargetCorpseId = null;
        slime.jobProgress = 0;
        slime.jobNutritionGained = 0;
      }
    }
    const reserved = reservedCorpseTargets();
    for (const slime of state.slimes || []) {
      if (slime.job === "corpse" && canWorkJob(slime) && !slime.jobTargetCorpseId) {
        assignCorpseTarget(slime, reserved);
      }
    }
  }

  function removeCorpseRecord(corpseId) {
    state.corpses = (state.corpses || []).filter((corpse) => corpse.id !== corpseId);
    for (const slime of state.slimes || []) {
      if (slime.job === "corpse" && slime.jobTargetCorpseId === corpseId) {
        slime.jobTargetCorpseId = null;
        slime.jobProgress = 0;
        slime.jobNutritionGained = 0;
      }
    }
    if (currentSelection()?.kind === "corpse" && currentSelection().id === corpseId) {
      setSelection(null);
    }
  }

  function removeLivingSlimeRecord(slimeId) {
    state.slimes = (state.slimes || []).filter((slime) => slime.id !== slimeId);
    if (state.creatureRecords) {
      delete state.creatureRecords[slimeId];
    }
    state.tasks = (state.tasks || []).filter((task) => !taskTargetsSlime(task, slimeId));
    if (currentSelection()?.kind === "slime" && currentSelection().id === slimeId) {
      setSelection(null);
    }
  }

  function taskTargetsSlime(task, slimeId) {
    if (!task || !slimeId) {
      return false;
    }
    const data = task.data || {};
    return data.slimeId === slimeId || data.parentAId === slimeId || data.parentBId === slimeId;
  }

  function normalizeSlimeJob(slime) {
    if (!slime) {
      return;
    }
    if (slime.job === "waste") {
      slime.job = "corpse";
    }
    if (!CREATURE_JOBS.some((job) => job.id === slime.job)) {
      slime.job = "idle";
    }
    if (isInSynthesisTube(slime) || slimeJobRoomBlockReason(slime) || (slime.containerId && isContainerInTransit(slime.containerId))) {
      slime.job = "idle";
    }
    slime.jobProgress = Math.max(0, Number(slime.jobProgress) || 0);
    slime.jobNutritionGained = Math.max(0, Number(slime.jobNutritionGained) || 0);
    slime.jobTargetCorpseId ||= null;
    slime.jobKnowledge = normalizeJobKnowledge(slime.jobKnowledge);
    if (slime.job !== "corpse") {
      slime.jobTargetCorpseId = null;
      slime.jobNutritionGained = 0;
    }
    if (slime.job === "idle") {
      slime.jobProgress = 0;
      slime.jobTargetCorpseId = null;
      slime.jobNutritionGained = 0;
    }
  }




  function canWorkJob(slime) {
    return Boolean(
      slime
      && slime.status !== "dead"
      && slime.mature
      && !isInSynthesisTube(slime)
      && !(slime.containerId && isContainerInTransit(slime.containerId))
      && !slimeJobRoomBlockReason(slime)
      && !slimeJobSpecificBlockReason(slime, slime.job)
      && slimeStat(slime, "bodyIntegrity").current > 0
    );
  }






  function jobAssignmentBlockReason(slime) {
    if (!slime || slime.status === "dead") {
      return "No living slime available.";
    }
    if (isInSynthesisTube(slime)) {
      return "Specimens in the synthesis tube cannot be assigned jobs.";
    }
    if (slime.containerId && isContainerInTransit(slime.containerId)) {
      return `${slime.name}'s container is being hauled.`;
    }
    const roomReason = slimeJobRoomBlockReason(slime);
    if (roomReason) {
      return roomReason;
    }
    if (!slime.mature) {
      return "Immature slimes cannot be assigned jobs.";
    }
    if (slimeStat(slime, "bodyIntegrity").current <= 0) {
      return "Body Integrity is too low for job assignment.";
    }
    return "";
  }



  function corpseProcessingDuration(slime) {
    const score = corpseProcessingSuitability(slime).score;
    return minutesToSeconds(Math.round(clamp(240 - score * 1.8, 45, 240)));
  }

  function jobRemainingText(slime) {
    if (slime.job === "corpse" && corpseProcessingTimingKnown(slime)) {
      return `${formatDuration(Math.max(0, corpseProcessingDuration(slime) - slime.jobProgress))} remaining`;
    }
    if (slime.job === "disposal" && wasteDisposalTimingKnown(slime)) {
      return `${formatDuration(Math.max(0, wasteDisposalDuration(slime) - slime.jobProgress))} remaining`;
    }
    return slime.jobProgress > 0 ? "processing underway" : "processing";
  }

  function jobProgressPercent(slime) {
    if (slime.job === "corpse" && isCorpseProcessingTargetForSlime(slime, findCorpse(slime.jobTargetCorpseId))) {
      return Math.round(clamp((slime.jobProgress / corpseProcessingDuration(slime)) * 100, 0, 100));
    }
    if (slime.job === "disposal" && containerWasteAmount(slimePitJobSite(slime)) > 0) {
      return Math.round(clamp((slime.jobProgress / wasteDisposalDuration(slime)) * 100, 0, 100));
    }
    return 0;
  }

  function shouldShowJobProgress(slime) {
    if (slime.job === "corpse") {
      return isCorpseProcessingTargetForSlime(slime, findCorpse(slime.jobTargetCorpseId)) && corpseProcessingTimingKnown(slime);
    }
    if (slime.job === "disposal") {
      return containerWasteAmount(slimePitJobSite(slime)) > 0 && wasteDisposalTimingKnown(slime);
    }
    return false;
  }

  function corpseProcessingSuitability(slime) {
    const evaluated = evaluateGenome(slime.genome);
    const traits = evaluated.traits;
    const profile = physicalProfile(slime.genome, evaluated);
    const tags = new Set(traits.sustenance.meta?.tags || []);
    let score = 0;
    const reasons = [];
    const element = baseOutcomeLabel(traits.element);
    const consistency = baseOutcomeLabel(traits.consistency);
    const behavior = baseOutcomeLabel(traits.behavior);
    const stabilityRisk = Number(traits.stability.meta?.risk) || 5;

    const elementScores = {
      acid: 42,
      flame: 30,
      poison: 28,
      water: 18,
      metal: 12,
      stone: 12,
      null: 8
    };
    if (elementScores[element]) {
      score += elementScores[element];
      reasons.push(`${element} affinity`);
    }
    const consistencyScores = {
      watery: 18,
      "runny gel": 20,
      "loose jelly": 16,
      mucous: 18,
      "tar-like": 14,
      "grainy slurry": 10,
      "soft gelatin": 8
    };
    if (consistencyScores[consistency]) {
      score += consistencyScores[consistency];
      reasons.push(consistency);
    }
    if (tags.has("corpse")) {
      score += 32;
      reasons.push("corpse-compatible sustenance");
    }
    if (tags.has("waste")) {
      score += 26;
      reasons.push("waste sustenance");
    }
    if (tags.has("decay")) {
      score += 12;
      reasons.push("decay sustenance");
    }
    if (tags.has("contaminated") || tags.has("hazardous")) {
      score += 8;
      reasons.push("hazard-tolerant sustenance");
    }
    if (behavior === "cleaning") {
      score += 16;
      reasons.push("cleaning behavior");
    } else if (behavior === "burrowing" || behavior === "swarming") {
      score += 8;
      reasons.push(`${behavior} behavior`);
    }
    if ((profile?.weightKg || 0) >= 20) {
      score += 8;
    }
    if ((profile?.weightKg || 0) < 1) {
      score -= 8;
    }
    score -= Math.max(0, stabilityRisk - 5) * 4;
    score = clamp(Math.round(score), 0, 100);
    return {
      score,
      band: jobSuitabilityBand(score),
      reasons
    };
  }

  function wasteDisposalSuitability(slime) {
    const evaluated = evaluateGenome(slime.genome);
    const traits = evaluated.traits;
    const profile = physicalProfile(slime.genome, evaluated);
    const tags = new Set(traits.sustenance.meta?.tags || []);
    let score = 0;
    const reasons = [];
    const element = baseOutcomeLabel(traits.element);
    const consistency = baseOutcomeLabel(traits.consistency);
    const behavior = baseOutcomeLabel(traits.behavior);
    const stabilityRisk = Number(traits.stability.meta?.risk) || 5;

    const elementScores = {
      acid: 36,
      poison: 30,
      flame: 24,
      stone: 18,
      metal: 14,
      light: 14,
      water: 12,
      frost: 8,
      null: 6
    };
    if (elementScores[element]) {
      score += elementScores[element];
      reasons.push(`${element} affinity`);
    }
    const consistencyScores = {
      watery: 14,
      "runny gel": 18,
      "loose jelly": 16,
      mucous: 20,
      "tar-like": 18,
      "grainy slurry": 14,
      "soft gelatin": 8,
      crystalline: -12,
      brittle: -16
    };
    if (consistencyScores[consistency]) {
      score += consistencyScores[consistency];
      reasons.push(consistency);
    }
    if (tags.has("waste")) {
      score += 38;
      reasons.push("waste sustenance");
    }
    if (tags.has("contaminated") || tags.has("hazardous")) {
      score += 20;
      reasons.push("hazard-tolerant sustenance");
    }
    if (tags.has("decay")) {
      score += 10;
      reasons.push("decay sustenance");
    }
    if (tags.has("clean")) {
      score -= 14;
    }
    if (behavior === "cleaning") {
      score += 20;
      reasons.push("cleaning behavior");
    } else if (behavior === "skittish" || behavior === "territorial") {
      score -= 10;
    } else if (behavior === "burrowing" || behavior === "swarming") {
      score += 6;
    }
    if ((profile?.weightKg || 0) >= 20) {
      score += 6;
    }
    if ((profile?.weightKg || 0) < 1) {
      score -= 8;
    }
    score -= Math.max(0, stabilityRisk - 5) * 6;
    score = clamp(Math.round(score), 0, 100);
    return {
      score,
      band: jobSuitabilityBand(score),
      reasons
    };
  }

  function wasteDisposalDuration(slime) {
    const score = wasteDisposalSuitability(slime).score;
    let minutes;
    if (score >= 75) {
      minutes = Math.round(clamp(480 - (score - 75) * 12, 120, 480));
    } else if (score >= 50) {
      minutes = Math.round(1440 - (score - 50) * 38.4);
    } else if (score >= 25) {
      minutes = Math.round(4320 - (score - 25) * 115.2);
    } else {
      minutes = Math.round(10080 - score * 230.4);
    }
    return minutesToSeconds(minutes);
  }

  function cleanupUseSuitabilityBand(score, hasSevereConcern = false) {
    if (hasSevereConcern && score >= 40) {
      return "Risky";
    }
    if (score >= 80) {
      return "Excellent";
    }
    if (score >= 55) {
      return "Good";
    }
    if (score >= 30) {
      return "Risky";
    }
    return "Poor";
  }

  function cleanupUsePredictionBands() {
    return ["Poor", "Risky", "Good", "Excellent"];
  }

  function buildCleanupUseSuitabilityResult({ known, score = 0, band = "Unknown", helpfulFactors = [], concerns = [], unknownFactors = [], clearEvidence = 0, severeConcern = false }) {
    const confidence = predictionConfidenceFromContext({
      unknownFactors,
      knownFactors: helpfulFactors,
      concerns,
      clearEvidence,
      skillIds: ["analysis", "creatureLore", "creatureHandling"]
    });
    let range;
    if (!known || band === "Unknown") {
      range = predictionRangeFromBand(cleanupUsePredictionBands(), "Risky", "Unknown", { unknownLow: "Poor", unknownHigh: "Excellent" });
    } else {
      range = predictionRangeFromBand(cleanupUsePredictionBands(), band, confidence.label, { unknownLow: "Poor", unknownHigh: "Excellent" });
      if (severeConcern && range.high === "Excellent") {
        range.high = "Good";
      }
    }
    return { known, score, band, range, confidence, helpfulFactors, concerns, unknownFactors };
  }

  function observedCleanupUseSuitability(slime) {
    const learned = ensureJobKnowledge(slime, "cleanup");
    if (learned.band) {
      return buildCleanupUseSuitabilityResult({
        known: true,
        band: learned.band,
        helpfulFactors: learned.reason ? [learned.reason] : [],
        clearEvidence: learned.reason ? 40 : 10
      });
    }

    if (!slime) {
      return buildCleanupUseSuitabilityResult({
        known: false,
        band: "Unknown",
        concerns: ["no living slime selected"]
      });
    }

    const evaluated = evaluateGenome(slime.genome);
    const traits = evaluated.traits;
    const revealed = slime.revealed || {};
    const helpfulFactors = [];
    const concerns = [];
    const unknownFactors = [];
    let score = 0;
    let clearEvidence = 0;
    let severeConcern = false;

    if (revealed.sustenance) {
      const tags = new Set(traits.sustenance?.meta?.tags || []);
      const profile = environmentalSustenanceProfile(slime);
      if (tags.has("contaminated") || tags.has("waste") || tags.has("hazardous") || tags.has("fume") || profile?.attributeKey === "contamination") {
        score += 38;
        clearEvidence += 38;
        helpfulFactors.push("feeds on contamination");
      } else {
        score -= 16;
        concerns.push("contamination feeding not confirmed");
      }
    } else {
      unknownFactors.push("sustenance");
    }

    if (revealed.behavior) {
      const behavior = baseOutcomeLabel(traits.behavior);
      const behaviorText = String(behavior || "").toLowerCase();
      if (behaviorText === "cleaning" || /clean|scavenge|forage/.test(behaviorText)) {
        score += 30;
        clearEvidence += 30;
        helpfulFactors.push("seeks contamination");
      } else if (/pred|hunt|ambush|prey|vibration/.test(behaviorText)) {
        score -= 45;
        severeConcern = true;
        concerns.push("predatory behavior");
      } else if (/territorial|aggressive|swarming/.test(behaviorText)) {
        score -= 22;
        severeConcern = true;
        concerns.push(`${behaviorText} behavior`);
      } else if (/docile|calm|placid/.test(behaviorText)) {
        score += 16;
        helpfulFactors.push("calm behavior");
      }
    } else {
      unknownFactors.push("behavior");
    }

    const visibleResidueText = [];
    if (revealed.byproduct) {
      visibleResidueText.push(baseOutcomeLabel(traits.byproduct));
    } else {
      unknownFactors.push("byproduct");
    }
    if (revealed.consistency) {
      visibleResidueText.push(baseOutcomeLabel(traits.consistency));
    } else {
      unknownFactors.push("body consistency");
    }
    if (revealed.stability) {
      visibleResidueText.push(baseOutcomeLabel(traits.stability));
      const stabilityRisk = Number(traits.stability?.meta?.risk) || 5;
      if (stabilityRisk <= 3) {
        score += 14;
        helpfulFactors.push("stable body profile");
      } else if (stabilityRisk >= 7) {
        score -= 24;
        severeConcern = true;
        concerns.push("unstable body profile");
      }
    } else {
      unknownFactors.push("stability");
    }

    const residueText = visibleResidueText.join(" ").toLowerCase();
    if (/slime|mucus|tar|foam|ooze|acid|fume|poison|waste|residue|volatile|unstable/.test(residueText)) {
      score -= 32;
      severeConcern = true;
      concerns.push("may leave residue");
    } else if (revealed.byproduct && revealed.consistency && revealed.stability) {
      score += 12;
      helpfulFactors.push("no known residue risk");
    }

    const stress = slimeStat(slime, "stress").current;
    if (stress <= 20) {
      score += 10;
      helpfulFactors.push("calm condition");
    } else if (stress >= 70) {
      score -= 20;
      severeConcern = true;
      concerns.push("high Stress");
    }

    const bodyIntegrity = slimeStat(slime, "bodyIntegrity").current;
    if (bodyIntegrity <= 35) {
      score -= 12;
      concerns.push("poor Body Integrity");
    }

    score = clamp(Math.round(score), 0, 100);
    const known = clearEvidence > 0 || concerns.length > 0 || helpfulFactors.length >= 2;
    if (!known) {
      return buildCleanupUseSuitabilityResult({
        known: false,
        score: 0,
        band: "Unknown",
        helpfulFactors,
        concerns,
        unknownFactors
      });
    }

    return buildCleanupUseSuitabilityResult({
      known: true,
      score,
      band: cleanupUseSuitabilityBand(score, severeConcern),
      helpfulFactors,
      concerns,
      unknownFactors,
      clearEvidence,
      severeConcern
    });
  }

  function cleanupUseSuitabilityPanel(slime) {
    const suitability = observedCleanupUseSuitability(slime);
    const panel = document.createElement("div");
    panel.className = "job-note";
    panel.dataset.cleanupUseSuitability = slime.id;
    panel.title = cleanupUseOptionTitle(slime);

    const rangeSpan = document.createElement("span");
    rangeSpan.dataset.cleanupSuitabilityRange = slime.id;
    rangeSpan.textContent = `Cleanup suitability: ${predictionRangeText(suitability.range)}`;
    rangeSpan.title = cleanupUseRangeTooltip(suitability);

    const confidenceSpan = document.createElement("span");
    confidenceSpan.dataset.cleanupSuitabilityConfidence = slime.id;
    confidenceSpan.textContent = `Confidence: ${suitability.confidence.label}`;
    confidenceSpan.title = predictionConfidenceTooltip(suitability.confidence);

    panel.append(rangeSpan, document.createTextNode(" | "), confidenceSpan);
    return panel;
  }

  function observedCorpseProcessingSuitability(slime) {
    const learned = ensureJobKnowledge(slime, "corpse");
    if (learned.band) {
      return {
        known: true,
        score: 0,
        band: learned.band,
        reasons: learned.reason ? [learned.reason] : []
      };
    }
    const evaluated = evaluateGenome(slime.genome);
    const traits = evaluated.traits;
    const knownKeys = ["element", "consistency", "sustenance", "behavior", "stability", "size", "shape"]
      .filter((traitKey) => slime.revealed?.[traitKey]);
    if (!knownKeys.length) {
      return { known: false, score: 0, band: "Unknown", reasons: [] };
    }

    let score = 0;
    const reasons = [];
    let clearPositiveEvidence = 0;
    let clearNegativeEvidence = 0;
    if (slime.revealed?.element) {
      const element = baseOutcomeLabel(traits.element);
      const elementScores = {
        acid: 42,
        flame: 30,
        poison: 28,
        water: 18,
        metal: 12,
        stone: 12,
        null: 8
      };
      if (elementScores[element]) {
        score += elementScores[element];
        if (["acid", "flame", "poison"].includes(element)) {
          clearPositiveEvidence += elementScores[element];
        }
        reasons.push(`${element} affinity`);
      }
    }
    if (slime.revealed?.consistency) {
      const consistency = baseOutcomeLabel(traits.consistency);
      const consistencyScores = {
        watery: 18,
        "runny gel": 20,
        "loose jelly": 16,
        mucous: 18,
        "tar-like": 14,
        "grainy slurry": 10,
        "soft gelatin": 8
      };
      if (consistencyScores[consistency]) {
        score += consistencyScores[consistency];
        if (consistencyScores[consistency] >= 20) {
          clearPositiveEvidence += consistencyScores[consistency];
        }
        reasons.push(consistency);
      }
    }
    if (slime.revealed?.sustenance) {
      const tags = new Set(traits.sustenance.meta?.tags || []);
      if (tags.has("corpse")) {
        score += 32;
        clearPositiveEvidence += 32;
        reasons.push("corpse-compatible sustenance");
      }
      if (tags.has("waste")) {
        score += 26;
        clearPositiveEvidence += 26;
        reasons.push("waste sustenance");
      }
      if (tags.has("decay")) {
        score += 12;
        reasons.push("decay sustenance");
      }
      if (tags.has("contaminated") || tags.has("hazardous")) {
        score += 8;
        reasons.push("hazard-tolerant sustenance");
      }
    }
    if (slime.revealed?.behavior) {
      const behavior = baseOutcomeLabel(traits.behavior);
      if (behavior === "cleaning") {
        score += 16;
        clearPositiveEvidence += 16;
        reasons.push("cleaning behavior");
      } else if (behavior === "burrowing" || behavior === "swarming") {
        score += 8;
        reasons.push(`${behavior} behavior`);
      }
    }
    if (slime.revealed?.size && slime.revealed?.shape) {
      const profile = physicalProfile(slime.genome, evaluated);
      if ((profile?.weightKg || 0) >= 20) {
        score += 8;
      }
      if ((profile?.weightKg || 0) < 1) {
        score -= 8;
        clearNegativeEvidence += 8;
      }
    }
    if (slime.revealed?.stability) {
      const stabilityRisk = Number(traits.stability.meta?.risk) || 5;
      const penalty = Math.max(0, stabilityRisk - 5) * 4;
      score -= penalty;
      if (penalty >= 8) {
        clearNegativeEvidence += penalty;
      }
    }
    score = clamp(Math.round(score), 0, 100);
    if (score < 25 && clearPositiveEvidence < 25 && clearNegativeEvidence < 8) {
      return { known: false, score: 0, band: "Unknown", reasons: [] };
    }
    return {
      known: true,
      score,
      band: jobSuitabilityBand(score),
      reasons
    };
  }

  function corpseProcessingResidueOutcome(corpse, suitability, effects) {
    const freshness = corpseFreshness(corpse);
    const score = Math.max(0, Number(suitability?.score) || 0);
    if (score >= 70 && effects?.extraWaste <= 0 && (freshness === "fresh" || freshness === "decaying")) {
      return null;
    }
    let typeKey = "looseBiomatter";
    if (freshness === "spoiled") {
      typeKey = score < 25 ? "hazardousSludge" : "contaminatedResidue";
    } else if (freshness === "ruined") {
      typeKey = score < 25 ? "contaminatedResidue" : "inertResidue";
    } else if (freshness === "decaying") {
      typeKey = score < 40 ? "contaminatedResidue" : "looseBiomatter";
    } else if (score < 25) {
      typeKey = "contaminatedResidue";
    }
    const stateAmount = { fresh: 1, decaying: 1, spoiled: 2, ruined: 1 }[freshness] || 1;
    const amount = Math.max(1, stateAmount + Math.max(0, Number(effects?.extraWaste) || 0) + (score < 25 ? 1 : 0));
    return { typeKey, amount };
  }

  function applyCorpseProcessingResidue(slime, corpse, suitability, effects) {
    const outcome = corpseProcessingResidueOutcome(corpse, suitability, effects);
    if (!outcome) {
      return false;
    }
    return addFeedingResidue(outcome.typeKey, outcome.amount, {
      slime,
      location: feedingResidueLocationForCorpseJob(slime, corpse),
      sourceLabel: `Corpse processing: ${corpse.name}`,
      tags: ["corpse-processing", ...corpseWasteTags(corpse), corpseFreshness(corpse), jobSuitabilityBand(suitability.score)]
    });
  }

  function corpseProcessingEffects(slime, corpse, suitability) {
    const tags = new Set(evaluateGenome(slime.genome).traits.sustenance.meta?.tags || []);
    const freshness = corpseFreshness(corpse);
    const quality = {
      fresh: 1.2,
      decaying: 0.8,
      spoiled: 0.35,
      ruined: 0.25
    }[freshness] || 0.25;
    let baseNutrition = 1;
    if (tags.has("corpse")) {
      baseNutrition = 8;
    } else if (tags.has("decay")) {
      baseNutrition = 5;
    } else if (tags.has("organic")) {
      baseNutrition = 3;
    } else if (tags.has("waste")) {
      baseNutrition = 2;
    }
    const nutrition = Math.max(0, Math.round(baseNutrition * quality * (0.4 + suitability.score / 90)));
    const materialStress = { fresh: 1, decaying: 2, spoiled: 5, ruined: 2 }[freshness] || 2;
    const materialDamage = { fresh: 0, decaying: 1, spoiled: 2, ruined: 0 }[freshness] || 0;
    const stress = Math.max(0, Math.round(Math.max(0, 55 - suitability.score) / 12 + materialStress - (nutrition >= 6 ? 1 : 0)));
    const bodyDamage = Math.max(0, Math.round(Math.max(0, 45 - suitability.score) / 15 + materialDamage));
    const extraWaste = Math.max(0, (suitability.score < 25 ? 1 : 0) + (freshness === "spoiled" ? 1 : 0) + (nutrition === 0 ? 1 : 0));
    return { nutrition, stress, bodyDamage, extraWaste };
  }

  function applyCorpseProcessingNutrition(slime, effects, fromProgress, toProgress, duration) {
    const totalNutrition = Math.max(0, Number(effects?.nutrition) || 0);
    const safeDuration = Math.max(1, Number(duration) || 1);
    const start = clamp(Number(fromProgress) || 0, 0, safeDuration);
    const end = clamp(Number(toProgress) || 0, 0, safeDuration);
    if (!totalNutrition || end <= start) {
      return 0;
    }
    const alreadyGained = Math.max(0, Number(slime.jobNutritionGained) || 0);
    const expectedGained = totalNutrition * (end / safeDuration);
    const rawGained = Math.max(0, Math.min(totalNutrition - alreadyGained, expectedGained - alreadyGained));
    const gained = adjustedSlimeNutritionGain(slime, rawGained);
    if (gained > 0) {
      adjustSlimeStat(slime, "nutrition", gained);
      slime.jobNutritionGained = alreadyGained + rawGained;
    }
    return gained;
  }

  function applyCorpseProcessingEffects(slime, corpse, suitability, effects) {
    const knowledge = ensureJobKnowledge(slime, "corpse");
    knowledge.completedUnits = Math.max(0, Number(knowledge.completedUnits) || 0) + 1;
    if (effects.stress) {
      adjustSlimeStat(slime, "stress", effects.stress);
    } else if (suitability.score >= 70 && effects.nutrition >= 4) {
      adjustSlimeStat(slime, "stress", -1);
    }
    if (effects.bodyDamage) {
      adjustSlimeStat(slime, "bodyIntegrity", -effects.bodyDamage);
      learnJobFit(slime, "corpse", suitability.score < 25 ? "Hazardous" : "Poor", `${corpseStateLabel(corpse).toLowerCase()} corpse strain`);
      addEvent(`${slime.name} lost ${effects.bodyDamage} Body Integrity processing ${corpse.name}.`);
    } else if (suitability.score >= 70 && knowledge.completedUnits >= 2) {
      learnJobFit(slime, "corpse", "Good", "clean corpse processing");
    } else if (suitability.score >= 40 && knowledge.completedUnits >= 2) {
      learnJobFit(slime, "corpse", "Adequate", "completed corpse processing");
    } else if (suitability.score < 25) {
      learnJobFit(slime, "corpse", "Poor", "messy corpse processing");
    }
    if (effects.extraWaste) {
      learnJobFit(slime, "corpse", "Poor", "messy corpse processing");
    }
  }

  function observedWasteDisposalSuitability(slime) {
    const knowledge = ensureJobKnowledge(slime, "disposal");
    if (!knowledge.band) {
      return { known: false, score: 0, band: "Unknown", reasons: [] };
    }
    return {
      known: true,
      score: 0,
      band: knowledge.band,
      reasons: [...new Set([knowledge.reason, knowledge.lastObservation].filter(Boolean))]
    };
  }

  function applyWasteDisposalExposure(slime, suitability, minutes) {
    const damageRate = wasteDisposalExposureRate(slime, suitability);
    const stressRate = wasteDisposalStressRate(slime, suitability);
    const damage = Math.max(0, minutes * damageRate);
    const stress = Math.max(0, minutes * stressRate);
    if (damage <= 0 && stress <= 0) {
      return 0;
    }
    if (damage > 0) {
      if (slimeStat(slime, "bodyIntegrity").current - damage <= 0) {
        slime.deathCause = "waste exposure";
      }
      adjustSlimeStat(slime, "bodyIntegrity", -damage);
    }
    if (stress > 0) {
      adjustSlimeStat(slime, "stress", stress);
    }
    const knowledge = ensureJobKnowledge(slime, "disposal");
    knowledge.exposureLoss = Math.max(0, Number(knowledge.exposureLoss) || 0) + damage;
    knowledge.nextExposureNoticeLoss ||= WASTE_DISPOSAL_EXPOSURE_NOTICE_LOSS;
    if (knowledge.exposureLoss >= knowledge.nextExposureNoticeLoss) {
      learnWasteDisposalFit(slime, suitability.score < 25 ? "Hazardous" : "Poor", "waste exposure");
      recordJobObservation(slime, "disposal", "body damage from waste exposure");
      knowledge.nextExposureNoticeLoss += WASTE_DISPOSAL_EXPOSURE_NOTICE_LOSS;
    }
    return damage;
  }

  function wasteDisposalExposureRate(slime, suitability = wasteDisposalSuitability(slime)) {
    const score = suitability.score;
    const evaluated = evaluateGenome(slime.genome);
    const stabilityRisk = Number(evaluated.traits.stability.meta?.risk) || 5;
    const badness = Math.max(0, 55 - score) / 55;
    const instability = Math.max(0, stabilityRisk - 5);
    return (badness * 0.015 + instability * 0.002) / SECONDS_PER_MINUTE;
  }

  function wasteDisposalStressRate(slime, suitability = wasteDisposalSuitability(slime)) {
    const score = suitability.score;
    const stabilityRisk = wasteDisposalStabilityRisk(slime);
    const badness = Math.max(0, 60 - score) / 60;
    const instability = Math.max(0, stabilityRisk - 5);
    return (badness * 0.025 + instability * 0.003) / SECONDS_PER_MINUTE;
  }

  function observeSlowWasteDisposal(slime, suitability) {
    const knowledge = ensureJobKnowledge(slime, "disposal");
    if (knowledge.slowObserved || suitability.score >= 50) {
      return;
    }
    if ((Number(knowledge.observedMinutes) || 0) < WASTE_DISPOSAL_SLOW_OBSERVATION) {
      return;
    }
    knowledge.slowObserved = true;
    learnWasteDisposalFit(slime, "Poor", "slow waste digestion");
    recordJobObservation(slime, "disposal", "slow waste digestion");
  }

  function wasteDisposalFeedingResidueOutcome(suitability, elementalResidueUnits) {
    const score = Math.max(0, Number(suitability?.score) || 0);
    if (score >= 75) {
      return elementalResidueUnits > 0
        ? { typeKey: "elementalTrace", amount: elementalResidueUnits }
        : null;
    }
    if (score >= 50) {
      return { typeKey: "inertResidue", amount: 1 };
    }
    if (score >= 25) {
      return { typeKey: "contaminatedResidue", amount: 1 };
    }
    return { typeKey: "hazardousSludge", amount: 2 };
  }

  function applyWasteDisposalFeedingResidue(slime, suitability, elementalResidueUnits) {
    const outcome = wasteDisposalFeedingResidueOutcome(suitability, elementalResidueUnits);
    if (!outcome) {
      return false;
    }
    return addFeedingResidue(outcome.typeKey, outcome.amount, {
      slime,
      sourceLabel: "Waste disposal",
      tags: ["waste-disposal", "waste", jobSuitabilityBand(suitability.score)]
    });
  }

  function completeWasteDisposalUnit(slime, suitability) {
    const knowledge = ensureJobKnowledge(slime, "disposal");
    knowledge.completedUnits = Math.max(0, Number(knowledge.completedUnits) || 0) + 1;
    knowledge.residueProgress = Math.max(0, Number(knowledge.residueProgress) || 0) + (suitability.score >= 75 ? 2 : 1);
    const nutrition = wasteDisposalNutritionGain(slime, suitability);
    const adjustedNutrition = adjustedSlimeNutritionGain(slime, nutrition);
    if (adjustedNutrition) {
      adjustSlimeStat(slime, "nutrition", adjustedNutrition);
    }
    if (suitability.score >= 60 && adjustedNutrition) {
      adjustSlimeStat(slime, "stress", -1);
    } else if (suitability.score < 25) {
      adjustSlimeStat(slime, "stress", 2);
    }
    let residue = 0;
    while (knowledge.residueProgress >= WASTE_DISPOSAL_RESIDUE_INTERVAL) {
      residue += 1;
      knowledge.residueProgress -= WASTE_DISPOSAL_RESIDUE_INTERVAL;
    }
    if (residue) {
      addResource("elementalResidue", residue, slimeEffectiveRoomId(slime));
    }
    const leftLocalResidue = applyWasteDisposalFeedingResidue(slime, suitability, residue);
    if (suitability.score >= 70 && knowledge.completedUnits >= 2) {
      learnWasteDisposalFit(slime, "Good", "clean waste disposal");
    } else if (suitability.score >= 40 && knowledge.completedUnits >= 2) {
      learnWasteDisposalFit(slime, "Adequate", "completed waste disposal");
    } else if (suitability.score < 25) {
      learnWasteDisposalFit(slime, "Poor", "rough waste disposal");
    }
    if (suitability.score < 20 && wasteDisposalStabilityRisk(slime) >= 7) {
      addSuspicion(WASTE_DISPOSAL_CONTAMINATION_SUSPICION);
      learnWasteDisposalFit(slime, "Hazardous", "contamination during disposal");
      recordJobObservation(slime, "disposal", "contamination during disposal");
    }
    addEvent(`${slime.name} disposed of 1 Waste${residue ? ` and left ${residue} Elemental Residue` : ""}${adjustedNutrition ? `, gaining ${formatNumber(adjustedNutrition)} Nutrition` : ""}${leftLocalResidue ? ", leaving local residue" : ""}.`);
  }

  function wasteDisposalNutritionGain(slime, suitability) {
    const tags = new Set(evaluateGenome(slime.genome).traits.sustenance.meta?.tags || []);
    let base = 0;
    if (tags.has("waste")) {
      base += 4;
    }
    if (tags.has("contaminated") || tags.has("hazardous")) {
      base += 2;
    }
    if (tags.has("decay")) {
      base += 1;
    }
    if (!base || suitability.score < 25) {
      return 0;
    }
    return Math.max(0, Math.round(base * (0.45 + suitability.score / 120)));
  }

  function wasteDisposalStabilityRisk(slime) {
    const evaluated = evaluateGenome(slime.genome);
    return Number(evaluated.traits.stability.meta?.risk) || 5;
  }

  function nextWasteExposureEvent(slime) {
    const suitability = wasteDisposalSuitability(slime);
    const rate = wasteDisposalExposureRate(slime, suitability);
    if (rate <= 0) {
      return null;
    }
    const knowledge = ensureJobKnowledge(slime, "disposal");
    const currentDamage = Math.max(0, Number(knowledge.exposureLoss) || 0);
    const nextDamage = Math.max(knowledge.nextExposureNoticeLoss || WASTE_DISPOSAL_EXPOSURE_NOTICE_LOSS, currentDamage + 0.01);
    return {
      time: state.clock + (nextDamage - currentDamage) / rate,
      label: `${slime.name} waste exposure`,
      type: "job"
    };
  }

  function learnJobFit(slime, jobId, band, reason) {
    const knowledge = ensureJobKnowledge(slime, jobId);
    const rank = { Poor: 1, Adequate: 2, Good: 3, Hazardous: 4 };
    const current = rank[knowledge.band] || 0;
    const next = rank[band] || 0;
    if (!knowledge.band || band === "Hazardous" || (knowledge.band !== "Hazardous" && next > current)) {
      knowledge.band = band;
      knowledge.reason = reason;
    }
  }

  function learnWasteDisposalFit(slime, band, reason) {
    learnJobFit(slime, "disposal", band, reason);
  }

  function recordJobObservation(slime, jobId, reason) {
    const knowledge = ensureJobKnowledge(slime, jobId);
    knowledge.lastObservation = String(reason || "").trim();
    knowledge.lastObservedAt = state.clock;
  }

  function jobSuitabilityBand(score) {
    if (score >= 75) {
      return "Excellent";
    }
    if (score >= 50) {
      return "Good";
    }
    if (score >= 25) {
      return "Adequate";
    }
    return "Poor";
  }

  function creatureJobLabel(jobId) {
    return CREATURE_JOBS.find((job) => job.id === jobId)?.label || CREATURE_JOBS[0].label;
  }

  function corpseProcessingTimingKnown(slime) {
    return ["element", "consistency", "sustenance", "behavior", "stability", "size", "shape"]
      .every((traitKey) => slime.revealed?.[traitKey]);
  }

  function wasteDisposalTimingKnown(slime) {
    return Boolean(ensureJobKnowledge(slime, "disposal").band);
  }

  function ensureJobKnowledge(slime, jobId) {
    slime.jobKnowledge = normalizeJobKnowledge(slime.jobKnowledge);
    slime.jobKnowledge[jobId] ||= {};
    return slime.jobKnowledge[jobId];
  }

  function normalizeJobKnowledge(candidate) {
    const normalized = {};
    for (const [jobId, knowledge] of Object.entries(candidate || {})) {
      if (!knowledge || typeof knowledge !== "object") {
        continue;
      }
      normalized[jobId] = {
        ...knowledge,
        observedMinutes: Math.max(0, Number(knowledge.observedMinutes) || 0),
        exposureLoss: Math.max(0, Number(knowledge.exposureLoss) || 0),
        completedUnits: Math.max(0, Number(knowledge.completedUnits) || 0),
        residueProgress: Math.max(0, Number(knowledge.residueProgress) || 0),
        lastObservation: String(knowledge.lastObservation || "").trim(),
        lastObservedAt: knowledge.lastObservedAt == null ? null : finiteTime(knowledge.lastObservedAt, 0),
        nextExposureNoticeLoss: Math.max(WASTE_DISPOSAL_EXPOSURE_NOTICE_LOSS, Number(knowledge.nextExposureNoticeLoss) || WASTE_DISPOSAL_EXPOSURE_NOTICE_LOSS)
      };
    }
    return normalized;
  }

  function renderIdentityStrip(slime, evaluated) {
    const strip = document.createElement("div");
    strip.className = "identity-strip";
    strip.setAttribute("aria-label", "Discovered identity traits");
    for (const traitKey of ["color", "element", "shape", "byproduct"]) {
      strip.append(identitySlotEl(slime, traitKey, evaluated.traits[traitKey]));
    }
    return strip;
  }

  function identitySlotEl(slime, traitKey, outcome) {
    const slot = document.createElement("span");
    slot.className = `identity-slot identity-slot-${traitKey}`;
    const markerOutcome = slimeTraitMarkerOutcome(slime, traitKey, outcome);
    if (!markerOutcome) {
      slot.classList.add("identity-slot-unknown");
      slot.textContent = "?";
      slot.title = `${getRegionLabel(traitKey)} unknown`;
      return slot;
    }

    const icon = traitIdentityIconEl(traitKey, markerOutcome);
    if (icon) {
      slot.append(icon);
    } else {
      slot.textContent = "none";
    }
    if (traitKey === "byproduct") {
      slot.title = [`${getRegionLabel(traitKey)}: ${markerOutcome.label}`, ...byproductExpressionTitleLines(slime)].join("\n");
    } else {
      slot.title = `${getRegionLabel(traitKey)}: ${markerOutcome.label}`;
    }
    return slot;
  }

